export const KENNISBANK = [{"v": "Kan een makelaar of beheerder namens een eigenaar de polis van de opstalverzekering opvragen voor de verkoop van een pand?", "a": "Ja, de polis van de opstalverzekering kan op verzoek worden verstrekt aan de betrokken partijen (zoals de makelaar van de eigenaar) ten behoeve van de verkoop van een object."}, {"v": "Is het mogelijk om een kopie van de opstalverzekering van de VvE te ontvangen?", "a": "Ja, de polis van de opstalverzekering is beschikbaar en kan worden opgevraagd bij de beheerder."}, {"v": "Wat is de rol van het kantoor van de VvE beheerder ten opzichte van de besluiten van de eigenaren?", "a": "Het kantoor heeft een uitvoerende rol binnen de VvE en voert uitsluitend de besluiten uit die door de eigenaren gezamenlijk worden genomen."}, {"v": "Waarom staat er een verzekering op de offerte die niet in de goedgekeurde begroting is opgenomen?", "a": "Het kan voorkomen dat een verzekeraar in haar offerte aanvullende verzekeringen (zoals een rechtsbijstandverzekering) aanbiedt die nog niet in de financiële begroting van de VvE zijn verwerkt. Indien de algemene ledenvergadering alsnog akkoord gaat met het afsluiten van deze verzekering, kan dit alsnog in orde worden gemaakt."}, {"v": "Met welk type verzekering moet ik contact opnemen bij schade aan mijn woning binnen de VvE?", "a": "Wanneer er sprake is van schade, dient dit in eerste instantie via de opstalverzekering van de VvE gemeld te worden. In veel gevallen verwijst een eigen (inboedel)verzekering u hiervoor door naar de gezamenlijke opstalverzekering."}, {"v": "Welk type document heeft de Kamer van Koophandel nodig bij de wijziging van een splitsingsakte die na 2008 is gepasseerd?", "a": "Voor aktes die zijn gepasseerd na 2008 vraagt de Kamer van Koophandel om een papieren afschrift van de akte met een originele handtekening (natte handtekening) van de notaris."}, {"v": "Hoe voldoet een VvE aan de Wet verbetering functioneren VvE met betrekking tot het reservefonds?", "a": "Een Vereniging van Eigenaars voldoet aan de Wet verbetering functioneren VvE door te reserveren voor groot onderhoud op basis van een actueel meerjarenonderhoudsplan (MJOP). De jaarlijkse reservering die uit dit plan voortvloeit, dient te worden opgenomen in de begroting en te worden vastgesteld tijdens de algemene ledenvergadering (ALV)."}, {"v": "Wat hebben jullie nodig om een VvE te kunnen activeren?", "a": "Wij wachten op de splitsingsakte om de VvE te kunnen activeren."}, {"v": "Met wie moet ik contact opnemen voor schade aan het dak en wie is verantwoordelijk voor het herstel?", "a": "Het dak behoort aan de VvE, dus de VvE is verantwoordelijk voor het herstel van lekkages. Voor de afhandeling en het plannen van de werkzaamheden wordt er contact opgenomen met de betrokken bewoner door een aangestelde deskundige of herstelpartner."}, {"v": "Welke documenten heeft de beheerder nodig voor de aanmelding bij de Kamer van Koophandel (KvK)?", "a": "Voor de KvK-inschrijving is na het passeren van de akte een origineel gewaarmerkt afschrift (met een natte handtekening) van de notaris vereist."}, {"v": "Is het mogelijk om de premie van de verzekering via een jaarbetaling te voldoen in plaats van maandelijks?", "a": "Bij de nieuwe verzekering is er gekozen voor een jaarbetaling in plaats van een maandelijkse betaling. Dit is vaak voordeliger omdat veel verzekeringsmaatschappijen korting geven bij een jaarbetaling en het beperkt het aantal mutaties in de administratie."}, {"v": "Wat moet ik doen als ik waterschade vermoed door een verstopte afvoer bij de bovenburen?", "a": "Bij vermoeden van waterschade door een verstopte afvoer is het raadzaam om eerst bij de bovenburen te controleren of de afvoer vrij is van bladeren en ander vuil."}, {"v": "Worden de oude verzekeringen opgezegd als er een nieuwe polis wordt afgesloten via de beheerder?", "a": "Wij autoriseren de nieuwe verzekeraar om de huidige verzekeringen te beëindigen, waarna er een royement zal volgen voor de oude polissen."}, {"v": "Wat kan de VvE doen als er binnen het gebouw zorgen zijn over de temperatuurinstellingen en stookkosten van individuele appartementen?", "a": "Binnen een VvE zijn hier meestal geen vaste afspraken over en deze zijn ook lastig te maken. Het beste is om hierover direct het gesprek aan te gaan met de buren om de zorgen te delen."}, {"v": "Wat moet ik doen bij een spoedgeval zoals wateroverlast door een verstopping in het riool van de VvE?", "a": "Bij spoedgevallen buiten kantoortijden kunt u contact opnemen met het spoednummer van de verzekering van de VvE voor het inschakelen van een herstelbedrijf."}, {"v": "Kan een individueel keuringsrapport per appartementsrecht gebruikt worden als algemeen MJOP voor de VvE?", "a": "Nee, individuele rapporten per appartementsrecht met interne of individuele aangelegenheden kunnen niet als MJOP voor de gehele VvE worden gebruikt. Voor een herberekening van de bijdragen is een gedegen, collectief MJOP noodzakelijk."}, {"v": "Met wie kan ik contact opnemen voor dringende zaken?", "a": "Voor dringende zaken kunt u van maandag tot en met vrijdag tussen 09:00 en 13:00 uur contact met ons opnemen via e-mail of telefoon. Voor calamiteiten buiten deze openingstijden kunt u bellen naar ons algemene telefoonnummer; u wordt dan automatisch doorgeschakeld naar de nooddienst."}, {"v": "Waar kunnen aspirant-eigenaren terecht met hun vragen zolang zij nog geen officiële eigenaar zijn van een appartementsrecht binnen de VvE?", "a": "Zolang iemand nog geen officiële eigenaar is, kan de betreffende persoon voor vragen worden doorverwezen naar de verkopende partij."}, {"v": "Waar kan ik informatie vinden over de financiën en verzekeringen van het pand?", "a": "Informatie over financiën en verzekeringen kunt u terugvinden in de notulen van de VvE."}, {"v": "Wat gebeurt er als er tijdens een ledenvergadering te weinig stemmen vertegenwoordigd zijn om rechtsgeldige besluiten te nemen?", "a": "Mochten er te weinig stemmen vertegenwoordigd zijn, dan zal er een tweede reglementaire ledenvergadering worden gepland en uitgeschreven over circa 3 tot 5 weken."}, {"v": "Wat moet ik aanleveren om een schade ter beoordeling bij de opstalverzekeraar in te dienen?", "a": "Om een schade ter beoordeling bij de verzekeraar in te kunnen dienen hebben wij het volgende nodig: een kopie van de polis van de verzekeringen, een bewijs van de aangetoonbaar verholpen oorzaak (bijvoorbeeld een herstelfactuur) en een offerte voor het herstel van de gevolgschade aan de opstal van een herstelbedrijf. Zodra deze informatie compleet is, zullen wij contact met de opstalverzekeraar opnemen."}, {"v": "Onder welke voorwaarden kan de VvE administratieve ondersteuning krijgen bij het beheren van laadpalen via een externe partij zoals E-Flux?", "a": "De beheerder kan de gewenste stappen namens de Vereniging uitvoeren, mits de externe partij de feitelijke administratieve afhandeling verricht. De VvE betaalt dan maandelijks de kosten per laadpunt via automatische afschrijving, waarna de beheerder deze kosten administratief verwerkt."}, {"v": "Wie mag het machtigingsformulier namens de appartementen invullen en tekenen als men als eigenaar geregistreerd staat?", "a": "Wanneer u als eigenaar in het kadaster staat geregistreerd, kunt u het machtigingsformulier namens de appartementen invullen en tekenen."}, {"v": "Is elk appartement binnen een VvE verplicht om bij te dragen aan het reservefonds?", "a": "Niet elk appartement is in alle gevallen verplicht bij te dragen aan het reservefonds van de Vereniging van Eigenaars; dit hangt af van de specifieke splitsingsakte en gemaakte afspraken. Wel kan een eigenaar die niet bijdraagt nog steeds stemrecht hebben binnen de Vereniging."}, {"v": "Welke stappen onderneemt de beheerder na het akkoord op de offerte en het machtigingsformulier?", "a": "Na ontvangst van het ingevulde en getekende machtigingsformulier verzorgt de beheerder de inschrijving als nieuwe bestuurder/administrateur bij de KvK en wordt aansluitend de toegang tot de bankrekening van de Vereniging aangevraagd."}, {"v": "Hoe werkt het proces voor het versturen van uitnodigingen en agenda's voor vergaderingen?", "a": "Dit is een geautomatiseerd proces waarbij de uitnodigingen en agenda's standaard worden doorgestuurd naar het geregistreerde e-mailadres in onze administratie. Indien u wilt dat deze stukken naar een ander adres worden verzonden, adviseren wij u dit ook af te stemmen met de betreffende beheerder of tussenpersoon om foutgevoeligheid te voorkomen."}, {"v": "Mag ik radiatoren verwijderen in een gebouw met blokverwarming?", "a": "De radiatoren en radiatorkranen zijn eigendom van de VvE. Daarom mag men niet zonder toestemming van de vergadering radiatoren verwijderen. Na verkregen toestemming door de vergadering kan men radiatoren voor eigen rekening en risico verwijderen. De kosten voor het (tijdelijk) laten uitschakelen van de ketel alsmede de kosten voor het verwijderen van de meters op locatie en wijziging in de administratie bij de VvE en het meetbedrijf komen voor rekening van de betreffende eigenaar. In geval van blokverwarming moet men zich er ook van bewust zijn dat men niet wordt vrijgesteld van deelname aan de stookkosten en onderhoud van de installatie."}, {"v": "Welke voorwaarde stelt de beheerder met betrekking tot de verzekering in het kader van aansprakelijkheid?", "a": "Voor ons als bestuurder is het van belang dat er op de polis van de VvE een 'garantie tegen onderverzekering' is aangetekend. Indien de huidige verzekeraar dit niet biedt op basis van de opgegeven herbouwwaarde, geven wij er de voorkeur aan dat de verzekeringen worden overgesloten naar een partij die deze garantie wel biedt."}, {"v": "Wanneer kunnen de collectieve verzekeringen van de VvE ingaan?", "a": "De collectieve verzekeringen kunnen ingaan op de datum van de start van het beheer, of indien gewenst eerder, per datum van overdracht van het appartementsrecht."}, {"v": "Wanneer worden ingebrachte punten een officieel agendapunt voor de ALV en wanneer kan er een besluit over worden genomen?", "a": "Ingebrachte punten worden tijdens de vergadering besproken. Een daadwerkelijk besluit kan echter pas worden genomen zodra er offertes zijn ontvangen. Tot die tijd hoeft het punt nog niet als formeel agendapunt te worden opgenomen."}, {"v": "Wat moet ik doen met mijn eigen verzekeringen en zijn de panden standaard verzekerd?", "a": "De panden zijn via de collectieve VvE-verzekering verzekerd. Zodra deze ingaan, dient u uw eigen individuele verzekeringen per diezelfde datum te beëindigen. Ter informatie worden de polisbladen van de collectieve verzekering beschikbaar gesteld."}, {"v": "Bij welk orgaan ligt de verantwoordelijkheid voor de inventarisatie en het bepalen van bedragen voor onderhoudswerkzaamheden?", "a": "De inventarisatie van onderhoudswerkzaamheden en het bepalen van de bijbehorende bedragen wordt overgelaten aan de Algemene Ledenvergadering (ALV)."}, {"v": "Biedt u ook administratief beheer aan voor een onder-VvE binnen een grotere splitsing?", "a": "Wij bieden eigenlijk alleen een totaalpakket en zullen dat in dit geval ook doen, maar dan tegen een gereduceerd tarief."}, {"v": "Hoe kan ik schade door lekkages melden bij de verzekering als het dossier nog niet compleet is bij de nieuwe beheerder?", "a": "U kunt rechtstreeks contact opnemen met de verzekeringsadviseur. Indien er door een voorgaande beheerder reeds een melding is gemaakt van schade in uw woning, kan de verzekeringsadviseur u verder helpen terwijl de nieuwe beheerder in afwachting is van het complete dossier."}, {"v": "Wordt een individuele inventarisverzekering automatisch opgenomen in de collectieve opstalverzekering van de VvE?", "a": "Nee, een individuele inventarisverzekering gaat niet via de VvE. Het is verstandig om deze verzekering zelf te behouden."}, {"v": "Is het mogelijk om een VvE-vergadering digitaal bij te wonen en is dit juridisch toegestaan?", "a": "Of digitaal vergaderen is toegestaan, hangt af van de bepalingen in het splitsingsreglement of de splitsingsakte van de VvE. In oudere reglementen is hier vaak geen voorziening voor opgenomen. De tijdelijke noodwet die dit tijdens de COVID-periode toestond is na 2023 vervallen. De overheid werkt aan nieuwe wetgeving om digitaal vergaderen structureel juridisch mogelijk te maken; zodra deze wetgeving officieel van kracht wordt, zullen wij dit ondersteunen. Tot die tijd is de splitsingsakte leidend. Indien digitaal vergaderen niet mogelijk is en u niet fysiek aanwezig kunt zijn, kunt u zich laten vertegenwoordigen door iemand anders of een volmacht met steminstructies sturen."}, {"v": "Welke opties zijn er bij het vervangen van meters wat betreft het op afstand uitlezen en inzien van verbruiksgegevens?", "a": "De meters zijn op afstand uit te lezen. Zowel bij koop als bij lease van de meters is er een aanvullende optie om eigenaren inzage te geven in het dagelijks en historisch verbruik."}, {"v": "Hoe wordt bepaald of vochtdoorslag een verantwoordelijkheid is voor de VvE of voor een individuele eigenaar?", "a": "Om te bepalen of een vochtprobleem een VvE-aangelegenheid is, moet de oorzaak worden achterhaald. Indien de oorzaak zich in een privégedeelte bevindt (zoals een lekkage bij een toilet of badkamer van een eigenaar), dient de betreffende eigenaar de oorzaak te laten verhelpen. Indien de oorzaak in de gemeenschappelijke delen ligt, is het een zaak voor de VvE."}, {"v": "Onder welke voorwaarden kan een Algemene Ledenvergadering (ALV) plaatsvinden en zijn de besluiten dan rechtsgeldig?", "a": "Een ALV kan plaatsvinden op verzoek van een aantal eigenaren binnen de VvE in overeenstemming met het reglement van de VvE. Wanneer de vergadering volgens de regels is bijeengeroepen en de eigenaren de uitnodiging, agenda en eventuele bijlagen hebben ontvangen, zijn de tijdens deze vergadering genomen besluiten rechtsgeldig, ook als niet alle eigenaren aanwezig waren of hebben gereageerd op de notulen."}, {"v": "Wanneer wordt er een bedrijf ingeschakeld voor werkzaamheden aan de vergaarbak als de ruimtes nog niet toegankelijk zijn?", "a": "Wij zullen direct een bedrijf inschakelen zodra de betreffende ruimtes zijn vrijgemaakt."}, {"v": "Waarom staat het rekeningnummer voor de VvE-bijdrage in het portaal op 'onbekend'?", "a": "Het kan voorkomen dat het portaal aangeeft dat het rekeningnummer onbekend is wanneer de registratie bij de Kamer van Koophandel (KvK) nog niet is voltooid of verwerkt."}, {"v": "Wat zijn de voorwaarden voor het plaatsen van een warmtepomp op gemeenschappelijke delen van de VvE?", "a": "Voor het plaatsen van een warmtepomp op een gemeenschappelijk deel (zoals het dak of een balkon) is toestemming van de VvE vereist. Dit kan via een besluit in de vergadering met een gekwalificeerde meerderheid van stemmen (zie Artikel 38, lid 6 van de reglementen) of via een schriftelijke stemronde waarbij alle eigenaren unaniem instemmen en een verklaring ondertekenen. Voor de aanvraag zijn specificaties (zoals geluidsniveau in decibel) en de wijze van bevestiging noodzakelijk. De eigenaar is verantwoordelijk voor de installatiekosten, eventuele schade aan gemeenschappelijke delen en de kosten voor het tijdelijk verwijderen en terugplaatsen indien de VvE onderhoudswerkzaamheden aan het gebouw moet uitvoeren."}, {"v": "Mag ik de schoorsteenmantel in mijn woning verwijderen?", "a": "Het verwijderen van schoorsteenmantels kan niet zomaar, omdat deze vaak een dragende functie hebben voor de schoorsteen op het dak. Het verwijderen hiervan kan voor gevaarlijke situaties zorgen. In sommige gevallen is het mogelijk, maar dit moet door een deskundige worden beoordeeld. Daarnaast lopen in de schoorsteenmantels vermoedelijk ook de afvoeren van de ondergelegen appartementen welke niet onderbroken kunnen en mogen worden."}, {"v": "Wie is er verantwoordelijk voor het vaststellen van de hoogte van de maandelijkse VvE-bijdrage?", "a": "Hoewel de beheerder graag meedenkt over de hoogte van de maandelijkse bijdrage, ligt het uiteindelijke besluit hiertoe bij de Algemene Ledenvergadering (ALV). De bijdragen worden vastgesteld in lijn met de 'Wet verbetering functioneren VvE'."}, {"v": "Met wie kan ik contact opnemen voor het toevoegen van offertes aan de agenda voor de Algemene Ledenvergadering?", "a": "U kunt de betreffende offerte(s) versturen naar de beheerder, waarna deze ervoor zal zorgen dat deze worden toegevoegd aan de agenda voor de komende vergadering."}, {"v": "Hoe kan ik een offerte opvragen voor specifiek onderhoud aan het pand, zoals de boeiboorden?", "a": "U kunt de huidige onderhoudspartij vragen om vrijblijvend een offerte voor de betreffende werkzaamheden uit te brengen."}, {"v": "Is de VvE verantwoordelijk voor het onderhoud of de vervanging van brievenbussen en het intercomsysteem?", "a": "Brievenbussen en het intercomsysteem worden beschouwd als gemeenschappelijke voorzieningen van het gebouw. De verantwoordelijkheid voor onderhoud of vervanging hiervan ligt daarom bij de VvE."}, {"v": "Wat biedt het Totaal Portaal en kan ik daar ook de splitsingsakte, statuten of betaalgegevens inzien?", "a": "Via het Totaal Portaal heeft u als eigenaar op één centrale plek 24/7 inzicht in zaken die met uw VvE te maken hebben, zoals de notulen, jaarrekeningen, het meerjarenonderhoudsplan (MJOP) en uw betaalgegevens. Momenteel is hierin alleen het huidige jaar beschikbaar. De splitsingsakte en statuten kunt u opvragen bij de beheerder. U kunt veilig online inloggen op het portaal via https://totaalportaal.nl/login. Hier kunt u ook zelf uw wachtwoord instellen. Het portaal herkent u op basis van het (primaire) e-mailadres dat bij ons in de administratie bekend is."}, {"v": "Is schade door inbraak gedekt onder de opstalverzekering van de VvE?", "a": "Helaas kan de verzekeraar hierin vaak geen rol van betekenis spelen wanneer er een eigen risico bij de opstalverzekeraar van kracht is dat hoger is dan de geleden schade. In veel gevallen geldt er voor de opstalverzekering een eigen risico van 500 euro."}, {"v": "Is het mogelijk om de VvE schriftelijk op te starten in plaats van via een fysieke vergadering?", "a": "Wanneer het overgrote deel van de appartementen reeds aan nieuwe eigenaren is geleverd, is een schriftelijke opstart niet praktisch omdat hiervoor unanimiteit (100% instemming) vereist is. In dergelijke gevallen wordt er een fysieke of digitale Algemene Ledenvergadering ingepland waarvoor alle eigenaren een uitnodiging ontvangen."}, {"v": "Wat kan Totaal VvE Beheer betekenen als wij als VvE een MJOP willen laten opstellen?", "a": "Totaal VvE Beheer stelt zelf geen MJOP op, maar kan hiervoor een prijsopgave aanvragen of een bouwkundige inschakelen. Houd er rekening mee dat dit doorgaans niet op zeer korte termijn lukt. Omdat de kosten door de VvE voldaan moeten worden, dient de eigenaar de opdracht zelf aan de bouwkundige te verstrekken indien er nog onvoldoende saldo op de VvE-rekening staat."}, {"v": "Is het voordeliger om voor onderhoud te sparen op basis van een percentage van de herbouwwaarde of op basis van een MJOP, en hoe wordt dit bepaald als er nog geen MJOP is?", "a": "Dat is geheel afhankelijk van de staat van onderhoud; de ene VvE is voordeliger uit op basis van een MJOP en de ander op basis van de herbouwwaarde. Wanneer er nog geen MJOP aanwezig is, bijvoorbeeld bij een recent geactiveerde VvE, wordt de reservering wettelijk vastgesteld op basis van de geldende herbouwwaarde. Een inschatting van het verschil in maandlasten kan pas worden gegeven zodra er alsnog een MJOP is opgesteld."}, {"v": "Wat is het kantooradres van Totaal VvE Beheer?", "a": "Ons kantooradres is Volmerlaan 5 in Rijswijk."}, {"v": "Wat moet ik doen als ik een foutmelding krijg bij het inloggen op het portaal?", "a": "Stuur een screenshot van de foutmelding ('error') die u krijgt naar ons door, dan kunnen wij dit verder onderzoeken."}, {"v": "Wanneer en hoe kan ik inloggen op het Totaal Portaal?", "a": "U kunt 24/7 veilig online inloggen op het Totaal Portaal via https://totaalportaal.nl/login. Het systeem herkent u aan het (primaire) e-mailadres dat in onze administratie is opgegeven. Via de inlogpagina kunt u tevens uw wachtwoord instellen."}, {"v": "Wat is de rol van de beheerder ten opzichte van de besluiten in de Algemene Ledenvergadering (ALV)?", "a": "De beheerder heeft een uitvoerende taak wat betreft de besluiten die door de Algemene Ledenvergadering (ALV) zijn genomen."}, {"v": "Is het mogelijk om een ledenlijst van de VvE in te zien via het online portaal?", "a": "Op korte termijn is het inzien van een ledenlijst in het nieuwe portaal niet te realiseren. Op verzoek kan Totaal VvE Beheer een dergelijke lijst wel per e-mail verzenden aan de leden van de Raad van Toezicht."}, {"v": "Is het mogelijk om via het portaal de gegevens van andere eigenaren of een ledenlijst in te zien?", "a": "Op het Totaal Portaal kunnen eigenaren geen gegevens van andere eigenaren inzien."}, {"v": "Is er een app beschikbaar voor het VvE portaal die ik kan downloaden in de Playstore?", "a": "Wij hebben geen app welke je kan downloaden, het portaal is uitsluitend beschikbaar via de webpagina www.totaalportaal.nl."}, {"v": "Wat kan ik doen als ik verhinderd ben voor de (VvE-)vergadering?", "a": "Indien u niet fysiek aanwezig kunt zijn bij de vergadering, kunt u een volmacht afgeven. U kunt hiermee een andere eigenaar (een van uw buren) of de beheerder machtigen om namens u te stemmen."}, {"v": "Wie is verantwoordelijk voor de besluitvorming binnen de VvE?", "a": "De besluiten liggen te allen tijde bij de leden zelf (de vergadering)."}, {"v": "Moet de VvE zelf een taxatie regelen voor de garantie tegen onderverzekering bij het afsluiten van een nieuwe verzekering?", "a": "De VvE dient zelf een taxatie te regelen voor de garantie tegen onderverzekering."}, {"v": "Is het toegestaan om een inpandige garage als werkplaats te gebruiken?", "a": "Zolang het gebruik van de inpandige garage als werkplaats niet bedrijfsmatig is, is dit toegestaan voor de verzekering van de VvE."}, {"v": "Is een besluit van de VvE vernietigbaar als dit afwijkt van de splitsingsakte zonder dat deze akte is aangepast?", "a": "Ja, de splitsingsakte is leidend."}, {"v": "Wordt de voorzitter van de VvE apart ingeschreven bij de Kamer van Koophandel (KvK)?", "a": "Wij schrijven ons in als \"alleen/zelfstandig bevoegd\" bestuurder van de Vereniging bij de KvK. Het apart inschrijven van een voorzitter bij de KvK is niet nodig."}, {"v": "Vervullen jullie ook de rol van voorzitter tijdens de VvE-vergadering en is dit inbegrepen in de offerte?", "a": "Ja, dat is mogelijk en inbegrepen in de prijs. Bij kleinere VvE's vervult Totaal VvE Beheer doorgaans ook de rol van voorzitter van de vergadering."}, {"v": "Is het mogelijk om het beheer van een ondersplitsing uit te besteden zonder dat de hoofdsplitsing door dezelfde partij wordt beheerd?", "a": "Het beheer van een ondersplitsing is niet werkbaar zonder ook de hoofdsplitsing te beheren. Dit komt doordat de beheerder afhankelijk is van de besluitvorming in de hoofdsplitsing. Wanneer de hoofdsplitsing een vergadering uitschrijft, is er vaak onvoldoende tijd om eerst een vergadering met de ondersplitsing te beleggen om het stemgedrag te bepalen. Daarom nemen wij een ondersplitsing alleen in beheer als ook de hoofdsplitsing door ons wordt beheerd; u kunt zich anders het beste wenden tot de beheerder van de hoofdsplitsing. Indien de hoofdsplitsing nog niet actief is, kunnen wij uiteraard wel ondersteunen bij het gelijktijdig opzetten van zowel de hoofd- als de ondersplitsing."}, {"v": "Wie kan ik spreken voor dringende zaken tijdens de afwezigheid van mijn vaste contactpersoon?", "a": "Voor dringende zaken kunt u contact opnemen met de algemene administratie. Zij zijn bereikbaar via e-mail of telefonisch van maandag tot en met vrijdag van 09:00 tot 13:00 uur. Voor calamiteiten na 13:00 uur kunt u hetzelfde nummer bellen, u wordt dan doorgeschakeld naar de nooddienst."}, {"v": "Met welk type besluitvorming moet rekening worden gehouden bij een schriftelijke stemming buiten een vergadering?", "a": "Bij een schriftelijk besluit is - in tegenstelling tot een besluit op een vergadering - unanimiteit vereist."}, {"v": "Wanneer en hoe is Totaal VvE Beheer bereikbaar voor dringende zaken en reguliere vragen?", "a": "Voor zowel dringende zaken als reguliere vragen zijn wij telefonisch bereikbaar van maandag tot en met vrijdag van 09:00 tot 13:00 uur. Voor dringende zaken kunt u ons daarnaast ook per e-mail bereiken."}, {"v": "Wanneer en hoe is de klantenservice bereikbaar?", "a": "De klantenservice is telefonisch bereikbaar van maandag tot en met vrijdag van 09:00 tot 13:00 uur. Daarnaast kunt u voor vragen contact opnemen via e-mail."}, {"v": "Wat zijn de contactgegevens en bereikbaarheidstijden van Totaal VvE Beheer?", "a": "De medewerkers zijn bereikbaar via info@totaalvve.nl of telefonisch via 070 360 34 43 van maandag tot en met vrijdag van 09:00 tot 13:00 uur."}, {"v": "Wat zijn de openingstijden en contactgegevens voor dringende zaken?", "a": "Voor dringende zaken kunt u contact opnemen met de klantenservice (binnendienst). Zij zijn bereikbaar via e-mail of telefonisch van maandag tot en met vrijdag van 09:00 tot 13:00 uur."}, {"v": "Nemen jullie nieuwe klanten aan en wat is er nodig voor een prijsopgave?", "a": "Wij nemen nieuwe klanten aan. Om een vrijblijvende prijsopgave te kunnen maken en uit te leggen hoe de overstap kan worden geregeld, hebben wij de splitsingsakte van de VvE nodig."}, {"v": "Wat is er nodig om een VvE op te richten voor een pand dat wordt getransformeerd naar appartementen?", "a": "Voor de oprichting van een VvE is een conceptvoorstel tot oprichting (notulen) nodig. Daarnaast dienen de afgesloten contracten voor gemeenschappelijke zaken zoals de lift en elektra te worden aangeleverd."}, {"v": "Wat houdt de opschortingsbevoegdheid voor een instelling in met betrekking tot bijdragen aan het reservefonds?", "a": "Voor de periode dat een instelling eigenaar is van één of meer appartementen, kan zij bevoegd zijn de betalingen van verschuldigde bijdragen voor het reservefonds op te schorten. Deze opschorting eindigt wanneer de vergadering besluit tot het doen van uitgaven ten laste van het reservefonds, of wanneer de instelling overgaat tot overdracht van de appartementsrechten. Bij overdracht aan een andere instelling kan de opschorting gehandhaafd blijven mits de verkrijgende partij onvoorwaardelijk garandeert dat zij de openstaande bijdragen en eventuele financiële nadelen voor de vereniging zal voldoen zodra de betalingsverplichting ontstaat."}, {"v": "Wat is de procedure voor het melden en herstellen van gevolgschade in mijn woning?", "a": "De VvE heeft haar verzekeringen ondergebracht bij een verzekeraar met een zgn. 'herstel in natura' bepaling. Dit betekent dat schade rechtstreeks gemeld dient te worden bij de schade-expert of de volmachtpartij. Zij zorgen dan doorgaans voor het inschakelen van een schadeherstelbedrijf. Indien u reeds een offerte heeft ontvangen voor het herstel, kunt u dit bij de melding aangeven; wellicht dat de verzekeraar deze overneemt en het betreffende bedrijf alsnog de opdracht voor het herstel kan krijgen."}, {"v": "Wat is de rol van de beheerder in het contact met aannemers en de gemeente bij onderhoudswerkzaamheden?", "a": "Het kantoor speelt geen actieve rol in het contact richting aannemers en/of de gemeente tot het moment dat de eigenaren unaniem een akkoord hebben gegeven op een offerte van een uitvoerder."}, {"v": "Is Totaal VvE Beheer verantwoordelijk voor het wegwerken van onderhoudsgebreken die zijn vastgesteld voordat het beheer werd overgenomen?", "a": "Totaal VvE Beheer draagt geen verantwoordelijkheid en verricht geen inspanningen voor het wegwerken van onderhoudsgebreken die zijn beschreven in een gebrekenlijst voordat het beheer wordt gestart. Het is en blijft de verantwoordelijkheid van de eigenaren zelf om te zorgen dat de betreffende werkzaamheden worden uitgevoerd en dat de benodigde offertes hiervoor worden opgevraagd."}, {"v": "Welke documenten moeten worden verstrekt bij een informatieverzoek over de VvE?", "a": "Bij een informatieverzoek dienen de meest recente notulen, de goedgekeurde begroting en de verzekeringspolis te worden verstrekt."}, {"v": "Wat is het risico als de maandelijkse VvE-bijdrage lager wordt vastgesteld dan wettelijk verplicht is?", "a": "Wanneer de bijdragen niet conform de wet worden vastgesteld, bestaat het risico dat een toekomstige koper van een appartementsrecht zijn of haar financiering (hypotheek) niet rondkrijgt."}, {"v": "Welke stappen moeten worden ondernomen om een fictieve VvE formeel te registreren?", "a": "Om een VvE formeel te registreren moeten de volgende stappen worden gezet: 1. Inventariseren van de huidige splitsingsakte en het reglement. 2. Zorgdragen voor een (notariële) aanpassing van de splitsingsakte en het formeel oprichten van een VvE. 3. Het inschrijven van de Vereniging van Eigenaars bij de Kamer van Koophandel."}, {"v": "Waarom is een formeel geregistreerde rechtspersoon nodig voor een VvE?", "a": "Voor het voeren van professioneel beheer, het incasseren van bijdragen en het eventueel uit handen geven van vorderingen is een formeel geregistreerd rechtspersoon vereist. Zolang deze registratie ontbreekt, kunnen er geen beheerwerkzaamheden worden verricht of optredens namens de vereniging plaatsvinden."}, {"v": "Wat wordt er bedoeld met een fictieve VvE en wat zijn de gevolgen?", "a": "Een fictieve VvE ontstaat wanneer appartementsrechten bij akte zijn gesplitst, maar er destijds geen formele Vereniging van Eigenaars (bij akte) is opgericht. Dit levert juridische problemen op, zoals bij het verhalen van achterstanden; een incasso- of gerechtsdeurwaarder kan namelijk niet aanmanen namens een rechtspersoon die niet officieel bestaat in het kadaster of de KvK. Het advies is om in dergelijke gevallen de splitsingsakte te laten wijzigen en de VvE alsnog formeel op te richten via een notaris."}, {"v": "Wat is er nodig voor de oprichting van een VvE, het opstellen van een voorstel en de conceptnotulen?", "a": "Voor het opstellen van een voorstel en de (concept)notulen hebben wij de (concept) splitsingsakte nodig. Geef hierbij ook aan of er gezamenlijke voorzieningen zijn waar rekening mee gehouden moet worden, zoals aansluitingen voor gas, water en licht (gwl). Op basis van de akte worden de stukken ter goedkeuring verstuurd."}, {"v": "Wat moet ik aanleveren voor het laten opstellen van een Meerjarenonderhoudsplan (MJOP)?", "a": "Voor het opstellen van een Meerjarenonderhoudsplan (MJOP) is het belangrijk om zoveel mogelijk informatie over het complex te verstrekken. Denk hierbij aan tekeningen, een bestek, materiaal- en hoeveelhedenstaten, een eerder opgesteld MJOP en de onderhoudsgeschiedenis (recente werkzaamheden). Daarnaast moet worden aangegeven bij wie de inspecteur zich kan melden voor toegang tot het gebouw en technische ruimten, zoals het dak."}, {"v": "Hoe wordt er omgegaan met het mandaat voor reparaties bij calamiteiten wanneer deze boven de afgesproken grens uitvallen?", "a": "De Vereniging is verplicht om bij calamiteiten (vanuit verzekeringsoogpunt) schadebeperkend te handelen. Indien een reparatie van bijvoorbeeld een lekkage duurder uitvalt dan het beoogde mandaat, kan er niet gewacht worden op fiattering door de eigenaren. In dergelijke gevallen worden de eigenaren uiteraard direct geïnformeerd over de situatie en de vermoedelijke overschrijding van het mandaat."}, {"v": "Is bij Totaal VvE Beheer de bestuursfunctie gescheiden van de beheersfunctie en administratie?", "a": "Totaal VvE Beheer schrijft zich in als bestuurder bij de Kamer van Koophandel. Binnen de organisatie zijn de werkzaamheden verdeeld: een toegewezen beheerder fungeert als het dagelijkse aanspreekpunt, terwijl collega's van de administratie zorg dragen voor het verrichten van betalingen en alle overige financiële werkzaamheden."}, {"v": "Wat is het voordeel van het afsluiten van een nieuwe verzekering via de collectieve polis van de VvE beheerder?", "a": "Een reden om over te stappen naar een nieuwe collectieve verzekeraar kan een scherpere premiestelling zijn. Daarnaast bieden sommige verzekeraars bij aanvang van de polis een meerjarige garantie tegen onderverzekering aan (bijvoorbeeld voor een periode van 6 jaar). Dit biedt extra zekerheid ten opzichte van een regulier taxatierapport dat slechts een beperkte tijd geldig is."}, {"v": "Wanneer worden leden geïnformeerd over de inhoud van de verzekeringen van de VvE?", "a": "Leden worden doorgaans niet buiten een vergadering om per brief geïnformeerd over de inhoud van de verzekeringen. De jaarlijkse Algemene Ledenvergadering is het moment voor een VvE om besluiten over bepaalde geagendeerde onderwerpen te nemen, waaronder het bespreken of afsluiten van de collectieve verzekeringen."}, {"v": "Welke financiële voorwaarde geldt er voordat een VvE een opdracht voor onderhoud kan verstrekken?", "a": "Alvorens de VvE een opdracht kan verstrekken, dient het geld (de aanneemsom) op de rekening van de Vereniging te staan. Hiervoor moeten eventuele (eenmalige) bijdragen tijdig zijn vastgesteld en betaald."}, {"v": "Wanneer krijgt een Meerjarenonderhoudsplan (MJOP) een formele status binnen de VvE?", "a": "Een MJOP heeft pas een formele status zodra deze is vastgesteld of aangenomen tijdens de Algemene Ledenvergadering (ALV)."}, {"v": "Wat moet ik doen bij een lekkage in de dakdoorvoer?", "a": "Bij een lekkage kunnen wij een loodgieter inschakelen om de schade te herstellen. Hiervoor hebben wij een telefoonnummer nodig waarop u bereikbaar bent voor het maken van een afspraak."}, {"v": "Waarom is de lijst met kosten niet volledig gespecificeerd op de factuur?", "a": "Wij kunnen de volledige lijst van kosten niet in zijn volledigheid op de factuur kwijt. De factuur verwijst daarom naar het e-mailbesluit welke een overzicht geeft van de volledige lijst van kosten."}, {"v": "Is het noodzakelijk om een betalingskenmerk te vermelden bij het overmaken van de VvE-bijdrage?", "a": "Een betalingskenmerk is niet noodzakelijk, zolang u ervoor zorgt dat het bedrag elke maand op de rekening van de VvE verschijnt."}, {"v": "Hoe kan ik een verzoek indienen voor een aanpassing aan mijn schuur of berging, zoals het verbreden van een deur?", "a": "Ik zal het verzoek op de agenda plaatsen voor de komende vergadering. Ik adviseer u in dit geval dan wel zelf aanwezig te zijn tijdens de vergadering om e.e.a. persoonlijk aan de eigenaren toe te lichten."}, {"v": "Is de VvE beheerder partij bij afspraken over balkononderhoud die door de eigenaar zelf met de verkoper van de woning zijn gemaakt?", "a": "De VvE beheerder is geen partij in afspraken die u zelf met de verkoper heeft gemaakt voor het onderhoud aan uw balkon. U dient in dat geval zelf de verkoper en/of aannemer te benaderen voor de uitvoering. Wel verzoeken wij u de beheerder te informeren zodra de datum van het onderhoud bekend is."}, {"v": "Op welke basis wordt de minimale jaarlijkse reservering voor het reservefonds van een VvE vastgesteld?", "a": "In het kader van de Wet verbetering functioneren VvE worden de bijdragen voor het reservefonds vastgesteld op basis van minimaal 0,5% van de herbouwwaarde van het pand (gebaseerd op de opstalverzekering)."}, {"v": "Hoeveel correspondentieadressen kunnen er per woonadres worden geregistreerd?", "a": "Wij kunnen per woonadres slechts één correspondentieadres toevoegen aan ons systeem."}, {"v": "Waar kan ik documenten inzien en welke informatie is nodig bij de verkoop van een appartement?", "a": "Totaal VvE Beheer stelt zelf geen MJOP op; dit wordt bij een positief besluit van de vergadering uitbesteed aan gespecialiseerde derden. Voor de verkoop van een appartement zijn zaken zoals de notulen, jaarrekeningen, het verzekeringspolisblad en het MJOP van belang. Als eigenaar kunt u deze documenten 24/7 inzien en downloaden via het Totaal Portaal. In dit digitale portaal heeft u op één centrale plek inzicht in alle relevante stukken van uw VvE en uw persoonlijke betaalgegevens. U kunt zelf uw wachtwoord via het portaal instellen en zaken veilig online regelen via de inlogpagina. Het portaal herkent u aan de hand van het primaire e-mailadres dat in onze administratie bekend is."}, {"v": "Welke rol speelt de splitsingsakte bij de verdeling van de kosten en verantwoordelijkheden tijdens de oprichting van een VvE?", "a": "De verdeling in kosten en verantwoordelijkheden dient in de splitsingsakte te worden vastgelegd en geregeld. Bij de oprichting van de VvE wordt hier rekening mee gehouden."}, {"v": "Hoe kan ik een klacht indienen bij Totaal VvE Beheer?", "a": "Bij Totaal VvE Beheer streven wij naar een zorgvuldige en professionele dienstverlening. Toch kan het voorkomen dat u ergens niet tevreden over bent. In dat geval kunt u uw klacht per e-mail richten aan het daarvoor bestemde klachten-e-mailadres."}, {"v": "Hoe krijg ik toegang tot het online klantenportaal en hoe stel ik mijn wachtwoord in?", "a": "U kunt 24/7 gebruikmaken van het portaal via de inlogpagina. Het systeem herkent het door u opgegeven primaire e-mailadres dat in onze administratie bekend is. U kunt via de inlogpagina ook zelf veilig online uw wachtwoord instellen."}, {"v": "Hoe krijg ik toegang tot het digitale portaal van de VvE?", "a": "U kunt 24/7 veilig online inloggen via https://totaalportaal.nl/login voor inzicht in zaken zoals notulen, jaarrekeningen, het meerjarenonderhoudsplan (MJOP) en betaalgegevens. Het systeem herkent u op basis van het (primaire) e-mailadres dat bekend is in onze administratie. U kunt hier ook zelf uw wachtwoord instellen."}, {"v": "Wanneer worden besluiten uit een vergadering geformaliseerd als er te weinig stemmen aanwezig waren?", "a": "Indien er tijdens een vergadering formeel gezien te weinig stemmen vertegenwoordigd zijn om rechtsgeldige besluiten te nemen, moeten de notulen achteraf worden bekrachtigd. Dit kan door middel van het aanleveren van getekende machtigingsformulieren door de ontbrekende stemgerechtigden. Na ontvangst van deze documenten worden de notulen geformaliseerd en kunnen de actiepunten worden uitgevoerd."}, {"v": "Wat kan ik doen als ik het niet eens ben met de besluiten die tijdens een Algemene Ledenvergadering (ALV) zijn genomen?", "a": "Indien u het niet eens bent met de genomen besluiten, kunt u binnen 30 dagen bezwaar aantekenen bij de kantonrechter."}, {"v": "Wordt er periodiek inzicht gegeven in de financiële reserve en de uitgaven van de Vereniging van Eigenaren?", "a": "Zodra wij toegang hebben tot de rekening van de Vereniging, zorgen wij voor een overzicht van de huidige reserve van de Vereniging en stellen wij jaarlijks een jaarrekening op zodat de eigenaren kunnen zien wat er met het geld van de Vereniging gebeurt."}, {"v": "Wat zijn de stappen en benodigdheden voor een bestuurswijziging bij de Kamer van Koophandel (KvK)?", "a": "Voor een bestuurswijziging zijn de persoonsgegevens (voornamen, achternaam, e-mailadres en BSN) van zowel de nieuwe beheerder/bestuurder als de huidige tekenbevoegde bestuurder nodig, evenals een ingevuld en getekend machtigingsformulier. Na het aanleveren van deze gegevens stuurt de KvK een digitale link of verzoek met instructies naar de tekenbevoegde voor de uitschrijving en naar de nieuwe bestuurder voor de toetreding, zodat de administratieve overdracht kan worden voltooid."}, {"v": "Welke verzekeringen worden er collectief voor de VvE afgesloten?", "a": "Voor de VvE worden de (wettelijk verplichte) collectieve opstal-, glas- en aansprakelijkheidsverzekering afgesloten. Het polisblad hiervoor is beschikbaar in de administratie."}, {"v": "Wat gebeurt er als een offerte voor noodzakelijk onderhoud door de eigenaren wordt afgewezen via een schriftelijke stemming?", "a": "Wanneer de kosten voor onderhoud, zoals aan de gevel of schoorstenen, hoger zijn dan het bedrag waarover de beheerder zelfstandig mag beslissen, is toestemming van de eigenaren nodig. Indien een schriftelijke stemming negatief uitvalt, kan de offerte ter besluitvorming op de agenda van de volgende vergadering worden gezet. Daar moet dan een meerderheid van stemmen positief besluiten. Een andere optie is dat de betreffende eigenaar de VvE formeel aansprakelijk stelt voor de schade, wat de VvE dwingt om onderzoek naar de oorzaak te doen en het onderhoud alsnog uit te voeren."}, {"v": "Wanneer zijn de VvE-bijdragen verschuldigd en vanaf wanneer gaan de verzekeringen in bij een nieuw opgelichte VvE?", "a": "De bijdragen zijn verschuldigd per datum transport van het eerste appartement en per die datum zullen wij ook de verzekeringen laten ingaan."}, {"v": "Hoe krijg ik toegang tot het Totaal Portaal en hoe stel ik mijn wachtwoord in?", "a": "U kunt 24/7 veilig online inloggen via https://totaalportaal.nl/login. Hier kunt u ook zelf uw wachtwoord instellen. Het systeem herkent u op basis van het primaire e-mailadres dat in de administratie van de VvE-beheerder bekend is."}, {"v": "Wat biedt het Totaal Portaal en hoe krijg ik toegang tot mijn VvE-gegevens (bijvoorbeeld voor een taxatie of verkoop)?", "a": "Als (nieuwe) eigenaar wordt u doorgaans via de notaris bij ons aangemeld, waarna onze medewerkers u nadere informatie verstrekken. U kunt 24/7 gebruikmaken van ons digitale Totaal Portaal via https://totaalportaal.nl/login. Hiermee krijgt u op één centrale plek inzicht in alle documenten die u nodig heeft, ook voor een taxatie of verkoop, zoals de notulen, jaarrekeningen, het meerjarenonderhoudsplan (MJOP) en uw betaalgegevens. U kunt zelf uw wachtwoord instellen via de inlogpagina; het systeem herkent het bij ons bekende (primaire) e-mailadres."}, {"v": "Hoe werkt de inschrijving van een VvE bij de Kamer van Koophandel (KvK), wat is hiervoor nodig en hoe lang duurt de verwerking?", "a": "Doorgaans schrijft de notaris de VvE na het passeren van de akte in bij de KvK, waarbij ons kantoor vaak als (eerste) bestuurder wordt aangemeld. Indien dit niet direct gebeurt, kan dit komen doordat de splitsingsakte dateert uit een periode waarin geen formele VvE werd opgericht. In dat geval kan de VvE met algemene stemmen besluiten tot inschrijving en een bestuurder benoemen. Voor de inschrijving (en het aansluitend openen van een bankrekening) is een ingevuld en getekend machtigingsformulier van de eigenaar nodig en een 'origineel gewaarmerkt (papieren) afschrift' van de splitsingsakte met een 'natte handtekening' van de notaris. Indien de notaris de inschrijving niet verzorgt, ontvangen wij dit afschrift graag per post zodat wij dit kunnen doorsturen naar de KvK. De gemiddelde verwerkingstijd bij de KvK na ontvangst van deze documenten is 4 tot 5 werkdagen."}, {"v": "Is het nodig om zelf een opstalverzekering af te sluiten voor mijn appartement?", "a": "Nee, u hoeft zelf geen opstalverzekering af te sluiten omdat de VvE deze verzekering afsluit voor het gehele complex. Zelf verzekeren zou leiden tot een dubbele verzekering. De opstalverzekering van de VvE dekt alle adressen die in de polis vermeld staan; hoewel de hoofdpagina van een polis soms verwarrend kan zijn, staan alle individuele huisnummers vermeld op de bijbehorende pagina's met verzekerde adressen."}, {"v": "Wie is verantwoordelijk voor de cosmetische afwerking als er na onderhoud aan een gemeenschappelijk deel (zoals het plaatsen van nieuwe intercomschermen) gaten of beschadigingen achterblijven?", "a": "Schade als gevolg van een gebrek van of aan een gemeenschappelijk deel van de VvE komt voor rekening en risico van de Vereniging van Eigenaars. Wanneer de Vereniging echter besluit onderhoud uit te laten voeren en de kosten draagt voor het leveren en plaatsen van nieuwe onderdelen, is de verdere (cosmetische) afwerking in principe de verantwoordelijkheid van de eigenaar zelf. Hierover kan de vergadering van eigenaars in de toekomst echter nog andere besluiten nemen."}, {"v": "Wat zijn de gevolgen bij een niet-tijdige of onvolledige betaling van een factuur?", "a": "Bij niet, niet tijdige of niet volledige betaling van enig verschuldigd bedrag, is de opdrachtgever met ingang van de vervaldatum van de betreffende factuur van rechtswege in verzuim. Vanaf dat moment is de opdrachtgever naast de wettelijke handelsrente tevens een vertragingsrente van 1% per maand verschuldigd, waarbij een gedeelte van een maand als een hele maand wordt gerekend."}, {"v": "Is een VvE verplicht om verlichting te plaatsen in een buitenportiek?", "a": "Bij wet is dit niet verplicht, maar een VvE kan dit zichzelf wel verplichten door het op te laten nemen in de akte van splitsing (al komt dit laatste nauwelijks voor). Los van een wettelijke verplichting is het wel wenselijk te zorgen voor een werkende portieklamp om de vluchtweg goed zichtbaar te houden."}, {"v": "Welke stappen worden ondernomen bij de oprichting of overname van een VvE?", "a": "Na ontvangst van de (concept) splitsingsakte kan er een voorstel worden gemaakt. Zodra het machtigingsformulier getekend is, verzorgen wij de (wijziging van de) inschrijving bij de Kamer van Koophandel (KvK), vragen we toegang tot de bankrekening of openen we een nieuwe rekening, en worden de (verplichte) collectieve verzekeringen afgesloten om het beheer te kunnen starten."}, {"v": "Welke informatie moet worden aangeleverd voor een alternatief voorstel voor de VvE-verzekeringsportefeuille?", "a": "Voor een alternatief voorstel dienen de leveringsvoorwaarden, omzet (huidig jaar en prognose volgend jaar), de totale herbouwaarde van alle VvE's in beheer, het jaarverslag, het aantal VvE's in beheer en informatie over de uitvoering van het onderhoud te worden verstrekt, specifiek voor de werkmaatschappij."}, {"v": "Wat is de status van de lekkage aan de Nunspeetlaan 358 en wie is verantwoordelijk?", "a": "De aannemer (Bauhub) heeft de lekkage gecontroleerd. De oorzaak ligt in het kitwerk of de douchecabine van de bovenburen. Omdat dit geen gemeenschappelijke delen betreft, valt dit niet onder de verantwoordelijkheid van de VvE."}, {"v": "Kan je controleren wat de status is van de factuur voor het MJOP van Naeltwijckstraat 35-45 Voorburg?", "a": "Ik ga direct voor je nakijken waar de factuur van de VvE van Naeltwijckstraat 35-45 op dit moment in het proces hangt."}, {"v": "Hoe werkt de procedure bij schade-afhandeling en de uitbetaling van de vergoeding?", "a": "Een schade-expert rapporteert aan de verzekeraar, die vervolgens de VvE (beheerder) informeert over de goedkeuring en vervolgstappen. Bij een gedekte schade wordt het bedrag op de rekening van de VvE uitbetaald. Meestal gebeurt dit in twee delen: eerst 50% van het bedrag en na het aanleveren van de herstelfactuur de resterende 50%."}, {"v": "Hoe werkt het overzetten van een gezamenlijk internetcontract naar de VvE?", "a": "Voor het overzetten van een gedeeld internetcontract zijn het huidige contract en de laatste factuur nodig. Indien het contract via Ziggo loopt, dient de VvE zelf de omzetting te regelen of een nieuw contract op naam van de VvE af te sluiten. Hierbij moet ook zorg worden gedragen voor het retourneren van oude apparatuur en het plaatsen van nieuwe apparaten."}, {"v": "Wat is het minimale bedrag om een lening aan te vragen voor werkzaamheden aan de VvE?", "a": "Lenen kan alleen met een minimum van 15.000 euro."}, {"v": "Kan de VvE de kosten voor de levering en plaatsing van een balkonhek betalen vanuit de reservefondsen als de splitsingsakte stelt dat dit voor rekening van de eigenaar is?", "a": "In de splitsingsakte is doorgaans bepaald wie verantwoordelijk is voor bepaalde kosten. Om af te wijken van de splitsingsakte en kosten die voor rekening van een individuele eigenaar zijn toch vanuit de reserve van de VvE te betalen, is een unaniem besluit van alle eigenaren binnen de VvE benodigd. Hiervoor dienen alle eigenaren de betreffende offerte te ondertekenen voor akkoord."}, {"v": "Waarom wordt een lekdetectierapport soms niet direct gedeeld met de verzekeraar?", "a": "Een lekdetectierapport wordt soms bewust niet direct aangeleverd om het risico op afwijzing van de claim te beperken, bijvoorbeeld wanneer er een risico bestaat dat de schade wordt toegeschreven aan achterstallig onderhoud."}, {"v": "Is het afsluiten van een rechtsbijstandverzekering een vast agendapunt tijdens de vergaderingen?", "a": "Het afsluiten van een rechtsbijstandverzekering wordt voortaan standaard meegenomen in de agenda's van de vergaderingen."}, {"v": "Wie is verantwoordelijk voor het verhelpen van schimmel door condens en gebrekkige ventilatie?", "a": "Wanneer schimmelvorming wordt veroorzaakt door bewonersgedrag of een gebrek aan ventilatiemogelijkheden (zoals het ontbreken van roosters in kozijnen of onvoldoende stoken), is dit geen gebrek dat door de Vereniging van Eigenaren (VvE) wordt verholpen. De eigenaar dient dit zelf te verhelpen door de ventilatie te verbeteren en de ruimtes correct te verwarmen."}, {"v": "Wat moet ik doen bij dringende rioleringsproblemen nadat er een melding is gemaakt?", "a": "Wanneer er een melding is gemaakt bij de rioolservice en de situatie lijkt dringend, kunt u zelf contact opnemen met het gespecialiseerde bedrijf voor een afspraak onder verwijzing naar de eerdere melding vanuit de VvE beheerder."}, {"v": "Is informatie over de VvE, zoals schadeafwikkelingen en offertes, opvraagbaar voor leden?", "a": "Documenten en zaken met betrekking tot de VvE zijn beschikbaar en opvraagbaar voor de leden."}, {"v": "Welke stappen moeten worden ondernomen bij funderingsproblemen zoals wateroverlast in de kelder, schimmel of zwam?", "a": "Wanneer er problemen zijn met de fundering zoals zwam, schimmel of wateroverlast, kan er een gespecialiseerd bedrijf worden ingeschakeld voor een inspectie of om de fundering te dichten. Indien de algemene ledenvergadering (ALV) zelf suggesties heeft voor een specifiek bedrijf, kan dit uiteraard ook worden overwogen."}, {"v": "Hoe zijn de kosten voor glasverzekeringen binnen de VvE geregeld?", "a": "Wanneer in het reglement bij de kosten inzake de afgesloten verzekeringen door de vergadering ook het glas (woning) is opgenomen, vallen deze kosten binnen de vereniging. Eventuele wijzigingen in de verzekeringsportefeuille kunnen tijdens de Algemene Ledenvergadering (ALV) worden besproken."}, {"v": "Wat gebeurt er als er na de afronding van een project geld overblijft van een extra bijdrage?", "a": "Mocht er na afronding een stuk overblijven, kan de vergadering besluiten een deel terug te storten naar de leden. Het is echter vaak verstandiger dit in reserve te houden voor toekomstig onderhoud."}, {"v": "Hoe gaat de verzekeraar om met een verzoek tot contra-expertise bij een schademelding?", "a": "Wanneer er onenigheid ontstaat over de schadevaststelling door de expert van de verzekeraar, kan er een verzoek tot contra-expertise worden ingediend. De verzekeraar beoordeelt dit verzoek conform de polisvoorwaarden en de geldende procedures voor schadeafhandeling."}, {"v": "Wat is de wettelijke termijn voor de uitnodiging van een Algemene Ledenvergadering?", "a": "Dat verschilt per splitsingsakte en modelreglement. Wij hanteren vaak een uitnodigingstermijn van 15 dagen plus 2 dagen."}, {"v": "Wat zijn de ervaringen van Totaal VvE Beheer met het bedrijf CED voor taxaties, gezien de wisselende online reviews?", "a": "Wij hebben geen klachten over CED. De meeste negatieve reviews lijken betrekking te hebben op schadeafhandeling, wat een andere tak is binnen de organisatie. Met de brandschade-experts binnen dat bedrijf hebben wij juist zeer goed contact."}, {"v": "Zijn de notulen van het afgelopen jaar al beschikbaar voor de verkoop van mijn appartement?", "a": "In het klantportaal kunt u zien of de notulen beschikbaar zijn."}, {"v": "Wat moet ik doen als mijn ramen na onderhoudswerkzaamheden niet goed zijn schoongemaakt door het uitvoerende bedrijf?", "a": "Om de situatie te kunnen beoordelen en actie te ondernemen richting het uitvoerende bedrijf, is het noodzakelijk om foto's van de vervuiling aan te leveren ter beoordeling."}, {"v": "Waar kan ik informatie vinden over de voortgang of details van een wijziging in de splitsingsakte?", "a": "Voor specifieke details over de voortgang of de exacte inhoud van een wijziging in de splitsingsakte kunt u contact opnemen met de behandelend notaris. Totaal VvE Beheer beschikt niet altijd over de complete informatie zolang het proces bij de notaris loopt."}, {"v": "Kan een schildersbedrijf bij het uitvoeren van schilderwerk aan de kozijnen ook direct het glas vervangen door dubbele beglazing (HR++)?", "a": "Totaal VvE Beheer kan bij de uitvoerende partij nagaan in hoeverre zij, naast het schilderwerk, ook het vervangen van glas naar dubbel glas (HR++) kunnen verzorgen. Indien dit gewenst is, dient specifiek aangegeven te worden voor welke kozijnen dit verzoek geldt, zodat dit met de glaszetters afgestemd kan worden."}, {"v": "Is het raadzaam om een standleiding direct volledig te vervangen als deze deels openligt voor herstelwerkzaamheden, ook als er nog geen directe problemen zijn?", "a": "Wanneer een standleiding nog openligt, is het kostentechnisch voor de langere termijn vaak een betere optie om deze direct volledig te vervangen. Indien de vergadering hier niet mee akkoord gaat, dient er alsnog een oplossing te komen voor eventuele gevolgschade. Het volledig preventief vervangen van de leiding zorgt ervoor dat verdere schade in de toekomst wordt voorkomen en herstelwerkzaamheden voor alle betrokkenen afgerond kunnen worden."}, {"v": "Op welk rekeningnummer worden vergoedingen vanuit de vergadering door de beheerder uitbetaald?", "a": "Vergoedingen vanuit de vergadering worden overgemaakt naar het bij de beheerder bekende bankrekeningnummer waarvan ook de maandbijdragen worden betaald."}, {"v": "Hoe kan er toegang verkregen worden tot het dak voor werkzaamheden aan de rookgasafvoer?", "a": "Voor toegang tot het dak dient er vaak een afspraak gemaakt te worden met de bewoners van de bovenste verdieping, om te bepalen of het dak bereikbaar is via hun balkon of woning."}, {"v": "Is bij de VvE-beheerder bekend hoe oud de huidige rookgasafvoer van de woning is?", "a": "De VvE-beheerder heeft niet altijd informatie beschikbaar met betrekking tot de ouderdom van de rookgasafvoer. Wanneer er geen informatie bekend is, bestaat het vermoeden dat de leidingen verouderd zijn en dat er bij de installatie van een nieuwe CV-ketel een nieuwe leiding getrokken moet worden naar het dak."}, {"v": "Is het mogelijk om via WhatsApp of een mobiel nummer filmpjes of mediabestanden te versturen naar de VvE beheerder om schade of gebreken te melden?", "a": "Wij hebben geen mobiele nummers voor het ontvangen van filmpjes of andere mediabestanden. Mocht u deze kunnen e-mailen dan kunnen wij hier naar kijken."}, {"v": "Waar in de woning kan ik controleren op een lekkende standleiding als ik nog geen schade heb opgemerkt?", "a": "Bij een vermoeden van een lekkende standleiding is het raadzaam om de koof waar de leidingen doorheen lopen te controleren. Indien er sprake is van een lekkage op een andere etage, kan er visueel onderzoek worden gedaan bij de aansluitpunten van de leidingen in uw eigen woning om te zien of daar vocht of schade zichtbaar is."}, {"v": "Wat zijn de voorwaarden voor het plaatsen van een airco binnen de VvE?", "a": "Voor het plaatsen van een airco gelden specifieke voorwaarden, welke zijn vastgelegd in een officieel document dat op aanvraag beschikbaar is."}, {"v": "Hoe moet een schade aan het gebouw of glasschade worden gemeld bij een herstel in natura polis?", "a": "Schades aan het gebouw (Rubriek A) kunnen worden gemeld bij de alarmcentrale van uClaim via 088 554 00 05 of via de website www.uclaim.eu. Voor glasschaden (Rubriek C) kunt u contact opnemen met de Glaslijn via 0800 020 50 90. Bij een herstel in natura polis dient de verzekeringsnemer zelf de melding te maken om direct de terugkoppeling te ontvangen."}, {"v": "Kan ik een juridisch voorstel indienen voor de wijze waarop zaken genotuleerd moeten worden?", "a": "Het staat eigenaren vrij om via een jurist een voorstel te laten doen voor de wijze waarop bepaalde zaken genotuleerd moeten worden. Dit voorstel dient voorafgaand aan de vergadering aangeleverd te worden."}, {"v": "Mogen eigenaren aanvullende informatie of een toelichting naar de overige leden sturen ter voorbereiding op de ALV?", "a": "Wanneer eigenaren een aanvulling of toelichting willen sturen naar alle leden als voorbereiding op de ALV, kunnen zij dit zelfstandig doen. Het is hierbij gebruikelijk om de VvE-beheerder in de CC van de correspondentie mee te nemen."}, {"v": "Is het mogelijk om de agenda van de Algemene Ledenvergadering (ALV) nog aan te passen of agendapunten te wijzigen nadat de uitnodiging is verstuurd?", "a": "Wijzigingen aan de agenda worden over het algemeen niet doorgevoerd als de omschrijving te vaag is of als het verzoek tot aanpassing niet gegrond is. De beheerder behoudt zich het recht voor om verzoeken tot afzwakking of wijziging van agendapunten af te wijzen om de duidelijkheid van de vergadering te waarborgen."}, {"v": "Bij wie kan ik terecht met vragen over de afgrenzing tussen individuele en gemeenschappelijke zaken binnen de VvE?", "a": "Vragen over wat wel en niet individueel is, kunnen worden gesteld aan de beheerder van de VvE. Grote VvE's kunnen specifieke uitzonderingen hebben in de splitsingsakte; deze afwijkingen worden bij Totaal VvE Beheer vermeld onder het kopje kenmerken bij afwijking splitsingsakte."}, {"v": "Wanneer is het beste moment om de nokvorsten van het dak te laten afsmeren?", "a": "Voor het afsmeren van de nokvorsten is het advies om op warmer weer te wachten in verband met het gebruik van het materiaal voor het afsmeren."}, {"v": "Wie is verantwoordelijk voor de oplossing en de gevolgschade bij een lekkage van een individuele waterleiding?", "a": "Bij een lekkage van een individuele waterleiding dient de eigenaar van de betreffende leiding, in overleg met de buren die hinder ondervinden, zelf een oplossing te verzorgen. Dit geldt ook voor de afhandeling van de geconstateerde gevolgschade."}, {"v": "Wat zijn de opties als er onvoldoende saldo op de VvE-rekening staat voor een noodzakelijke opdracht?", "a": "Een optie is dat eigenaren een aanvullende vooruitbetaling doen om het tekort te overbruggen. De onderlinge verhouding en wijze waarop dit gebeurt, kunnen de eigenaren onderling bespreken. Deze vooruitbetaling is opvraagbaar zodra de openstaande vorderingen bij derden zijn voldaan."}, {"v": "Wie is verantwoordelijk voor de schadeherstel als de schade niet gedekt wordt door de verzekering of een individuele oorzaak heeft?", "a": "Wanneer schade niet bij de verzekering ingediend kan worden of wanneer er sprake is van een individuele schadeoorzaak, dienen de betrokken eigenaren dit onderling met elkaar op te lossen."}, {"v": "Wie bepaalt welke personen er moeten tekenen voor een volmacht bij de notaris?", "a": "Het is aan de notaris om aan te geven wie er moeten tekenen voor een volmacht."}, {"v": "Is het mogelijk om als eigenaar een individuele afspraak te maken met de VvE beheerder?", "a": "Wij maken in principe geen afspraken los met individuele eigenaren, met uitzondering van de ledenvergadering. Dit behoort niet tot onze standaard dienstverlening."}, {"v": "Wie is er verantwoordelijk voor het maken van een afspraak met een loodgieter voor onderzoek naar een lekkage en het verlenen van toegang tot de woningen?", "a": "De betreffende eigenaren zijn zelf verantwoordelijk voor het verzorgen van toegang tot de woningen. Het is niet de taak van de administrateur om te bemiddelen bij het maken van individuele afspraken tussen eigenaren en een externe partij zoals een loodgieter. Indien het niet lukt om gezamenlijk toegang te verlenen voor onderzoek of lekdetectie, is het aan de eigenaren zelf om dit te verhelpen of nader te onderzoeken."}, {"v": "Wie is er verantwoordelijk voor het onderhoud van het dak onder een dakterras?", "a": "Het dak onder het dakterras valt onder de verantwoordelijkheid van de VvE. Het terras zelf en het bijbehorende hekwerk vallen hier niet onder."}, {"v": "Hoe is de schoonmaak van het trappenhuis geregeld als er geen collectief schoonmaakcontract is?", "a": "Wanneer er voor een trappenhuis geen schoonmaakcontract is afgesloten, dienen de gebruikers hiervan zelf in onderling overleg voor de schoonmaak zorg te dragen."}, {"v": "Welke garantie is er dat eigenaren voorgeschoten bedragen voor werkzaamheden uiteindelijk terugkrijgen?", "a": "Voor een voorgeschoten bedrag wordt een vooruitbetaling in de administratie van de VvE opgenomen. Zodra de betaling binnenkomt, kan dit met de betreffende eigenaren worden verrekend."}, {"v": "Wat gebeurt er als ik voorafgaand aan een vergadering toelichtingen of standpunten indien met betrekking tot agendapunten?", "a": "De standpunten en toelichtingen die u schriftelijk indient met betrekking tot de agendapunten worden als aanvulling op de agendering beschouwd en dienen in de notulen van de vergadering te worden opgenomen."}, {"v": "Wat moet ik doen als ik nota's ontvang van leveranciers (zoals glazenwassers) die beweren dat er nog bedragen openstaan bij de VvE?", "a": "U kunt deze nota's naar de beheerder doorsturen. Wij zullen de administratie controleren en de openstaande posten bekijken."}, {"v": "Heeft de VvE recht op een tegemoetkoming vanwege hoge energieprijzen (zoals de TTB) en hoe wordt dit verdeeld?", "a": "Mocht er een tegemoetkoming beschikbaar zijn vanuit de Belastingdienst of overheid voor de VvE, dan zal de VvE deze ontvangen. Indien u hier documentatie over heeft, kunt u deze toesturen zodat wij dit kunnen controleren."}, {"v": "Wat is het voordeel van een verzekeringspakket met een gratis waardevaststelling?", "a": "Een waardevaststelling biedt garantie tegen onderverzekering, wat essentieel is voor de VvE."}, {"v": "Waarom moet een defect aan de standleiding eerst worden hersteld voordat gevolgschade aan de opstal wordt aangepakt?", "a": "Experts en herstelpartijen adviseren om eerst de oorzaak (de standleiding) fatsoenlijk aan te pakken voordat zij kunnen starten met het herstel van de gevolgschade."}, {"v": "Wanneer dient de algemene ledenvergadering (ALV) van de VvE uiterlijk gehouden te worden conform het reglement?", "a": "Dit verschilt per reglement, vraag dit voor de zekerheid na bij uw beheerder."}, {"v": "Is de VvE verantwoordelijk voor het onderhoud, bijvullen of vernieuwen van individuele cv-ketels?", "a": "Nee, zowel het onderhoud, het bijvullen als het vernieuwen van individuele cv-ketels valt niet binnen de verantwoordelijkheden van de VvE. Omdat de cv-ketels individueel eigendom zijn, worden deze kosten conform de splitsingsakte niet opgenomen in de gezamenlijke begroting en dient de eigenaar dit zelf te regelen."}, {"v": "Wat is de gebruikelijke gang van zaken bij onderhoud aan mandelige (gemeenschappelijke) zaken tussen twee VvE's?", "a": "Voor mandelige zaken is het gebruikelijk om vooraf afstemming te hebben over de werkzaamheden en de kostenverdeling, in plaats van achteraf een factuur te sturen. Om een verzoek tot kostenverdeling te kunnen beoordelen en voor te leggen aan de leden, is een compleet dossier nodig met een onderbouwing van de werkzaamheden, inclusief de originele offerte en foto's van de situatie voor en na de uitgevoerde werkzaamheden."}, {"v": "Wat moet er gebeuren als de afwerking rondom nieuw geplaatste kozijnen of het bijbehorende voegwerk niet goed is uitgevoerd?", "a": "Bij het installeren van nieuwe kozijnen is vaak voegherstel rondom nodig. Als de afwerking te wensen overlaat of het voegwerk in de hoeken niet netjes is meegepakt, dient de betreffende aannemer hiervoor aansprakelijk gesteld te worden en terug te komen om de gebreken te herstellen."}, {"v": "Is het mogelijk om maandelijkse overboekingen die al zijn gedaan te laten staan als vooruitbetaling voor de volgende jaarlijkse factuur?", "a": "Het is geen probleem om maandelijkse betalingen te laten staan. Deze worden dan geregistreerd als vooruitbetalingen die bij de eerstvolgende jaarlijkse factuur zullen worden verrekend."}, {"v": "Wordt de splitsingsakte volledig vernieuwd bij een wijziging in het reglement?", "a": "De akte wordt niet volledig vernieuwd, maar er wordt een akte van wijziging toegevoegd waarin de uitsluitingen worden gemeld en het laatste standaard reglement van toepassing wordt verklaard."}, {"v": "Waarvoor kan ik de backoffice omgeving van de VvE beheerder gebruiken?", "a": "In de backoffice omgeving kunt u alle gegevens omtrent uw VvE inzien en direct online een melding maken van benodigd onderhoud of een storing."}, {"v": "Kan de portiekverlichting aangepast worden naar verlichting met een bewegingssensor om energie te besparen?", "a": "Verzoeken voor het aanpassen van de portiekverlichting, zoals het plaatsen van sensoren, kunnen worden geagendeerd voor de komende Algemene Ledenvergadering (ALV) ter bespreking. Er kan dan tevens worden gekeken of er binnen de VvE bewoners zijn die hier zelf een rol in kunnen betekenen om kosten voor een elektricien te besparen."}, {"v": "Hoe gaat de VvE beheerder om met vragen van een notaris bij de verkoop van een appartementsrecht of garage?", "a": "Wanneer de notaris zich tot de VvE beheerder richt met specifieke vragen over de verkoop en de VvE (zoals de omvang van het reservefonds), worden deze zo snel mogelijk beantwoord."}, {"v": "Wat moet ik doen als ik herstelwerkzaamheden aan een lekkage heb laten uitvoeren zonder officiële factuur?", "a": "In het geval dat er geen officiële facturen aanwezig zijn voor herstelwerkzaamheden, is het raadzaam om een overzicht te maken van hoe en wat er precies is opgepakt. Dit overzicht kan vervolgens, samen met eventuele aankoopbonnen van materialen, worden ingebracht tijdens de Algemene Ledenvergadering (ALV) om de kosten middels een vergaderbesluit af te wikkelen."}, {"v": "Heeft het VvE-beheer informatie over de isolatie van het dak van het gebouw?", "a": "Vraag dit voor de zekerheid na bij uw beheerder."}, {"v": "Wat is de aanbevolen eerste stap bij het onderzoeken van een lekkage aan een (gedeelde) schoorsteen of het dak?", "a": "In de basis is het laten langskomen van een dakdekker de eerste stap. Een ervaren dakdekker kan vaak direct de oorzaak vaststellen en het probleem binnen het mandaat oppakken. Het inschakelen van een gespecialiseerd onderzoeksbureau is meestal pas nodig als een reguliere inspectie door een vakman niet volstaat."}, {"v": "Wat is de gebruikelijke betalingstermijn voor facturen?", "a": "De betaling van facturen gebeurt in principe altijd binnen 2 weken."}, {"v": "Waar moet ik op letten bij het indienen van een schadeclaim met betrekking tot het eigen risico?", "a": "Het is belangrijk om rekening te houden met het eigen risico per gebeurtenis. Het is niet altijd raadzaam om schades die qua bedrag dicht bij het eigen risico liggen in te dienen in verband met registraties in het systeem van verzekeraars (FISH)."}, {"v": "Zijn de bedragen die in een expertiserapport van de verzekeraar worden genoemd inclusief of exclusief BTW?", "a": "De bedragen in het expertiserapport van de verzekeraar zijn inclusief BTW."}, {"v": "Wat moet ik doen als er specifieke VvE-informatie of documenten ontbreken in de portaal?", "a": "In het geval er zaken ontbreken, kunt u de betreffende beheerder een e-mail sturen."}, {"v": "Wat is de procedure voor het melden van zaken zoals schade aan het portiekkozijn of graffiti?", "a": "Na ontvangst van foto's van de schade of de graffiti zullen deze zaken zo spoedig mogelijk worden uitgezet voor herstel."}, {"v": "Ik ben een nieuwe eigenaar binnen de VvE en zou graag het reglement willen inzien. Kunt u dit naar mij opsturen?", "a": "Het reglement van de VvE kunt u inzien op het klantportaal."}, {"v": "Welke partijen kunnen worden aanbevolen voor het opstellen of actualiseren van een onderhoudsplan?", "a": "Er zijn diverse gespecialiseerde partijen beschikbaar voor het opstellen van onderhoudsplannen. Totaal VvE Beheer heeft voorkeurspartijen die zij adviseren voor het uitvoeren van deze werkzaamheden."}, {"v": "Beschikt de beheerder over bouwtekeningen van het pand ten behoeve van een taxatie?", "a": "Vraag dit voor de zekerheid na bij uw beheerder."}, {"v": "Is het mogelijk om een melding te ontvangen zodra de jaarstukken gereed zijn?", "a": "Zodra de jaarstukken gereed zijn, kunt u deze inzien in het klantportaal. U ontvangt hiervan geen melding."}, {"v": "Mag een inspectie van een rookgaskanaal in opdracht worden gegeven middels het bestuurdersmandaat?", "a": "Het is mogelijk om een inspectie middels het bestuurdersmandaat in opdracht te geven, mits hierover afstemming heeft plaatsgevonden met de betrokken partijen/beheerder."}, {"v": "Welke acties moeten er ondernomen worden vanuit de VvE als een CV-ketel op een onbekend rookgaskanaal moet worden aangesloten?", "a": "Wanneer niet duidelijk is hoe een rookgaskanaal loopt, dienen er twee stappen te worden ondernomen: 1. Inspectie: Middels een camerainspectie moet worden vastgesteld tot hoever het kanaal omhoog loopt. 2. Rookgaskanaal verlenging: Op basis van de inspectie kan worden bepaald hoe het bestaande kanaal verlengd kan worden tot aan het dak."}, {"v": "Kunt u een loodgieter aanbevelen voor het inspecteren van een lekkage?", "a": "Vraag dit voor de zekerheid na bij uw beheerder."}, {"v": "Wat gebeurt er als de factuur voor herstelwerkzaamheden na een lekkage hoger is dan het door de verzekeraar vastgestelde schadebedrag?", "a": "Een factuur die hoger uitvalt dan het vastgestelde schadebedrag van de verzekeraar is mogelijk. In dat dient de VvE te beslissen of de overige werkzaamheden uitgevoerd mogen worden."}, {"v": "Welke informatie is er nodig bij het melden van een lekkage?", "a": "Bij het melden van een lekkage is het belangrijk om aan te geven wat de situatie is, ook is het handig om foto's en of video's te delen zodat we de situatie goed kunnen inschatten en de juiste partij kunnen inschakelen."}, {"v": "Is een garage of opslagruimte gedekt onder de huidige verzekeringspolis van de VvE?", "a": "Dit verschilt per polis, vraag dit voor de zekerheid na bij uw beheerder."}, {"v": "Waarom wordt een gevel soms niet volledig geïmpregneerd bij renovatiewerkzaamheden?", "a": "In sommige situaties volstaat de huidige staat van de gevel volledig om vochtwerend te zijn. Het selectief of deels impregneren van specifieke etages kan in bepaalde gevallen zelfs leiden tot andere bouwkundige problemen binnen het pand, waardoor het technisch niet raadzaam is om de gehele gevel te behandelen."}, {"v": "Wat is de procedure bij brandschade als er geen daders bekend zijn?", "a": "Wanneer er sprake is van brandschade en er zijn geen daders bekend, wordt de kwestie afgewikkeld met de verzekering."}, {"v": "Wat wordt er van de bewoner/huurder verwacht wanneer er dakwerkzaamheden worden uitgevoerd aan het pand?", "a": "Bij dakwerkzaamheden wordt vooraf contact opgenomen met de bewoners van de bovenetage om toegang te verkrijgen indien dit nodig is. Indien er in de offerte wordt aangegeven dat er gewerkt wordt met steigers, zullen deze aan de voorzijde van het pand worden geplaatst."}, {"v": "Hoe moet waterschade door een daklekkage worden afgehandeld als dit niet onder de verzekering valt?", "a": "Wanneer er sprake is van schade die niet door de verzekering wordt gedekt, dient er een herstelofferte te worden aangeleverd. Deze offerte kan vervolgens ter beoordeling aan de vergadering van eigenaars worden voorgelegd."}, {"v": "Kan de beheerder informatie verstrekken over de kleurcodes (zoals RAL-codes) van de kozijnen van een specifiek appartement?", "a": "De beheerder heeft hier helaas geen informatie over. Voor specifieke kleurcodes van schilderwerk dient vaak gekeken te worden in de splitsingsakte of bij eerdere onderhoudsverslagen, mits deze beschikbaar zijn gesteld aan het beheer."}, {"v": "Kan ik als aanstaande eigenaar direct een kopie van het polisblad van de collectieve verzekering opvragen bij de VvE-beheerder?", "a": "De VvE-beheerder mag de huidige polis niet rechtstreeks aan derden verstrekken. Een kopie van het polisblad dient via de huidige eigenaar van het appartementsrecht verzocht te worden."}, {"v": "Met welke doorlooptijd moet er rekening gehouden worden bij grote planmatige onderhoudswerkzaamheden?", "a": "Het is niet ongebruikelijk dat grotere planmatige klussen meerdere maanden duren voordat de uitvoering kan starten. Hierbij moet tevens rekening worden gehouden met seizoensinvloeden; bepaalde werkzaamheden kunnen bijvoorbeeld tijdens de winterperiode niet worden uitgevoerd vanwege de weersomstandigheden."}, {"v": "Moet onderhoud aan het dak met spoed uitgevoerd worden als er momenteel geen zware lekkages zijn?", "a": "Hoewel er op een specifiek moment geen sprake hoeft te zijn van zware lekkages, is het altijd de voorkeur om lekkages te voorkomen. Wanneer aannemers bij opname aangeven dat een dak aan vervanging toe is, wordt geadviseerd dit serieus te nemen om toekomstige schade te vermijden."}, {"v": "Kan de beheerder beslissen om geplande werkzaamheden, zoals dakvervanging, uit te stellen voor de VvE?", "a": "Of werkzaamheden uitgesteld kunnen worden, is aan de VvE (de gezamenlijke eigenaren) en niet aan de beheerder om te bepalen. De beheerder adviseert op basis van offertes en de staat van onderhoud, maar de besluitvorming ligt bij de ledenvergadering."}, {"v": "Is het mogelijk om een extra brievenbus te laten plaatsen voor een specifiek appartementsrecht?", "a": "Er kan op eigen kosten worden gezorgd voor een extra brievenbus. Hiervoor dienen de specificaties van de gewenste brievenbus te worden doorgegeven aan de beheerder."}, {"v": "Hoe geef ik een adreswijziging door voor mijn (zakelijke) correspondentie?", "a": "U kunt uw nieuwe adresgegevens schriftelijk of per e-mail aan ons doorgeven. Wij passen de gegevens vervolgens aan in onze administratie voor de betreffende complexen."}, {"v": "Waarom kan er vertraging optreden bij de uitvoering van planmatig onderhoud nadat de opdracht al is verstrekt?", "a": "Planmatig onderhoud kan in de huidige markt langer duren door een beperkt aanbod van aannemers en personeel. Het verstrekken van een opdracht betekent helaas niet automatisch dat de werkzaamheden nog in hetzelfde kalenderjaar worden opgepakt; de planning is afhankelijk van de beschikbaarheid van de uitvoerende partijen."}, {"v": "Is het mogelijk om een doorlopende volmacht te verstrekken voor standaardzaken?", "a": "Wij bieden de mogelijkheid om een doorlopende volmacht te ontvangen voor standaardzaken. Voorbeelden van de situaties waarin dit van toepassing is, zijn op aanvraag beschikbaar."}, {"v": "Hoe worden VvE-leden geïnformeerd over de datum van een taxatie door een externe partij?", "a": "Zodra de communicatie vanuit de externe partij over de datum van de taxatie is ontvangen, wordt dit aan de betrokkenen laten weten."}, {"v": "Is er een appartementenclausule van toepassing op de collectieve opstalverzekering en is er een aansprakelijkheidsverzekering afgesloten?", "a": "Ja, een appartementenclausule is van toepassing op de collectieve opstalverzekering. Daarnaast heeft de VvE ook een aansprakelijkheidsverzekering afgesloten."}, {"v": "Bij wie kan ik terecht voor een camera-inspectie van een schoorsteenkanaal als mijn reguliere schoorsteenveger dit niet kan uitvoeren?", "a": "Vraag dit na bij de beheerder, zij kunnen u adviseren welke partij geschikt is."}, {"v": "Kunnen aanvullende werkzaamheden aan het dak vanuit de reserve van de VvE worden betaald?", "a": "Deze offerte leggen wij middels een schriftelijke stemming aan jullie voor en kan vanuit de reserve betaald worden."}, {"v": "Wat verandert er aan de verzekeringspolis wanneer er een horecagelegenheid in het pand van de VvE komt?", "a": "Bij de aanwezigheid van horecagelegenheden worden de gebruikelijke clausules in de verzekeringspolis opgenomen. Daarnaast kunnen er specifieke preventiemaatregelen gelden die aan de huurder moeten worden doorgegeven. De premie kan in sommige gevallen ongewijzigd blijven, maar dit hangt af van de beoordeling door de verzekeraar."}, {"v": "Wat is het advies voor de afrekening van nutsvoorzieningen bij een ondersplitsing zonder eigen aansluitingen?", "a": "Het is raadzaam om tussenmeters te realiseren. Wanneer er gewerkt wordt zonder aparte aansluitingen of tussenmeters, ontstaan er vaak discussies over het verbruik en de kostenverdeling, zeker bij stijgende prijzen of verschillend stookgedrag. Om een gezonde splitsing te behouden, is het essentieel dat eigenaren hierover met elkaar in gesprek gaan."}, {"v": "Hoe werkt de besluitvorming en administratie bij een ondersplitsing met twee stemgerechtigden?", "a": "Bij een ondersplitsing met twee stemmen is voor alle zaken overeenstemming tussen beide partijen nodig voordat de administratie kan worden gevoerd. Zonder akkoord van beide eigenaren kunnen er geen specifieke reserves, bijdragen of incasso's worden vastgesteld of uitgevoerd."}, {"v": "Kan de VvE rekeningen voor energie en water betalen als er binnen een ondersplitsing geen overeenstemming is over de bijdragen?", "a": "Als er geen bijdragen worden betaald voor de kosten van stroom, gas en water, kan de VvE deze niet voldoen. Hiervoor zullen eerst de bijdragen vastgesteld moeten worden."}, {"v": "Wat moet ik doen als mijn appartement of specifieke werkzaamheden niet zijn opgenomen in een offerte voor groot onderhoud, zoals houtrotherstel?", "a": "Wanneer er zaken opgepakt moeten worden die niet in de huidige offerte staan, zal daarvoor een aanvullende offerte opgesteld moeten worden. Om dit proces te versnellen is het raadzaam om een overzicht met foto's van de benodigde werkzaamheden aan te leveren, zodat de situatie beoordeeld kan worden."}, {"v": "Heeft de VvE beheerder vaste aannemers voor onderhoudswerkzaamheden wanneer de eigen voorkeurspartijen van de klant niet beschikbaar zijn?", "a": "Wanneer vaste partijen van de klant niet langer beschikbaar zijn, kan de VvE beheerder zoeken naar geschikte aannemers. Het is echter ook praktisch om te kijken naar alternatieve voorkeurspartijen die de klant zelf kan aandragen voor het uitbrengen van offertes."}, {"v": "Wat gebeurt er met de individuele maandbijdragen van de eigenaren als de totale bijdrage aan de hoofdsplitsing wijzigt?", "a": "In het geval de maandbijdragen in de hoofdsplitsing wijzigen, ontvangen de eigenaren hier bericht over en worden de nieuwe maandbijdragen conform de huidige verhouding in dezelfde maand van kracht."}, {"v": "Is het mogelijk om toestemming te vragen aan de VvE voor tijdelijke verhuur voordat de eigenaar er zelf gaat wonen?", "a": "Een verzoek om een verhuurperiode van bijvoorbeeld 6 maanden (voordat de eigenaar er zelf gaat wonen) kan worden ingediend om te laten bespreken tijdens de Algemene Ledenvergadering (ALV). De vergadering kan dan bepalen of zij hier bezwaar tegen hebben."}, {"v": "Wat houdt een akkoord op een volmacht in met betrekking tot noodzakelijk onderhoud?", "a": "Binnen de volmacht wordt met een akkoord voor offertes ten behoeve van noodzakelijk onderhoud tevens akkoord gegeven op eventuele noodzakelijke eenmalige extra bijdragen die nodig zijn voor de uitvoering van dit onderhoud."}, {"v": "Is het mogelijk om werkzaamheden door een aannemer op regiebasis (uren en materiaal) te laten uitvoeren in plaats van via een vaste offerte?", "a": "Afhankelijk van wat de aannemer tegenkomt, kunnen werkzaamheden op basis van nacalculatie worden afgerekend, waarbij het aantal uren en het materiaal naar alle redelijkheid worden gefactureerd. Indien er de voorkeur aan wordt gegeven om met vaste offertes te werken, kan de VvE zelf een offerte aanleveren en het traject regelen."}, {"v": "Door wie moet een Meerjarenonderhoudsplan (MJOP) worden opgesteld?", "a": "Het opstellen van een MJOP dient vanuit de eigenaren geschreven te worden of door een onafhankelijk bouwkundige."}, {"v": "Waarom moet er een constructeur worden ingeschakeld bij schade of gebreken aan het gebouw?", "a": "Het inschakelen van een constructeur is noodzakelijk om de technische staat en veiligheid van de constructie te beoordelen, zeker wanneer visuele inspectie (zoals foto's) duidt op mogelijke constructieve problemen. Houd er rekening mee dat hier kosten aan verbonden zijn voor zowel het onderzoek als het toegankelijk maken van de betreffende locaties voor de constructeur."}, {"v": "Hoe kan een besluit worden genomen over onderhoudszaken die niet op de agenda van de ALV staan?", "a": "Voor zaken die niet op de agenda staan, kan eventueel besloten worden om een Technische Commissie aan te stellen met een mandaat om hierover te beslissen."}, {"v": "Kunnen de kosten voor werkzaamheden aan gemeenschappelijke delen van het gebouw uit de reservefondsen van de VvE worden betaald?", "a": "Het gemeenschappelijke stuk kan vanuit de reserve betaald worden."}, {"v": "Wat moet ik doen als er water omhoog komt in mijn toilet of douche wanneer de bovenburen gebruikmaken van het sanitair?", "a": "Wanneer er water omhoog komt bij het gebruik van sanitair op hogere etages, is het advies om verder onderzoek te laten doen naar de standleidingen door middel van een cameraonderzoek en een rookgasonderzoek. Neem contact op met de beheerder van de VvE."}, {"v": "Is het noodzakelijk om een bevestiging te sturen zodra een betaling is verricht?", "a": "Dit is niet nodig, ons systeem zal dit zelf herkennen."}, {"v": "Is het mogelijk om de voorschotten voor gas en elektra tussentijds aan te passen?", "a": "De voorschotten voor gas en stroom zijn gebaseerd op de beschikbare verbruiksstukken. Hierin kunnen geen aanpassingen worden gedaan tot het eerstvolgende afrekenmoment."}, {"v": "Wat gebeurt er als een reparatieverzoek buiten het mandaat van de beheerder valt?", "a": "Indien een reparatieverzoek of onderzoek niet binnen het mandaat kan worden uitgevoerd, zal er eerst een offerte volgen."}, {"v": "Kan ik een kopie van een bankafschrift van de VvE ontvangen voor de verkoop van mijn woning?", "a": "Ja, een kopie van het bankafschrift van de VvE kan op aanvraag worden verstrekt."}, {"v": "Beschikt de VvE-beheerder over een kopie van de koopakte van mijn appartement?", "a": "Nee, de koopakte hebben wij als VvE-beheerder niet in ons bezit."}, {"v": "Wat zijn de regels met betrekking tot het gebruik van de gemeenschappelijke toegang en het portiek?", "a": "Het portiek en de gemeenschappelijke toegang tot het portiek dienen vrijgehouden te worden van obstakels."}, {"v": "Wat moet de VvE doen als er tijdens onderhoudswerkzaamheden ernstige constructieve gebreken worden geconstateerd aan balkons?", "a": "Er wordt geadviseerd om in de tussentijd geen gebruik van het balkon te maken. Er zal middels een schriftelijke stemming aan de leden een verzoek worden voorgelegd voor een aanvullend mandaat voor de inzet van een constructeur om de situatie te beoordelen."}, {"v": "Is het toegestaan om zonder toestemming van de VvE door de gevel te gaan met bijvoorbeeld een rookgasafvoer (RGA)?", "a": "Het is niet toegestaan om zonder toestemming door de gevel te gaan met bijvoorbeeld een rookgasafvoer (RGA). Indien dit zonder toestemming is gebeurd, dient deze in principe verwijderd te worden."}, {"v": "Hoe gaat het beheer om met de privacy van contactgegevens van huurders die worden gedeeld voor reparaties of onderhoud?", "a": "De contactgegevens van huurders worden uitsluitend gedeeld met de betreffende aannemers die de werkzaamheden moeten uitvoeren."}, {"v": "Worden gaten in de gevel die zijn geboord voor het plaatsen van een steiger weer hersteld?", "a": "In geval van geboorde gaten in de gevel voor de steiger, zullen deze uiteraard worden hersteld."}, {"v": "Is het gebruikelijk dat kopers/nieuwe eigenaren aanwezig zijn bij een Algemene Ledenvergadering (ALV) vóór de officiële overdracht?", "a": "In principe is het niet gebruikelijk dat nieuwe eigenaren voor een overdracht aanwezig zijn bij de vergadering. Hiervoor zou toestemming gevraagd moeten worden aan de huidige eigenaren. De kopers zouden dan uitsluitend als toehoorder aanwezig kunnen zijn, tenzij er een volmacht wordt verstrekt door de huidige eigenaar."}, {"v": "Waarom wordt er bij onderhoud aan balkons op een hogere verdieping vaak ook naar de balkons op de verdiepingen daaronder gekeken?", "a": "De staat van balkons binnen hetzelfde complex is veelal soortgelijk. Als een balkon op een hogere etage gebreken vertoont, is de kans groot dat dit bij de onderliggende etages ook het geval is (soms in mindere mate, maar vaak is er wel onderhoud nodig)."}, {"v": "Wordt er bij kleine VvE's standaard een kascontrole uitgevoerd?", "a": "Bij kleine VvE's vindt er meestal geen kascontrole plaats. Op verzoek kunnen jaarstukken uitgebreid worden doorgenomen op de algemene ledenvergadering."}, {"v": "Welke mogelijkheden zijn er als de huidige verzekerde som van de opstalverzekering aanzienlijk hoger is dan de berekende herbouwwaarde?", "a": "Wanneer de verzekerde som afwijkt van de herbouwwaarde, zijn er verschillende opties: de verzekerde som verlagen naar het huidige berekende bedrag (waarbij het risico op onderverzekering blijft bestaan), de polis ongewijzigd laten, de som verlagen naar een tussenbedrag met een veiligheidsmarge, of het pand officieel laten taxeren door een deskundige instantie om de verzekerde som op basis van die taxatie aan te passen."}, {"v": "Waarom staat waterschade niet expliciet vermeld op het overzicht van de verzekering?", "a": "De dekking voor waterschade staat in de voorwaarden van de verzekering vermeld."}, {"v": "Wanneer kan een zelfbewoningsplicht worden opgenomen in de reglementen van de VvE?", "a": "Voor het invoeren van een zelfbewoningsplicht dient eerst de splitsingsakte te worden aangepast en moet er een nieuw concept van het Huishoudelijke Reglement worden opgesteld."}, {"v": "Wat moet ik doen bij overlast door omwonenden, zoals stankoverlast?", "a": "Wij adviseren om eerst zelf een poging te doen om aan te kloppen en onderling naar de situatie te kijken voordat er een melding wordt gemaakt."}, {"v": "Met wie moet ik contact opnemen voor het verifiëren van aktes of juridische details bij een notaris: de VvE-beheerder of moet ik dit zelf doen?", "a": "Dat zouden jullie zelf moeten doen, dit valt buiten de werkzaamheden van de administrateur/bestuurder."}, {"v": "Wanneer pakt de beheerder een aanschrijving of officieel document van een instantie op?", "a": "Pas wanneer documentatie officieel op papier aan de VvE gericht is, kan en zal de beheerder hiermee aan de slag gaan."}, {"v": "Zijn er kosten verbonden aan het annuleren van een aanvraag, zoals offertekosten?", "a": "Nee, er worden geen kosten in rekening gebracht zolang er nog geen opdracht is verstrekt."}, {"v": "Met wie kan ik contact opnemen voor juridische zaken zoals splitsingsaktes?", "a": "Wanneer u een externe partij hierin mee wilt nemen, kunt u het algemene e-mailadres aanhouden."}, {"v": "Kan de VvE actie ondernemen of een bouwkundige keuring afdwingen wanneer een eigenaar technische installaties (zoals ventilatie of CV) onjuist heeft aangesloten, wat leidt tot overlast of gevaarlijke situaties?", "a": "Vanuit de VvE kan er in dergelijke situaties weinig tot niets worden afgedwongen. In het geval van onjuiste aansluitingen of onveilige situaties door buren wordt geadviseerd om bouw- en woningtoezicht van de gemeente in te schakelen om dit te laten controleren en eventueel handhaven."}, {"v": "Soms kan de VvE bepaalde zaken niet afdwingen bij overlast of gebreken. Wat moet ik dan doen?", "a": "Wanneer de VvE vanuit haar bevoegdheden weinig of niets kan afdwingen, kan het noodzakelijk zijn om zelf Bouw- en woningtoezicht in te schakelen om de situatie te laten beoordelen."}, {"v": "Zijn de daklijsten van het pand onderdeel van de VvE?", "a": "Daklijsten zijn onderdeel van de VvE."}, {"v": "Wat is de procedure als ik een plan of wijziging wil voorleggen aan de vergadering?", "a": "Plannen moeten volledig uitgewerkt worden voorgelegd. Het is doorgaans het meest praktisch als dit ter plaatse doorgenomen wordt met de Technische Commissie (TC), voordat er iets richting de vergadering gaat."}, {"v": "Hoe kunnen bestaande afspraken over het onderhoud van algemene zaken het beste worden verwerkt bij de overstap naar een nieuw splitsingsreglement?", "a": "Bij de overstap naar een nieuw reglement (zoals Modelreglement 2017) kan de notaris worden verzocht om de specifieke wensen en opmerkingen zoveel mogelijk 1-op-1 over te zetten, inclusief de juiste verwijzingen naar de betreffende artikelen in het nieuwe splitsingsreglement."}, {"v": "Wat moet ik doen als er sprake is van een hardnekkige verstopping of lekkage waarbij toegang tot de woning van de buren noodzakelijk is, maar zij werken niet mee?", "a": "Wanneer werkzaamheden bij de buren uitgevoerd moeten worden en zij geven geen toestemming, is het advies om zo snel mogelijk Bouw- en Woningtoezicht op locatie te laten komen om een oplossing af te dwingen. Indien u een rechtsbijstandverzekering heeft, kunt u deze inschakelen. Heeft u deze niet, dan dient u de buren minimaal aansprakelijk te stellen; voor hulp hierbij kunt u informeren bij een rechtswinkel."}, {"v": "Onder welke voorwaarden kan een beheerder iemand sturen voor reparatiewerkzaamheden waarbij hakwerk nodig is?", "a": "Er kan pas iemand gestuurd worden voor reparaties zodra er expliciet toestemming is gegeven om open te hakken wat er opengehakt moet worden (bijvoorbeeld bij de buren indien noodzakelijk)."}, {"v": "Is een erker onderdeel van de gemeenschappelijke ruimte of wordt deze als individueel eigendom beschouwd?", "a": "Dit hangt af van hoe het in de splitsingsakte is beschreven, vraag dit voor de zekerheid bij de beheerder na."}, {"v": "Wat moet ik doen als ik een gunstigere offerte ontvang voor noodzakelijke werkzaamheden zoals gevel- of schilderwerk?", "a": "In het geval er een gunstigere offerte volgt, kunt u deze aan ons toesturen. Wij zullen deze vervolgens aan de vergadering voorleggen, dit kan schriftelijk of via de Algemene Ledenvergadering (ALV)."}, {"v": "Hoe kan de herbouwwaarde voor de opstalverzekering van de VvE het beste worden vastgesteld?", "a": "Om de herbouwwaarde van een pand correct vast te stellen, adviseert Totaal VvE Beheer om een officiële herbouwwaardetaxatie te laten uitvoeren."}, {"v": "Hoe kan ik een extra sleutel voor mijn voordeur aanvragen en waar kan ik deze ophalen?", "a": "Wanneer er voor uw complex een sleutelplan aanwezig is, kunt u na akkoord van de VvE een extra sleutel laten maken bij de aangewezen sleutelspecialist. U dient de sleutel daar zelf op te halen en direct af te rekenen."}, {"v": "Wanneer kan er een melding worden ingediend bij de opstalverzekering?", "a": "Het indienen van zaken bij de opstalverzekering is pas mogelijk nadat de schadeoorzaak of schadeoorzaken zijn weggenomen. Houd er rekening mee dat het eigen risico per gebeurtenis geldt."}, {"v": "Wat moet ik aanleveren als ik een melding maak voor onderhoudszaken?", "a": "Voor onderhoudszaken is altijd een offerte en/of foto's nodig om de melding in behandeling te kunnen nemen."}, {"v": "Kan Totaal VvE Beheer helpen bij het vergelijken van privéverzekeringen met de verzekeringen van de VvE?", "a": "Wij ondersteunen niet bij het vergelijken van de verschillen tussen uw huidige privéverzekeringen en die voor de VvE. Dit is een taak voor uw verzekeringsadviseur; het is met name belangrijk dat deze controleert of de dekking gelijkwaardig is."}, {"v": "Heeft de beheerder invloed op de planning of uitvoerdata van aannemers bij werkzaamheden?", "a": "De administrateur/bestuurder heeft geen invloed op de planning of uitvoerdata van aannemers. Dit wordt normaliter door de aannemer zelf gecommuniceerd en uitgevoerd."}, {"v": "Wat moet er gebeuren als er scheuren in de muren van een appartement zichtbaar zijn?", "a": "Bij het constateren van scheuren kan worden beoordeeld of het om werkingsscheuren gaat. Indien het niet acuut is, is het raadzaam om bij een update van het Meerjarenonderhoudsplan (MJOP) een bouwkundige specifiek naar deze scheuren te laten kijken en dit vervolgens te bespreken in de Algemene Ledenvergadering (ALV)."}, {"v": "Hoe kan ik extra fietsbeugels of fietsnietjes aanvragen bij de gemeente?", "a": "U kunt via de website van de gemeente een aanvraag indienen voor het laten plaatsen van fietsbeugels in de openbare ruimte."}, {"v": "Zijn rookmelders verplicht in het gebouw?", "a": "Het is wettelijk verplicht om rookmelders te plaatsen."}, {"v": "Wat moet ik doen als een regenpijp of hemelwaterafvoer (HWA) verstopt zit en dreigt over te lopen?", "a": "Wanneer een hemelwaterafvoer overloopt en potentieel schade kan veroorzaken, kunt u in overleg met de buren proberen de afvoer door te prikken om de ergste druk te verlichten. Ondertussen zal de VvE beheerder een loodgietersbedrijf inschakelen om de verstopping definitief te verhelpen en eventuele defecte delen van de afvoer te vervangen."}, {"v": "Hoe wordt de minimale inleg voor het onderhoud van de VvE bepaald?", "a": "De bestuurder geeft aan wat er minimaal ingelegd moet worden voor de uitvoer van het onderhoud. Het is vervolgens aan de ledenvergadering om hier wel of niet mee akkoord te gaan."}, {"v": "Bij welke instantie kan ik een melding maken van een onveilig of illegaal bouwwerk bij de gemeente?", "a": "U kunt hiervoor een melding maken bij de Haagse Pandbrigade van de gemeente. Het is daarbij belangrijk dat zij weten om welke VvE het gaat en namens welk appartement de melding wordt gedaan."}, {"v": "Valt het uitvoeren van onderhoud aan de riolering onder de verzekering?", "a": "Het uitvoeren van onderhoud aan de riolering is nooit verzekeringswerk. Werkzaamheden die betrekking hebben op onderhoud hebben niets met de opstalverzekering van doen."}, {"v": "Is het mogelijk om telefonisch contact op te nemen via WhatsApp?", "a": "Bellen via WhatsApp is niet mogelijk bij ons."}, {"v": "Hoe kan ik het beste een afspraak maken bij Totaal VvE Beheer?", "a": "Bellen voor afspraken is het beste via onze telefonische ondersteuning. Wij zijn bereikbaar op maandag tot en met vrijdag tussen 09.00 en 13.00 uur op het telefoonnummer 070 360 3443."}, {"v": "Is gevolgschade standaard opgenomen in een offerte?", "a": "Gevolgschade is niet standaard inbegrepen in de offerte."}, {"v": "Is het mogelijk om via WhatsApp contact te houden met de beheerder voor snelle afstemming?", "a": "Nee, het is niet mogelijk om via WhatsApp contact te houden voor afstemming."}, {"v": "Wat kan ik doen als er tijdens de vergadering voldoende stemmen zijn, maar er naar mijn mening geen gewenst besluit wordt genomen?", "a": "Mocht er een besluit worden genomen waar u het niet mee eens bent, dan heeft u altijd de mogelijkheid om zelf de stap richting de kantonrechter te zetten voor een vervangende machtiging."}, {"v": "Hoe gaan we om met een MJOP waarin nog punten staan die opgelost moeten worden, zonder dat er direct een volledig nieuw MJOP opgesteld hoeft te worden?", "a": "Het meest praktisch is om een fotodocument aan te leveren van de opgeloste punten. Dit kan vervolgens als aanvulling bij het MJOP worden gevoegd."}, {"v": "Wanneer wordt er gekozen voor het volledig vervangen van een kozijn in plaats van alleen schilderen?", "a": "Een kozijn wordt volledig vervangen wanneer de staat van het houtwerk dusdanig slecht is dat reparatie of schilderwerk niet meer volstaat, bijvoorbeeld als het kozijn loskomt of ernstig is aangetast."}, {"v": "Hoe verloopt de procedure bij het overstappen naar een andere bankrekening voor de VvE?", "a": "Er wordt een nieuwe bankrekening aangevraagd. Zodra deze bekend is, worden de eigenaren geïnformeerd met het verzoek om vanaf de volgende maand naar dit nieuwe rekeningnummer te betalen. Vervolgens wordt het saldo van de oude rekening overgeboekt naar de nieuwe rekening en wordt de oude rekening gesloten."}, {"v": "Wat moet ik doen als een internetprovider (zoals KPN) weigert installatiedocumenten of een technisch rapport van de glasvezelaanleg naar de VvE te sturen?", "a": "De installateur hoort een plaatsingsdocument te kunnen verzorgen voor de VvE. Een andere optie is om te kiezen voor een professionele partij die wel bereid is de nodige documentatie en toestemmingsrapporten te delen."}, {"v": "Is het toegestaan voor lekdetectiebedrijven om vanuit ramen aan de buitengevel te werken?", "a": "Dit dient met het lekdetectiebedrijf afgestemd te worden. Er is een grote kans dat zij in verband met ARBO-wetgeving niet uit ramen mogen hangen voor werkzaamheden aan de buitenzijde."}, {"v": "Wat kan de oorzaak zijn van condensvorming op de ramen bij een appartement?", "a": "Hoewel gebreken aan de gevel (zoals openstaande voegen) een rol kunnen spelen, kan condensvorming op ramen ook veroorzaakt worden door slecht ventileren."}, {"v": "Heb ik toestemming nodig van de VvE voor het plaatsen van een pergola?", "a": "Of er toestemming nodig is, hangt af van de situatie. Het is belangrijk om te weten of de pergola aan de gevel of andere gemeenschappelijke zaken wordt bevestigd. Daarnaast spelen de afmetingen een rol en of het bouwwerk volgens de gemeentelijke richtlijnen vergunningsplichtig is. Dien daarom altijd een concreet voorstel in bij de VvE-beheerder, zodat deze kan beoordelen of er toestemming gevraagd moet worden of dat er aanvullende informatie nodig is."}, {"v": "Wie is er verantwoordelijk voor het opvolgen van garantieverzoeken bij een zelf aangedragen partij door de VvE?", "a": "Wanneer er garantieverzoeken liggen bij een door de VvE zelf aangedragen partij, ligt de verantwoordelijkheid voor het oplossen en het versturen van herinneringen bij de eigenaren zelf."}, {"v": "Met wie moet ik contact opnemen voor advies over particuliere verzekeringen?", "a": "Wanneer we het over particuliere verzekeringen hebben, dan verwijzen we altijd naar de eigen verzekeringsadviseurs."}, {"v": "Welke bedrijven kunnen benaderd worden voor het verhelpen van bruinrot/vochtproblemen in de kruipruimte?", "a": "U kunt hiervoor contact opnemen met gespecialiseerde bedrijven zoals Den Heijer Vochtwering of NooitmeerZwam. Bij het opvragen van informatie kunt u vermelden dat de uiteindelijke opdracht zeer waarschijnlijk via de VvE zal lopen."}, {"v": "Is het mogelijk om op korte termijn een VvE-vergadering in te plannen voor de goedkeuring van plannen zoals het uitbreiden van een groepenkast of het plaatsen van warmtepomp-units?", "a": "Het is mogelijk om plannen voor bijvoorbeeld de uitbreiding van een groepenkast of de installatie van warmtepomp-units op papier te zetten en middels een schriftelijke stemming aan de leden voor te leggen. Op deze manier kan er wellicht akkoord worden gegeven zonder dat er een extra fysieke vergadering hoeft plaats te vinden, wat de VvE kosten voor een extra vergadering kan besparen."}, {"v": "Wat is de beste aanpak wanneer de VvE een aanschrijving van de gemeente ontvangt voor noodzakelijk onderhoud?", "a": "Bij een aanschrijving vanuit de gemeente is het essentieel om direct in contact te treden met de gemeente of de betreffende instantie (zoals de pandbrigade). Door actieve communicatie te onderhouden en aan te tonen dat de VvE voortgang boekt met de uitvoering van de vereiste werkzaamheden, kan de preventie van definitieve dwangsommen worden bewerkstelligd."}, {"v": "Hoe moet de VvE omgaan met een illegaal dakterras of bouwwerk op het gezamenlijke dak?", "a": "In het geval van een onrechtmatig geplaatst bouwwerk, zoals een dakterras of schuurtje, dient eerst te worden achterhaald welke eigenaar hier gebruik van maakt. Vervolgens is de eerste stap om de betreffende eigenaar dwingend aan te schrijven. In de basis is dergelijke problematiek op dat moment een verantwoordelijkheid van de eigenaar en (nog) niet direct een probleem voor de VvE als geheel."}, {"v": "Kan de VvE-beheerder het aanbrengen van vogelwering organiseren?", "a": "Het organiseren van vogelwering behoort niet tot de standaard werkzaamheden van de beheerder. Wanneer er een offerte voor dergelijke voorzieningen wordt ontvangen, kan deze aan de vergadering van eigenaren worden voorgelegd. Indien andere eigenaren hier geen belang bij hebben, kan het zijn dat er een toestemmingsverzoek moet worden ingediend zodat u deze voorzieningen voor eigen rekening mag aanleggen."}, {"v": "Waar moet men rekening mee houden bij de renovatie van een stenen portiektrap?", "a": "Bij de renovatie van een portiektrap moet er rekening mee worden gehouden dat achter de stenen treden vaak een houten skeletbouw zit. Zodra de treden worden weggehaald, bestaat de kans dat het onderliggende houtwerk aangetast of rot is en vernieuwd dient te worden."}, {"v": "Moeten bewoners thuis zijn voor werkzaamheden aan de granito vloer in de gemeenschappelijke ruimtes als er bij hen binnen niets gedaan wordt?", "a": "In principe is er voor werkzaamheden aan de granito vloer in de gemeenschappelijke ruimtes alleen toegang beneden in de centrale hal of entree nodig."}, {"v": "Hoe moet ik handelen bij zaken die enkel de appartementen van de direct betrokken eigenaren aangaan?", "a": "Bij zaken die feitelijk alleen de betreffende appartementen aangaan, wordt geadviseerd om eerst afstemming te zoeken tussen de betrokken eigenaren onderling."}, {"v": "Worden werkzaamheden aan kozijnankers in de gevel gezien als gemeenschappelijk onderhoud of als individuele kosten?", "a": "Wanneer kozijnankers behandeld of vervangen moeten worden voor een goede afronding van noodzakelijk gevelwerk, dienen deze als onderdeel van de gemeenschappelijke gevelwerkzaamheden gezien te worden."}, {"v": "Wanneer is een meerderheid van 80% van de stemmen vereist en wat is de procedure bij een splitsingsakte?", "a": "Een meerderheid van 80% van de stemmen is vereist voor het aangaan van leningen en voor aanpassingen van de splitsingsakte. Bij een aanpassing van de splitsingsakte is het vervolgens van belang dat alle eigenaren de aanpassing ondertekenen bij de notaris; dit kan ook via een volmacht."}, {"v": "Hoeveel stemmen zijn er nodig voor een besluit over offertes en het vaststellen van een eenmalige extra bijdrage?", "a": "Besluiten over offertes en het vaststellen van eenmalige extra bijdrage(n) gebeurt met een meerderheid van de stemmen."}, {"v": "Wat moet ik doen bij een lekkage of verstopping aan de standleiding van het complex?", "a": "Wanneer er sprake is van een lekkage of verstopping in de standleiding, dient u dit zo snel mogelijk te melden bij de beheerder (buiten kantoortijden via het noodnummer). Totaal VvE Beheer zal vervolgens een rioolservice of aannemer inschakelen om het probleem te verhelpen. Houd uw contactgegevens bij de hand voor het inplannen van een afspraak."}, {"v": "Wanneer wordt een waterleiding als individueel beschouwd in een VvE?", "a": "Wanneer een leiding vanaf de individuele watermeter loopt en alleen dienstbaar is aan het betreffende appartement, wordt deze als individueel beschouwd."}, {"v": "Is schade aan de portiektrap als gevolg van onjuist gebruik door bewoners (zoals het overmatig gieten van water) gedekt door de verzekering?", "a": "Schade die ontstaat door onjuist handelen van gebruikers, zoals het overmatig gieten van water over de trap, wordt doorgaans niet aangemerkt als verzekeringswerk. De kosten voor herstel van dergelijke schade vallen niet onder de verzekering."}, {"v": "Is de financiële situatie van een VvE van invloed op de verantwoordelijkheid van de leden voor het onderhoud?", "a": "De financiële situatie van de VvE staat volledig los van de verantwoordelijkheid van de leden om het onderhoud te verzorgen."}, {"v": "Welke rol speelt de beheerder bij de aanleg van glasvezel en de technische schouw?", "a": "Voor de aanleg van glasvezel dient u zelf de afspraken te organiseren met de glasvezelleverancier. De beheerder bemiddelt hier niet in. Na ontvangst van het schouwrapport wordt deze uitsluitend ter goedkeuring aan de leden voorgelegd."}, {"v": "Met wie kan ik contact opnemen voor de status van reparaties of dossiers die via de verzekering lopen?", "a": "U kunt hiervoor het beste contact opnemen met uw beheerder. Zij kunnen u verder helpen of namens de vereniging contact opnemen met de verzekeraar."}, {"v": "Hoe wordt de berekening van de maandbijdragen bepaald?", "a": "De berekening van de maandbijdragen bestaat uit de vaste kosten uit de begroting plus het gemiddelde uit het Meerjarenonderhoudsplan (MJOP), berekend per appartement per maand. In het kader van de wet verbetering functioneren VvE is het vaststellen van deze bijdrage op basis van een MJOP wettelijk verplicht."}, {"v": "Is het mogelijk om rapporten of documenten als fysiek exemplaar (hard copy) te ontvangen?", "a": "Wij ontvangen en verstrekken de stukken alleen digitaal."}, {"v": "Wanneer kan er een offerte worden opgesteld voor werkzaamheden in de kruipruimte?", "a": "Zodra de kruipruimte leeggehaald en toegankelijk is, kan een partij de situatie bekijken om hiertoe een offerte op te stellen."}, {"v": "Is het mogelijk om naast een offerte voor houtrotherstel ook een offerte op te laten stellen voor het volledig vervangen van kozijnen?", "a": "Het is mogelijk om een aanvullend verzoek in te dienen om ook een prijsopgave op te laten stellen voor de volledige vervanging van de kozijnen."}, {"v": "Waar moet ik op letten als de VvE een opstalverzekering heeft met een lagere dekking voor eigenarenbelang?", "a": "Het is raadzaam voor alle eigenaren om de eigenarenbelang dekking binnen de particuliere pakketten (of zakelijke pakketten in geval van verhuur) goed na te kijken."}, {"v": "Wanneer wordt er gestart met werkzaamheden of renovaties nadat er offertes zijn opgevraagd?", "a": "De planning voor werkzaamheden volgt doorgaans op een vast proces: eerst worden de benodigde gelden geïncasseerd en vervolgens worden de definitieve offertes opgevraagd voordat er een concrete planning kan worden gemaakt."}, {"v": "Is er sprake van garantie op werkzaamheden die niet in de oorspronkelijke offerte of het MJOP zijn opgenomen?", "a": "Op zaken waar niet aan gewerkt is, zit geen garantie. Indien bepaalde gebreken nog in goede staat waren tijdens de opname van het MJOP en niet zijn opgenomen in de uitgevoerde offerte, vallen deze niet onder de garantiebepalingen van die specifieke werkzaamheden."}, {"v": "Is voor een keuring van de elektrische installaties binnen de VvE een Scope 8 rapport voldoende, of is een Scope 10 rapport vereist?", "a": "Voor de keuring van elektrische installaties wordt doorgaans een SCOPE 10 inspectie verwacht, aangezien deze specifiek gericht is op brandveiligheid van elektrische materieel, in tegenstelling tot de algemene veiligheidsinspectie van een SCOPE 8."}, {"v": "Wat doet de beheerder als een Vereniging van Eigenaren (VvE) wordt overgenomen met achterstallig onderhoud?", "a": "Bij de start van het beheer wordt direct geëvalueerd welke onderhoudswerkzaamheden prioriteit hebben. Er worden offertes opgevraagd bij verschillende partijen en deze worden ter besluitvorming voorgelegd aan de Algemene Ledenvergadering (ALV)."}, {"v": "Hoe kan ik zien of een specifiek bericht in een algemene mededeling voor mij bedoeld is?", "a": "Als een bericht specifiek voor een bepaalde eigenaar is bedoeld, wordt dit aangegeven met @naam eigenaar voor het betreffende tekstdeel."}, {"v": "Wanneer kan ik uit een VvE stappen?", "a": "Uit de VvE stappen kan alleen bij de verkoop van het appartement."}, {"v": "Ben ik als nieuwe eigenaar verantwoordelijk voor spullen of afval die een vorige eigenaar heeft achtergelaten in gemeenschappelijke ruimten of kruipruimtes?", "a": "Als rechtsopvolger ben je verantwoordelijk voor de staat van de ruimtes die bij het appartement horen, inclusief eventueel achtergelaten spullen of afval. Eventuele kosten of benodigde acties hiervoor dienen zelf verhaald te worden op de vorige eigenaar als u van mening bent dat dit niet door u is veroorzaakt."}, {"v": "Komt de beheerder altijd op locatie kijken bij meldingen van overlast of schade?", "a": "De beheerder doet het beheer en bestuur in principe vanaf afstand en gaat in de regel niet zelf op locatie kijken. Er wordt gewerkt met de input van de eigenaren. Indien een verzoek concreter gemaakt moet worden, kan er gevraagd worden om foto's of andere bewijsstukken aan te leveren."}, {"v": "Wat is de rol van de beheerder bij schadevergoedingen tussen buren of aangrenzende panden?", "a": "Wanneer er schade is ontstaan (of mogelijk nog meer schade zou kunnen ontstaan), dan wordt van de bestuurder verwacht dat deze de betreffende eigenaar (of de rechtsopvolger van de betreffende veroorzaker) aanschrijft voor die schade. Het is vervolgens aan de eigenaar in hoeverre dit weer op een vorige eigenaar te verhalen valt."}, {"v": "Hoe gaat de VvE om met herstelwerkzaamheden aan balkons waarvoor een vergunningstraject nodig is en waarbij gedreigd wordt met dwangsommen door de handhavende instantie?", "a": "Wanneer er sprake is van handhaving, voert de VvE de communicatie met de betreffende instantie. Indien er voortgang wordt geboekt, bijvoorbeeld door het opnieuw opstarten van een vergunningstraject voor herstelwerkzaamheden via de VvE, wordt er in de regel uitstel verleend voor het toepassen van dwangsommen."}, {"v": "Is juridische hulp bij aansprakelijkheidstellingen inbegrepen in de standaard beheersovereenkomst?", "a": "Het begeleiden van een aansprakelijkheidsstelling of juridische zaak tegen een externe partij valt niet onder de standaard beheersovereenkomst. De vergadering van eigenaars dient hiervoor een specifiek budget vast te stellen en te bepalen wie dit proces zal begeleiden."}, {"v": "Is het mogelijk om als VvE een leningstraject aan te gaan voor het financieren van projecten?", "a": "Een leningstraject voor de VvE kan eventueel een optie zijn, mits alle betrokkenen hierin mee gaan. Wij kunnen hiervoor een offerte opstellen voor de begeleiding, aangezien dit een tijdrovend traject betreft."}, {"v": "Is het toegestaan om vloerverwarming te plaatsen in een appartement binnen de VvE?", "a": "Indien dit niet specifiek in het Huishoudelijk Reglement (HHR) is opgenomen, dient u de juiste procedures en toestemmingsverzoeken te volgen. Wanneer een verzoek netjes en goed onderbouwd wordt aangeleverd bij het bestuur, is de inschatting dat hier doorgaans geen bezwaar tegen zal zijn."}, {"v": "Wanneer kan er een opdracht worden verstrekt aan een herstelbedrijf na een gedekte schade?", "a": "Zodra de schade-expert een raming heeft opgesteld en de verzekeraar een definitieve bevestiging voor de uitbetaling heeft afgegeven, kan de opdracht aan het herstelbedrijf worden verstrekt."}, {"v": "Kan de VvE ondersteunen bij een inspectie of aanschrijving die niet direct aan de VvE is gericht, maar aan een individuele eigenaar?", "a": "Wanneer een inspectie of aanschrijving van een overheidsinstantie (zoals de pandbrigade) geen aanschrijving aan de VvE zelf betreft, kan de VvE beheerder hier niets in betekenen. De eigenaar dient in dat geval zelf afspraken te maken met de betreffende instantie om eventuele last te voorkomen."}, {"v": "Kan ik als aankoopmakelaar of externe partij financiële informatie over een VvE opvragen voor de financiering van een koper?", "a": "Gegevens van de VvE kunnen niet direct aan derden worden verstrekt. Wij verzoeken u deze informatie op te vragen via de verkopende partij (de huidige eigenaar)."}, {"v": "Is een akkoord via WhatsApp voldoende voor het verstrekken van een opdracht voor een (nood)reparatie?", "a": "Hoewel een noodoplossing via een WhatsApp-bericht akkoord kan worden bevonden, dient dit alsnog schriftelijk via een reactie op de e-mail officieel akkoord bevonden te worden. Wij kunnen anders de opdracht niet verstrekken. Een printscreen van een WhatsApp-bericht is niet voldoende voor de dossiervorming."}, {"v": "Wat moet ik doorgeven als er een nieuwe levering voor een aansluiting moet worden aangevraagd na een eindstand?", "a": "Om een nieuwe levering aan te vragen hebben wij de meterstand nodig, samen met de aansluitgegevens die terug te vinden zijn op de jaarrekening of een factuur."}, {"v": "Welke gegevens heeft de VvE-beheerder nodig bij het overnemen van de nutscontracten (gas, elektra, water)?", "a": "Voor het overnemen en verwerken van gezamenlijke nutscontracten door de VvE zijn per meter de volgende gegevens nodig: de jaarnota, de meest recente factuur en de actuele meterstanden. Daarnaast dient aangegeven te worden welke huisnummers de meters delen en of de huidige contracten een variabele of vaste looptijd hebben."}, {"v": "Wat gebeurt er als het saldo van de reserve van de VvE niet toereikend is voor noodzakelijk onderhoud?", "a": "Wanneer het saldo van de reserve niet toereikend is voor het uitvoeren van noodzakelijk onderhoud (wanneer hiertoe wordt besloten door de vergadering), dan zal er door de eigenaren aanvullend ingelegd dienen te worden conform breukdeel."}, {"v": "Wat is de procedure als een voordeur of kozijn vervangen moet worden en de maten onbekend zijn?", "a": "Het beste is om een vakman een offerte op te laten stellen die aan de vergadering kan worden voorgelegd. Hierbij is het raadzaam om ook foto's van de huidige situatie mee te sturen."}, {"v": "Nemen jullie schademeldingen aan die rechtstreeks door huurders worden gedaan?", "a": "Meldingen van huurders nemen wij niet aan. Bij een individueel appartement dient de huurder eerst contact op te nemen met de eigenaar van het appartement."}, {"v": "Vanaf welk moment kan Totaal VvE Beheer informatie verstrekken of actie ondernemen voor een potentiële koper?", "a": "Pas op het moment dat u daadwerkelijk belanghebbende (eigenaar) bent, kunnen wij informatie verstrekken of zaken voor u nagaan."}, {"v": "Kan de VvE-beheerder bemiddelen bij het verkrijgen van handtekeningen of toestemming van andere eigenaren voor een verbouwing (zoals een dakopbouw) voordat ik de woning heb aangekocht?", "a": "Pas op het moment dat u belanghebbende (eigenaar) bent, kunnen wij dingen voor u betekenen of zaken nagaan."}, {"v": "Moet er voor het schilderen van boeiboorden altijd een steiger worden geplaatst?", "a": "Voor het schilderen van het boeiboord zal doorgaans een steiger nodig zijn. Het is raadzaam om te beoordelen of dit gecombineerd kan worden met ander onderhoud, hoewel het soms verstandiger is om schilderwerk naar voren te halen om houtrot en daarmee toekomstige hogere kosten te voorkomen."}, {"v": "Wat kan ik doen als er geen actuele meterstanden bekend zijn of als de slimme meter niet goed lijkt te werken?", "a": "Het is mogelijk dat er een slimme meter aanwezig is, maar dat er problemen zijn met de meter. U kunt in dat geval contact opnemen met het nationale storingsnummer op telefoonnummer 0800-9009. U komt dan uit bij de netbeheerder en zij kunnen eventueel een schouw uitvoeren."}, {"v": "Worden overdrachten uitgevoerd door de beheerders zelf?", "a": "Overdrachten worden niet door de beheerders zelf uitgevoerd."}, {"v": "Hoeveel offertes zijn er nodig voor een schadeclaim bij de verzekeraar?", "a": "Voor de verzekeraar is één herstelofferte voldoende."}, {"v": "Waar moet op gelet worden bij het combineren van verschillende werkzaamheden waarbij steigers nodig zijn?", "a": "Bij het combineren van werkzaamheden, zoals kozijnvervanging en gevelwerk, is het verstandig om te kijken of partijen van elkaars steigers gebruik kunnen maken. Het is belangrijk om vooraf duidelijk op papier te zetten welke partij de steiger plaatst en of andere partijen hierop kunnen 'meeliften', aangezien dit aanzienlijk in de kosten kan schelen."}, {"v": "Hoe moeten facturen van aannemers worden geadresseerd aan de VvE?", "a": "Facturen dienen correct te worden geadresseerd aan de naam van de VvE zelf, en niet aan de beheerder."}, {"v": "Zit de begeleiding van verhaals- en aansprakelijkheidsstellingen in de standaard dienstverleningsovereenkomst?", "a": "Nee, verhaals- en aansprakelijkheidsstellingen (inclusief de begeleiding hiervan) zitten niet in onze standaard dienstverleningsovereenkomst."}, {"v": "Hoe kunnen besluiten over offertes worden genomen als niet alle eigenaren reageren?", "a": "Indien nodig kan er een extra vergadering worden georganiseerd. Besluitvorming kan dan plaatsvinden met een meerderheid van stemmen, eventueel via volmachten. Daarnaast wordt van eigenaren verwacht dat zij zelf ook contact opnemen met mede-eigenaren die niet reageren op correspondentie om de voortgang te bevorderen."}, {"v": "Kan een derde partij of buurman die geen lid is van de VvE een verzoek indienen om een vergadering uit te schrijven?", "a": "Verzoeken om vergaderingen uit te schrijven kunnen enkel door de leden (eigenaren) zelf worden ingediend. Verzoeken van derden kunnen niet in behandeling worden genomen aangezien de beheerder uitsluitend voor de leden van de betreffende VvE werkt."}, {"v": "Waar kan ik een officiële klacht indienen over het functioneren van de VvE-beheerder?", "a": "Klachten kunnen worden gemaild naar het daarvoor bestemde e-mailadres van de organisatie."}, {"v": "Kan een voorstel voor een kleine verbetering aan het gebouw (zoals een fietsgoot) binnen het mandaat van de beheerder worden opgepakt als er een meerderheid van stemmen is binnen de VvE?", "a": "Wanneer er voor een dergelijke klus formeel geen mandaat is, is het verzoek om het voorstel op papier te zetten. Dit voorstel wordt vervolgens aan de vergadering voorgelegd met het verzoek om binnen een week eventuele bezwaren aan te geven. Indien er geen bezwaren binnenkomen, kan er vanuit worden gegaan dat het voorstel akkoord is en kan het verder worden opgepakt."}, {"v": "Wat moet ik doen bij een hardnekkige lekkage waarvan de oorzaak onduidelijk is, en kan er lekdetectie worden ingezet?", "a": "U kunt een afspraak maken met een lekdetectiebedrijf om de bron van de lekkage te achterhalen. Wanneer uit het onderzoek blijkt dat de oorzaak van de lekkage een gemeenschappelijke gedeelte van de VvE betreft, zal de beheerder de kosten binnen het mandaat afwikkelen."}, {"v": "Wat moet ik doen als er water op het dak blijft staan en de afvoer niet goed werkt?", "a": "Wanneer er water op het dak blijft staan door een mogelijk defecte afvoer, schakelen wij een rioolservice in om dit te verhelpen. Voor de toegang tot het dak is het vaak het makkelijkst als dit via een balkon kan plaatsvinden."}, {"v": "Met welke richtlijnen moet ik rekening houden bij aanpassingen aan het aangezicht van het pand?", "a": "Bij voorstellen die het aangezicht van de VvE betreffen, dient er rekening gehouden te worden met de huidige kleurstellingen en de uniforme uitstraling van het gebouw."}, {"v": "Vallen afvoer- en sanitairleidingen onder de gemeenschappelijke delen of de individuele zaken van een eigenaar?", "a": "Afvoer- en sanitairleidingen behoren tot de individuele zaken van een eigenaar, tenzij deze specifiek in de akte als gemeenschappelijk zijn aangemerkt."}, {"v": "Faciliteert de beheerder het organiseren van toestemming voor individuele eigenaren die wijzigingen willen realiseren?", "a": "Het organiseren van toestemming voor zaken die een eigenaar wil gaan realiseren is niet iets wat wij faciliteren. Dat is aan de eigenaar die eea wil gaan realiseren."}, {"v": "Welk bedrijf kan ik benaderen voor het bestrijden van ongedierte, zoals een wespenplaag?", "a": "U kunt hiervoor bijvoorbeeld Raco benaderen: https://racoplaagdierbestrijding.nl/contact/ of Kloek ongediertebestrijding."}, {"v": "Hoe worden eventuele achterstanden verrekend bij de verkoop van mijn woning?", "a": "Achterstanden worden vanzelf via de afrekening met de notaris verrekend, hiervoor is geen verdere actie nodig."}, {"v": "Wat kan ik doen als een bewoner niet meewerkt aan het verhelpen van een lekkage of schade?", "a": "In situaties waarbij een bewoner niet meewerkt aan het verhelpen van een gebrek, kan deze aansprakelijk worden gesteld en formeel worden gesommeerd om medewerking te verlenen. Daarnaast kunnen huurders melding maken bij de pandbrigade van de gemeente als de veiligheid of leefbaarheid in het geding is."}, {"v": "Wat moet ik doen als ik niet akkoord ga met de door de beheerder aangedragen offertes?", "a": "Indien u van mening bent dat de door ons aangedragen offertes niet akkoord zijn, kunt u zelf een derde offerte (en eventuele verdere offertes) verzorgen. Wij zullen deze vervolgens ter besluitvorming voorleggen na ontvangst."}, {"v": "Waarom zijn er nog gaatjes zichtbaar na een behandeling tegen houtworm?", "a": "Keurders vermelden altijd dat er gaten zijn; hieraan kan de klant zien wanneer het behandeld is. In het geval van een recente bestrijding is het middel nog werkzaam, ook al zijn de oude gaatjes nog zichtbaar."}, {"v": "Kan de VvE een verklaring opstellen waaruit blijkt dat bewoners geen toegang hebben tot parkeren op eigen terrein ten behoeve van een parkeervergunningsaanvraag?", "a": "Vraag bij uw beheerder een verklaring op die bevestigd dat u geen toegang heeft tot een parkeerplaats op het eigen terrein."}, {"v": "Wat zijn de mogelijkheden en aandachtspunten voor het plaatsen van een muuranker voor een bakfiets?", "a": "Voor het plaatsen van een muuranker zijn er een aantal aandachtspunten. In eerste instantie dient er toestemming te worden gegeven door de eigenaar van de betreffende muur of afscheiding. Verder dient er bij de gemeente te worden nagegaan in hoeverre het trottoir van de gemeente hiervoor gebruikt mag worden."}, {"v": "Op welke manieren kan herstel van schade na een lekkage worden afgehandeld via de verzekering?", "a": "Bij schadeherstel na een lekkage zijn er doorgaans twee opties via de verzekeraar: u kunt zelf een herstelofferte aanleveren ter beoordeling, of u kunt kiezen voor herstel in natura, waarbij de verzekeraar het herstel direct laat uitvoeren."}, {"v": "Wie kan ik bellen voor informatie over het inplannen van een afspraak met de loodgieter bij een urgente verstopping?", "a": "U kunt zelf contact opnemen met het opgegeven telefoonnummer van de Rioolservice om te informeren naar de planning."}, {"v": "Wat gebeurt er als een eigenaar of huurder niet aanwezig is bij een geplande afspraak met een onderhoudspartij?", "a": "Indien er sprake is van een 'no-show' en het ingeschakelde bedrijf hiervoor een factuur stuurt, zal de VvE-beheerder deze kosten doorbelasten aan de betreffende eigenaar."}, {"v": "Met welk doel worden de maandelijkse VvE-bijdragen verhoogd naar een niveau dat aanzienlijk hoger is dan voorheen?", "a": "De verhoging van de maandelijkse bijdrage is noodzakelijk om volledig aan de geldende wetgeving te voldoen."}, {"v": "Is het verstandig om afwezig te zijn bij een vergadering (of geen volmacht te geven) als ik besluiten wil kunnen aanvechten?", "a": "Niet (via volmacht) aanwezig zijn op een vergadering waarvan u besluiten wilt aanvechten wordt meestal afgeraden. Rechters wegen de aanwezigheid van eigenaren vaak mee in hun besluiten over het aanvechten van vergaderbesluiten."}, {"v": "Hoe moet er gehandeld worden bij een gebrek aan een gemeenschappelijk deel van het complex?", "a": "U kunt het gebrek melden bij de beheerder. Indien er herstelwerkzaamheden nodig zijn, kan de beheerder een gespecialiseerd bedrijf inschakelen om een afspraak te maken voor inspectie of herstel. Het is ook toegestaan dat de bewoner/huurder dit zelf organiseert, mits de offerte vooraf ter goedkeuring aan de beheerder wordt overlegd."}, {"v": "Welke bedrijven kunnen worden ingeschakeld voor rioolservice of het verhelpen van verstoppingen?", "a": "U kunt hiervoor bijvoorbeeld contact opnemen met ABC Rioolservice Haaglanden, Rioolservice de Lange, Zegwaard of RRS."}, {"v": "Wat gebeurt er met de dekking als de garantie tegen onderverzekering afloopt voordat een nieuw voorstel is ontvangen?", "a": "Wanneer er een nieuw voorstel voor de verlenging van de garantie tegen onderverzekering in aanvraag is, blijft de garantie in de tussenliggende periode van kracht, ook als het voorstel na de feitelijke afloopdatum wordt ontvangen."}, {"v": "Blijft de Garantie tegen Onderverzekering (GTO) van toepassing als de herberekening nog niet heeft plaatsgevonden?", "a": "Zolang de Garantie tegen Onderverzekering (GTO) doorloopt tot het moment van herberekening, is dit akkoord. De GTO blijft in voorkomende gevallen van toepassing tot het moment dat de herberekening is afgerond."}, {"v": "Kan een externe partij, zoals een taxateur, rechtstreeks documenten of informatie opvragen bij de VvE beheerder?", "a": "Wij werken alleen voor eigenaren. Een externe partij kan de eigenaar verzoeken om de benodigde documenten bij ons op te vragen of de eigenaar kan ons toestemming geven om de verzoeken van een externe partij in behandeling te nemen."}, {"v": "Wat zijn de reguliere openingstijden van het kantoor?", "a": "Het kantoor is geopend van maandag tot en met vrijdag van 9.00 tot 17.00 uur."}, {"v": "Wie is verantwoordelijk voor het repareren van de oorzaak van een schade binnen de VvE?", "a": "Het is de verantwoordelijkheid van de VvE of de individuele eigenaar om de oorzaak van een schade te repareren."}, {"v": "Welke mogelijkheden zijn er voor het herstellen van gevolgschade nadat een schadeclaim is goedgekeurd door de verzekeraar?", "a": "Er zijn twee mogelijkheden voor het herstellen van gevolgschade als de schade verzekerd is: u kunt de schade laten repareren door een door u gekozen bedrijf (waarbij de verzekeraar vooraf graag een gespecificeerde offerte ontvangt) of de verzekeraar schakelt een met hen samenwerkend bedrijf in voor direct herstel."}, {"v": "Kan Totaal VvE Beheer tijdens mijn vakantie correspondentie doorsturen naar een tijdelijke contactpersoon?", "a": "Nee, de beheerder verzorgt geen automatische doorsturing van e-mail naar derden tijdens uw vakantie. U dient zelf uw mailbox bij te houden of in te stellen dat e-mail automatisch wordt doorgestuurd naar de gewenste persoon."}, {"v": "Wat wordt er verwacht van de bewoners wanneer er onderhoud aan de lift plaatsvindt?", "a": "Er moet voor gezorgd worden dat de monteur opgevangen wordt en dat hij/zij toegang heeft tot de lift en bijbehorende ruimtes (bijvoorbeeld door het beschikbaar stellen van sleutels indien van toepassing)."}, {"v": "Wat gebeurt er als er bij een stemming over onderhoud aan een gezamenlijk bouwdeel (zoals een portiekkozijn) geen unaniem akkoord wordt bereikt door de eigenaren?", "a": "Wanneer er geen unaniem akkoord volgt, is het aan de eigenaren wat ze ermee willen doen, zoals bijvoorbeeld het aanvragen van een aanschrijving bij de gemeente."}, {"v": "Hoe kunnen plannen voor verbeteringen aan het pand, zoals het afsluiten van een portiek, in gang worden gezet?", "a": "Dergelijke zaken moeten worden besproken tijdens de ledenvergadering. Dit zijn de momenten om voorstellen te bespreken en besluiten te nemen. Wanneer eigenaren met concrete voorstellen komen, kunnen deze aan de vergadering worden voorgelegd voor besluitvorming. Zonder aanwezigheid en input van eigenaren tijdens de vergadering kunnen dergelijke zaken niet in gang worden gezet en wordt de vastgestelde begroting gevolgd."}, {"v": "Heeft Totaal VvE Beheer contactgegevens van partijen voor het onderhoud van verwarmingsketels?", "a": "Voor het servicen van verwarmingsketels kunt u contact opnemen met partijen zoals Sima of Feenstra."}, {"v": "Wat wordt er verwacht van bewoners tijdens de opname voor een Meerjarenonderhoudsplan (MJOP)?", "a": "Tijdens de opname voor het Meerjarenonderhoudsplan (MJOP) is het de bedoeling dat bewoners thuis beschikbaar zijn, zodat de bouwkundige de situatie ter plaatse goed kan beoordelen."}, {"v": "Onder welke algemene voorwaarden kan een VvE akkoord gaan met de installatie van een traplift in een gemeenschappelijk trappenhuis?", "a": "De installatie van een traplift kan worden goedgekeurd onder de voorwaarde dat de lift de toegang tot individuele appartementsdeuren niet blokkeert, bijvoorbeeld door de lift pas vanaf de eerste traptrede te laten starten. Daarnaast kan de eis worden gesteld dat er een smal model wordt geplaatst en dat er afspraken worden gemaakt met de leverancier over het tijdelijk verwijderen en veilig opslaan van de zitting bij langdurige afwezigheid."}, {"v": "Wat moet de VvE doen als we een nieuwe deur of aanpassing aan de veranda willen laten uitvoeren?", "a": "Indien u een aanpassing wilt laten uitvoeren, zoals het plaatsen van een deur voor de veranda, dient u zelf één of meerdere offertes op te vragen bij relevante bedrijven en deze ter beoordeling naar de VvE beheerder te sturen."}, {"v": "Is het verplicht voor eigenaren om aanwezig te zijn bij VvE-vergaderingen?", "a": "Het is aan de eigenaren zelf om de verantwoordelijkheid te nemen om aanwezig te zijn bij vergaderingen of niet. In principe vindt dit eenmaal per jaar plaats. Tijdens vergaderingen wordt de tijd genomen om zowel de rechten als de plichten van de eigenaren te verduidelijken."}, {"v": "Binnen welke tijden worden de algemene ledenvergaderingen standaard gehouden en zijn hier extra kosten aan verbonden?", "a": "De tijden van de vergaderingen zijn bij ons standaard tussen 9.00 en 16.00 uur (starttijd). Wanneer een vergadering buiten deze tijden start, brengen wij aanvullend € 95,00 excl. BTW in rekening."}, {"v": "Schakelt de opstalverzekering altijd een expert in bij schade aan een balkon?", "a": "Nee, de inschatting is dat de opstalverzekering niet in alle gevallen een expert zal inschakelen voor de beoordeling van dergelijke schades."}, {"v": "Hoe wordt een vochtprobleem of lekkage op een balkon onderzocht als de oorzaak niet direct duidelijk is?", "a": "Bij complexe vochtuitbreiding aan de onderzijde van een balkon kan een onafhankelijk bouwkundige worden ingeschakeld voor een inspectie en beoordeling. Indien visuele inspectie onvoldoende informatie biedt, kan er een lekdetectiebedrijf worden ingezet dat met behulp van kleurstoffen de exacte bron van de lekkage probeert te achterhalen."}, {"v": "Wat is de procedure wanneer er geld uit de gemeenschappelijke reserve wordt gebruikt voor onderhoud waar niet elke eigenaar aan hoeft mee te betalen?", "a": "Wanneer er door een specifieke groep eigenaren een bedrag uit de gemeenschappelijke reserve wordt onttrokken voor onderhoud waarvoor een andere eigenaar (bijvoorbeeld van de parterre) niet hoeft mee te betalen, is het gebruikelijk om deze eigenaar naar aandeel te compenseren."}, {"v": "Waarom stapt de VvE over naar een andere bank (zoals ABN AMRO)?", "a": "De overstap naar een andere bank kan een kleine kostenbesparing opleveren voor de VvE. Daarnaast is het beheersysteem volledig ingericht op deze bank, wat zorgt voor een efficiëntere verwerking van de administratie."}, {"v": "Wat moet ik doen bij een plafondlekkage die vermoedelijk bij de bovenburen vandaan komt?", "a": "De eerste stap is om bij de bovenburen te kijken of daar een duidelijke oorzaak te vinden is. Als de oorzaak bij hen ligt (zoals individueel leidingwerk of achterstallig onderhoud van de keuken of badkamer), dan is het de verantwoordelijkheid van de eigenaar van de bovenwoning om deze oorzaak weg te nemen."}, {"v": "Wat moet ik doen als ik schade aan de gevel of het metselwerk van het pand constateer?", "a": "Wanneer u schade constateert, verzoeken wij u om foto's hiervan naar ons op te sturen. Aan de hand van deze foto's kunnen wij de situatie beoordelen en waar nodig de juiste acties in gang zetten, zoals een inspectie of het coördineren van herstelwerkzaamheden."}, {"v": "Wat is de rol van de VvE beheerder bij het besluiten over zaken zoals het plaatsen van een portiekhek?", "a": "De beheerder legt de betreffende zaken voor aan de vergadering ten behoeve van de besluitvorming."}, {"v": "Zijn de kosten voor een lekdetectiebedrijf gedekt door de verzekering?", "a": "In sommige gevallen is een lekdetectie gedekt door de verzekeraar, controleer dit voor de zekerheid op de polis of vraag het na bij de beheerder van de vereniging."}, {"v": "Is er toestemming nodig van de VvE of de gemeente voor het vervangen van ramen of kozijnen?", "a": "Voor het vervangen van ramen en kozijnen is toestemming nodig van de VvE, aangezien deze over het algemeen gemeenschappelijk eigendom zijn en de VvE hier vaak gezamenlijk over beslist. Wat betreft de voorzijde van de woning is het ook belangrijk om bij de gemeente na te gaan of er een vergunning nodig is. Zodra u een concreet verzoek heeft, kunt u dit bij de VvE indienen."}, {"v": "Is de VvE-beheerder verantwoordelijk voor de medewerking of het gedrag van huurders van eigenaren?", "a": "De VvE-beheerder is niet verantwoordelijk voor de gedragingen van huurders van individuele eigenaren en kan huurders niet dwingen om medewerking te verlenen."}, {"v": "Kan ik individuele woningverbetering, zoals het plaatsen van dubbelglas+, vergoed krijgen via de VvE?", "a": "Hoewel dergelijke verzoeken aan de VvE kunnen worden voorgelegd, is het onwaarschijnlijk dat er akkoord wordt gegeven op een vergoeding voor individuele woningverbetering. Een dergelijke maatregel is vaker reëel wanneer dit collectief wordt uitgevoerd. In dat geval is het raadzaam om eerst bij de buren te informeren of er animo is voor een gezamenlijke aanpak."}, {"v": "Waarom kan ik PDF-bestanden of documenten in het portaal niet goed lezen of opslaan?", "a": "Wanneer PDF-bestanden niet goed openen of leesbaar zijn, ligt dit meestal aan de instellingen van de gebruikte internetbrowser (zoals het ontbreken van extensies voor PDF-bestanden). Wij adviseren om in dat geval een andere browser te proberen om de documenten juist te kunnen inzien of op te slaan."}, {"v": "Is het mogelijk om bestanden die in een ander formaat (zoals php) worden aangeboden om te zetten naar een PDF-bestand?", "a": "Totaal VvE Beheer heeft geen mogelijkheden om aanpassingen in het bestandsformaat van de verstrekte stukken te doen."}, {"v": "Is het de taak van de VvE-beheerder om achtergelaten fietsen of eigendommen van derden uit de voortuin te verwijderen?", "a": "Het verwijderen van eigendommen van derden behoort niet tot de taken van de beheerder/administrateur. De beheerder is niet bevoegd om eigendommen van anderen te verwijderen. Verzoeken hiertoe dienen rechtstreeks tussen eigenaren onderling te worden geregeld en/of bij de betreffende instanties te worden gemeld."}, {"v": "Stelt de opstalverzekering eisen aan de jaarlijkse keuring van brandmelders in appartementen?", "a": "Vanuit de opstalverzekering zijn er meestal geen eisen voor de keuring van brand/rookmelders in het geval van particuliere bewoning, voor bedrijfsruimte gelden er veelal wel preventiemaatregelen. \r\n \r\nDit neemt natuurlijk niet weg dat bijvoorbeeld de gemeente (of andere instantie) aan u als verhuurder aanvullende eisen kan stellen, waardoor dit wel nodig zou kunnen zijn (particuliere bewoning)."}, {"v": "Is Totaal VvE Beheer verantwoordelijk voor de werkzaamheden die door een externe aannemer worden verricht?", "a": "Totaal VvE Beheer is niet (eerstelijns) verantwoordelijk voor werkzaamheden die door een externe partij worden verricht. De vereniging neemt zelf het besluit om werkzaamheden aan een externe aannemer te gunnen of uit te besteden. \r\n\r\nVoor de controle/begeleiding van de werkzaamheden kan de VvE er altijd voor kiezen voor de inzet van een (interne/externe) onafhankelijke bouwkundige."}, {"v": "Wanneer kan er iets gezegd worden over de uitvoering van werkzaamheden nadat een opname voor offerte heeft plaatsgevonden?", "a": "Zodra de offerte is ontvangen, zal deze aan de vergadering worden voorgelegd. Pas na eventuele opdrachtverstrekking kan er informatie worden gegeven over de uitvoering van de werkzaamheden."}, {"v": "Wat houdt een last onder dwangsom (LOD) in voor een VvE en waar kan ik hierover meer informatie vinden?", "a": "Een last onder dwangsom (LOD) is een herstelmaatregel van een bestuursorgaan (zoals de gemeente) die inhoudt dat er een sanctie wordt opgelegd als een bepaalde overtreding niet binnen een gestelde termijn wordt hersteld. Als eigenaar kunt u via het Totaal Portaal 24/7 inzicht krijgen in relevante documenten van uw VvE die hierop betrekking hebben."}, {"v": "Op welke manier kunnen extra bijdragen voor onderhoud of renovatie worden voldaan en is betaling in termijnen mogelijk?", "a": "Betalingen van extra bijdragen dienen bij voorkeur in één keer voldaan te worden. Mocht dit niet mogelijk zijn, dan kan er contact worden opgenomen om te bespreken of er betalingsafspraken gemaakt kunnen worden. Let op: opdrachten richting aannemers kunnen pas worden verstrekt zodra het volledige bedrag op de rekening van de VvE staat. Een latere betaling (of betaling in termijnen) betekent dat het langer duurt voordat de werkzaamheden kunnen worden uitgevoerd."}, {"v": "Wat moet ik doen bij een urgente lekkage als er geen contact mogelijk is met de buren waar de oorzaak vermoedelijk ligt?", "a": "Wanneer er sprake is van een urgente lekkage en er kan geen contact worden gelegd met de bewoners van het pand waar de lekkage vandaan komt, kunt u bij hoge urgentie de brandweer inschakelen. Voor een beoordeling door de VvE-beheerder ontvangen wij graag foto's of video's van de situatie."}, {"v": "Wat is de verplichte minimale reserve en op welke basis wordt de bijdrage voor het reservefonds vastgesteld?", "a": "Er is geen wettelijk verplichte minimale totale reserve, maar wel een verplichte jaarlijkse reservering conform de Wet verbetering functioneren VvE. De bijdragen worden zo vastgesteld dat de jaarlijkse reservering uitkomt op minimaal 0,5% van de herbouwaarde van het gebouw, of op basis van de benodigde bedragen in een actueel Meerjarenonderhoudsplan (MJOP). De Vergadering besluit conform het reglement (artikel 14.2) op welke van deze beide wijzen de eigenaren bijdragen. Voor de 0,5% norm wordt in eerste instantie uitgegaan van een door de verzekeraar opgegeven geschatte herbouwwaarde. Vervolgens worden er taxaties uitgevoerd om de definitieve herbouwwaardes vast te stellen, welke na goedkeuring door de ALV in de begroting worden verwerkt. Deze minimale reservering is met name van belang voor kopers bij het verkrijgen van hun financiering."}, {"v": "Kunnen parkeerkosten door aannemers als meerkosten in rekening worden gebracht bij de VvE?", "a": "Parkeerkosten (indien geen gebruik kan worden gemaakt van bezoekerspassen) zijn niet ongebruikelijk en redelijk om te voldoen. Dit zal in de meeste gevallen ook in de betreffende voorwaarden/offertes worden/zijn vermeld."}, {"v": "Wat is de procedure als er een vermoeden van een lekkage aan een afvoer is, maar er geen actieve lekkage wordt waargenomen?", "a": "Wanneer er geen actieve lekkage wordt waargenomen, zou er gestart kunnen worden om in kaart te brengen van wie de betreffende afvoer is. Een eerste stap hierbij is om samen met de betreffende eigenaren en/of bewoners vast te stellen wat er gebeurt bij het gebruik van de betreffende afvoeren. \r\nWanneer er duidelijk is welke afvoer er dan problemen geeft, dan dient de betreffende eigenaar dit voor eigen rekening te herstellen."}, {"v": "Is een volmacht voor de eerste Algemene Ledenvergadering (ALV) ook geldig voor de tweede vergadering?", "a": "Nee, een volmacht voor de eerste vergadering gaat niet automatisch mee naar de tweede reglementaire vergadering (tenzij hier wel nadrukkelijk opmerking over is/wordt gemaakt in de betreffende volmacht)."}, {"v": "Wat gebeurt er als een factuur het mandaat van de beheerder overschrijdt?", "a": "Wanneer een factuur boven het mandaat ligt, moet deze aan de vergadering worden voorgelegd voor akkoord. Bij het ontbreken van een unaniem akkoord wordt de factuur ter bespreking op de agenda van de eerstvolgende Algemene Ledenvergadering (ALV) geplaatst."}, {"v": "Welke schade wordt er doorgaans door de verzekering van de VvE vergoed bij een schademelding?", "a": "Bij een schademelding wordt in de regel alleen de gevolgschade vergoed mits er sprake is van een gedekte gebeurtenis. Het herstel van de schadeoorzaak is voor VvE (tenzij dit een individuele oorzaak betreft)."}, {"v": "Wat is de procedure als er een verzoek komt om een jaarlijkse vergoeding te betalen aan een naburige VvE voor het gebruik van gemeenschappelijke voorzieningen, zoals portiekverlichting?", "a": "Wanneer er een verzoek binnenkomt via beheerder van de buren, zal de beheerder dit verzoek formeel voorleggen aan de vergadering mbt besluitvorming/controle. Bij akkoord dit conform afspraken met de beheerder van de buren verzorgen namens de VvE."}, {"v": "Hoe werkt het herstel van schade en de afwikkeling van het schadebedrag bij een verzekeringskwestie?", "a": "Dit is afhankelijk van de soort opstalverzekering, bijvoorbeeld of de betreffende verzekering een mogelijk voor \"direct herstel' kent . \r\n\r\nIn de meeste situaties dient via de beheerder een compleet dossier te worden aangeleverd, bestaande uit foto's van de schade, bevestiging wegnemen schadeoorzaak (factuur) en herstelofferte gevolgschade. \r\n\r\nDe opdrachtverstrekking via het herstel kan pas in gang worden gezet na goedkeuring en/of bevestiging vanuit de verzekeraar."}, {"v": "Kunt u helpen bij het vinden van een goede en betaalbare loodgieter voor werkzaamheden in mijn appartement?", "a": "U zou Loodgietersbedrijf Rieske kunnen proberen via https://www.loodgietersbedrijf-rieske.nl/site/contact."}, {"v": "Op welke manier vindt de besluitvorming binnen de VvE plaats over voorgestelde plannen of aanpassingen?", "a": "Plannen kunnen ter besluitvorming worden voorgelegd middels een schriftelijke stemming (unaniem akkoord nodig) of door het organiseren van een extra Algemene Ledenvergadering (ALV) waarin betreffende zaken kunnen worden besproken/besloten."}, {"v": "Welke tenaamstelling voor de appartementseigenaren wordt er aangehouden voor de administratie van de VvE?", "a": "De tenaamstelling moeten wij conform het kadaster aanhouden."}, {"v": "Wat moet ik doen als de opstalverzekering een schadeclaim afwijst en ik deze wil indienen bij mijn eigen aansprakelijkheidsverzekering (individuele schadeoorzaak)?", "a": "Wanneer de verzekeraar een afwijzing geeft op een schadeclaim met een individuele schadeoorzaak, dan wordt de afwijzing naar u doorgestuurd. De afwijzing kunt u dan gebruiken om een verzoek in te dienen bij de eigen aansprakelijkheidsverzekering. Wanneer deze ook niet tot uitkering overgaat, dient u de schade onderling met de betreffende partij/eigenaar af te wikkelen."}, {"v": "Worden reparatiekosten die niet door de opstalverzekering worden gedekt, vergoed door de aansprakelijkheidsverzekering voor particulieren (AVP)?", "a": "Nee, herstelkosten van een schadeoorzaak zijn in de basis geen verzekeringswerk (maar onderhoud).\r\nIn sommige gevallen kan het opsporen van een schadeoorzaak (hak- en breekwerk of de kosten van lekdetectie) wel worden ingediend."}, {"v": "Wat is er nodig voor de goedkeuring en afwikkeling van reeds uitgevoerde werkzaamheden door een individuele eigenaar?", "a": "Voor de afrekening van een factuur (gemeenschappelijk zaak) dient er of een vergaderbesluit (met meerderheid stemmen) of een unaniem akkoord buiten de vergadering te zijn middels een schriftelijke stemming."}, {"v": "Is de VvE verantwoordelijk voor het onderhoud of vervangen van rookgasafvoeren?", "a": "De verantwoordelijkheid voor de rookgasafvoer hangt af van het splitsingsreglement. In sommige gevallen worden ze als individueel beschouwd, terwijl ze in andere gevallen (doorgaans bij collectieve systemen of specifieke bepalingen) onder de verantwoordelijkheid van de VvE vallen."}, {"v": "Welke subsidies zijn er beschikbaar voor het vervangen van kozijnen en glas binnen een VvE?", "a": "Dit is afhankelijk van de gemeente en de omvang van de geplande werkzaamheden, soms zijn er verschillende subsidieregelingen beschikbaar. Te denken aan rijkssubsidies (RVO) voor minimaal HR++ glas. Daarnaast kennen sommige gemeenten aanvullende subsidies voor appartementen met een lager energielabel (label D of lager)."}, {"v": "Wat is de procedure bij een nieuwe schademelding nadat een vorig dossier is gesloten zonder de bevestiging dat de eerdere schade reeds volledig is hersteld?", "a": "In het geval van een nieuwe schade zal eerst aangetoond moeten worden dat de eerdere schade volledig is hersteld. Zonder dit bewijs kan een nieuwe schademelding niet in behandeling worden genomen."}, {"v": "Kan ik schade al laten herstellen voordat de een expert van de verzekeraar is langsgekomen?", "a": "Zaken al laten herstellen voordat een expert de schade heeft kunnen beoordelen is volledig voor eigen rekening en risico en meestal niet verstandig. \r\n\r\nWanneer er toch gekozen wordt dit te doen, is het zeer dringende advies alles zo compleet mogelijk vast te leggen middels (minimaal) een fotoreportage. Wanneer een door de verzekeraar aangewezen expert de situatie niet meer goed kan beoordelen en dit problemen met de vaststelling oplevert, kan dit namelijk gevolgen hebben voor de uitkering."}, {"v": "Wat zijn de vervolgstappen als geluidsoverlast niet onderling tussen bewoners kan worden opgelost?", "a": "Mochten eigenaren er onderling niet uitkomen, dan is het aan de betreffende eigenaar/eigenaren die geluidsoverlast ervaren om zelf de vervolgstappen te zetten (inschakelen instanties en/of juridische stappen)."}, {"v": "Wat moet ik doen als een lekkage aan het dak opnieuw optreedt na eerdere reparaties?", "a": "Wanneer een lekkage opnieuw optreedt op een locatie waar onlangs werkzaamheden zijn uitgevoerd, zal Totaal VvE Beheer contact opnemen met de betreffende daktechnieker om te onderzoeken of de reparatie onder de garantie valt. Indien het geen garantiekwestie betreft, wordt er gewerkt met een vooraf vastgesteld mandaat voor reparatiekosten; bij overschrijding hiervan zal eerst een offerte worden opgesteld en de vergadering worden voorgelegd."}, {"v": "Wat moet ik doen als ik vragen heb over de uitvoering van de werkzaamheden door de herstelpartij (herstelofferte)?", "a": "In geval van bijzonderheden of vragen over de uitvoering/offerte kunt u deze direct met de uitvoerder afstemmen. Mocht u hier niet uitkomen, kunt u zich bij de bestuurder melden."}, {"v": "Worden bij herstelwerkzaamheden via de verzekering volledige plafonds of muren geschilderd?", "a": "Vanuit de verzekering worden uitsluitend beschadigde stukken vergoed. De herstelpartijen worden op deze wijze aangestuurd, wat betekent dat niet altijd complete plafonds worden aangepakt, maar enkel de direct getroffen delen."}, {"v": "Is er sprake van verzekeringsdekking bij schade door achterstallig onderhoud?", "a": "In geval van duidelijk achterstallig onderhoud is er in principe geen dekking. De meeste polissen vereisen dat er sprake is van een onvoorziene gebeurtenis."}, {"v": "Hoe gaat de VvE om met uitspraken over verzekeringsdekking?", "a": "Wij doen nooit uitspraken over dekking; de beoordeling hiervan is altijd aan de verzekeraar."}, {"v": "Ik wil mijn voordeur veranderen, welke kleur mag ik aanhouden?", "a": "Aanpassingen van kleurstelling dienen altijd aan de vergadering te worden voorgelegd? Dit nog los van eventuele benodigde vergunningsaanvragen bij de gemeente."}, {"v": "Hoe kunnen opmerkingen over uitgevoerde werkzaamheden het beste worden aangeleverd bij de beheerder?", "a": "Het is raadzaam om opmerkingen over de werkzaamheden na afronding te bundelen en deze gespecificeerd en puntsgewijs aan te leveren, bij voorkeur vergezeld van foto's per punt. Dit zorgt voor een duidelijke communicatie richting de aannemer."}, {"v": "Hoe wordt de noodzaak van bepaalde werkzaamheden binnen de VvE bepaald?", "a": "De noodzaak van werkzaamheden is aan de vergadering om te bepalen. Dit kan door leden zelf, maar wellicht ook door het laten opstellen van een MJOP door een onafhankelijk bouwkundige die hier direct advies over uit kan brengen."}, {"v": "Worden onderhoudsoffertes vergoed door de verzekering?", "a": "Onderhoudsoffertes (achterstallig) van een VvE worden niet gedekt door de opstalverzekering. Dit is onderhoud dat door de VvE dient uitgevoerd en bekostigd te worden. De opstalverzekering dekt schade veroorzaakt door gebeurtenissen als brand, storm, waterlekkage, inbraak en vandalisme. Ook bijkomende kosten zoals opruimkosten en expertisekosten kunnen gedekt zijn, afhankelijk van de polis."}, {"v": "Wat zijn de mogelijkheden wanneer een aannemer weigert een gedetailleerde specificatie van een offerte aan te leveren?", "a": "Wanneer een partij niet bereid is om een verdere specificatie van de offerte aan te leveren, is het aan de VvE om te bepalen of zij wel of geen gebruik willen maken van de diensten van deze partij. Een alternatieve optie is om zelf andere partijen of offertes aan te dragen voor de gewenste werkzaamheden."}, {"v": "Zijn de kosten voor vervanging van een laminaatvloer gedekt door de VvE-verzekering?", "a": "De kosten voor vervanging van een laminaatvloer zijn doorgaans voor rekening van de inboedelverzekeraar van de bewoner en vallen niet onder de collectieve gebouwenverzekering van de VvE."}, {"v": "Wat kan de VvE-beheerder betekenen bij overlast van etensluchten vanuit een nabijgelegen bedrijfspand?", "a": "De VvE-beheerder kan het bericht doorzetten naar de betreffende eigenaren met het verzoek om contact op te nemen. Voor de beheerder zijn dit echter doorgaans geen zaken waar zij verder direct actie in kunnen ondernemen."}, {"v": "Verleent de beheerder medewerking bij een eventuele overstap naar een nieuwe bestuurder of beheerder?", "a": "Indien de VvE besluit op zoek te gaan naar een nieuwe bestuurder of beheerder, zal de huidige beheerder hier alle nodige medewerking aan verlenen."}, {"v": "Wat is de rol van de VvE-beheerder bij het aanpassen van de splitsingsakte?", "a": "De rol van de beheerder bij het aanpassen van een splitsingsakte is beperkt tot de besluitvorming. Zodra de notaris hierom verzoekt, wordt de besluitvorming gefaciliteerd op basis van een conceptakte. Voor het proces van aanpassing en formalisering dient de VvE zelf af te stemmen met een notaris."}, {"v": "Waarom is het verstandig om een wijziging in de splitsingsakte in één keer volledig en correct door te voeren?", "a": "Het is raadzaam om een akte in één keer goed aan te passen, omdat notarissen aanzienlijke kosten rekenen voor elke afzonderlijke wijziging of aanpassing."}, {"v": "Bij wie kan ik terecht voor het melden van glasschade en het herstellen hiervan?", "a": "U kunt hiervoor contact opnemen met de beheerder van de VvE. Er kan dan direct een afspraak worden gemaakt met de glashersteller om het glas te herstellen of te bestellen. De beheerder helpt u ook verder met het indienen van eventuele facturen. Let er wel op dat er foto's van de schade nodig zijn voor de opstalverzekering."}, {"v": "Binnen welke termijn kan ik een reactie verwachten van Totaal VvE Beheer?", "a": "Wij streven ernaar om binnen 48 uur een reactie te geven. Indien een telefonische reactie niet mogelijk is, sturen wij een e-mail om te laten weten dat de afhandeling iets langer duurt."}, {"v": "Worden huurders meegenomen in de officiële mailwisselingen van de VvE?", "a": "Wij communiceren uitsluitend met de eigenaar van de woning. Huurders horen door de verhuurders ingelicht te worden."}, {"v": "Wie is verantwoordelijk voor het herstel van schade die is ontstaan door een verbouwing van een eigenaar?", "a": "In het geval er schade ontstaat door een verbouwing van een eigenaar, dan dient deze dit uiteraard (via de betreffende aannemer) te laten herstellen. U dient hiertoe altijd rechtstreeks bij de betreffende eigenaar een verzoek in te dienen."}, {"v": "Wat zijn de nadelen van het plaatsen van een extra gemeenschappelijke meter voor de portiekverlichting?", "a": "Dat is een veel duurdere oplossing. Alleen al de leveringskosten van een extra aansluiting kosten een specifiek bedrag per maand bovenop de verbruikskosten."}, {"v": "Welk BTW-tarief moet er gehanteerd worden voor schilder- en stucwerkzaamheden bij de VvE?", "a": "Voor schilder- en stucwerkzaamheden dient het verlaagde BTW-tarief van 9% te worden toegepast. Dit tarief geldt voor zowel de arbeids- als de materiaalkosten, inclusief voorbehandeling en afplakken."}, {"v": "Worden schademeldingen gedeeld met de rest van de VvE?", "a": "In het kader van transparantie wordt het complete dossier dat naar de verzekering gaat ook gedeeld met de gehele VvE."}, {"v": "Blijven de betalingsverplichtingen aan de VvE bestaan als de beheerovereenkomst wordt opgezegd?", "a": "Betalingen aan de VvE blijven staan, totdat de vergadering anders zou besluiten. De bankrekening is en blijft eigendom van de vereniging en de verplichting tot betaling blijft voor alle eigenaren hetzelfde."}, {"v": "Hoe werkt de betaling wanneer een reparatie via de verzekering loopt en wat wordt er van de eigenaar verwacht tijdens de uitvoering?", "a": "Wanneer de werkzaamheden zijn afgerond ontvangt de beheerder de factuur van de aannemer. Deze zal bij de verzekering worden ingediend voor afronding van de betaling. De verzekeraar maakt het geld over naar de VvE bankrekening waarna de beheerder ervoor zorgt dat de factuur betaald wordt. \r\nVan de eigenaar wordt enkel verwacht toegang te verlenen tot de woning voor de uitvoer van het herstel."}, {"v": "Wat zijn de mogelijkheden als ik zelf een partij heb voor het uitvoeren van herstelwerkzaamheden binnen de VvE?", "a": "Als deze partij het herstel onder het mandaat van de VvE kan uitvoeren is dit geen probleem. Wel dienen zij bij de Kamer van Koophandel ingeschreven te staan en een officiële met BTW belastte factuur aan te kunnen leveren."}, {"v": "Ben ik als nieuwe eigenaar verantwoordelijk voor gebreken of blokkades die door de vorige eigenaar zijn veroorzaakt?", "a": "Als rechtsopvolger neemt u eventuele problemen over die mogelijk door de verkopende partij gecreëerd zijn. Het verzoek om dergelijke problemen op te lossen blijft daarom bij de huidige eigenaar liggen."}, {"v": "Moet zonwering worden verwijderd bij betonherstelwerkzaamheden aan de balkons?", "a": "Dat is afhankelijk van de werkzaamheden die uitgevoerd moeten worden. Het verstandigste is om dit aan desbetreffende aannemer te vragen voor de werkzaamheden gaan starten."}, {"v": "Is het mogelijk om subsidie aan te vragen voor de isolatie bij het vervangen van het dak?", "a": "Voor isolatie bij het vervangen van het dak kan subsidie worden aangevraagd. Let wel op dat dit specifiek voor het isolatiemateriaal geldt; voor bepaalde andere materialen, zoals folie, is het niet altijd mogelijk om subsidie aan te vragen."}, {"v": "Is het van belang dat de gevel in goede staat is voordat deze wordt geïmpregneerd?", "a": "Wanneer je een gevel wilt impregneren is het van belang dat de gevel in goede staat is en er geen zichtbare gebreken in het metselwerk zijn."}, {"v": "Valt een barst in een binnenmuur onder de verantwoordelijkheid van de VvE?", "a": "Een scheur of barst binnen in de woning valt niet onder het gemeenschappelijke gedeelte van de VvE. U dient hiervoor zelf een partij in te schakelen, bijvoorbeeld een stukadoor."}, {"v": "Wie kan er gebruikmaken van het noodnummer van de VvE?", "a": "Ons noodnummer is alleen te bereiken voor eigenaren. Huurders dienen zich te melden bij hun verhuurder."}, {"v": "Wat is vaak de oorzaak van schimmelvorming onder kozijnen?", "a": "Schimmel onder de kozijnen wordt vaak niet veroorzaakt door bouwkundige gebreken aan de kozijnen zelf, maar door een gebrek aan ventilatie in de betreffende ruimte."}, {"v": "Is het mogelijk om spouwmuurisolatie toe te passen bij een pand dat rond 1924 is gebouwd?", "a": "Bij panden die rond 1924 zijn gebouwd, werden nog geen spouwmuren gebruikt. Hierdoor is het niet mogelijk om spouwmuurisolatie toe te passen."}, {"v": "Hoe wordt er omgegaan met offertes voor werkzaamheden die zowel VvE-gerelateerde punten als individuele punten bevatten?", "a": "In sommige gevallen kan worden besloten om zowel de VvE-gerelateerde punten als de individuele punten gezamenlijk in de offerte voor de VvE op te nemen, zodat de werkzaamheden integraal uitgevoerd kunnen worden. De kosten voor de individuele punten zullen naderhand doorbelast worden aan desbetreffende eigenaar."}, {"v": "Bij wie kan ik nagaan of mijn woning een bijbehorende berging heeft?", "a": "Om te achterhalen of er een berging bij de woning hoort, kunt u kijken in de stukken die u heeft ontvangen bij het kopen van de woning. Ook kunt u de splitsingsakte raadplegen om te zien wat daarover benoemd staat."}, {"v": "Is het verstandig om bij een slechte staat van het dak direct voor een grondige renovatie te kiezen in plaats van een tijdelijke reparatie?", "a": "Wanneer een dak in zeer slechte staat verkeert, is het raadzaam om de staat van het dak grondig aan te pakken in plaats van een tijdelijke reparatie uit te voeren. Een reparatie is vaak kostbaar en bij een slecht dak blijft het risico op nieuwe lekkages op andere plekken bestaan. Het is verstandig om eerst een dakonderzoek of uitgebreide inspectie te laten uitvoeren en meerdere offertes te vergelijken om een weloverwogen keuze te kunnen maken."}, {"v": "Hoe moet een plafond worden hersteld na waterschade om schimmel te voorkomen?", "a": "Bij herstel van waterschade dienen doorweekte gipsplaten volledig te worden verwijderd en vervangen. Vervolgens moet het plafond opnieuw worden gestuct en afgewerkt met een schimmelwerende sauslaag om de oorzaak weg te nemen en het plafond in de oude staat terug te brengen."}, {"v": "Wat moet ik aanleveren om een schadeclaim bij de verzekeraar in te dienen?", "a": "Om een schade ter beoordeling bij de verzekeraar in te dienen hebben wij een volledig ingevuld schadeformulier, foto's van de schade en een bewijs dat de oorzaak is verholpen (bijvoorbeeld een herstelfactuur) nodig. Voor de herstelkosten dient u een offerte te overleggen. Heeft u de schade zelf al hersteld? Lever dan een opsomming van de gemaakte arbeidsuren aan, samen met de factuur of bonnen van de aangeschafte materialen. U kunt deze documenten naar uw beheerder sturen, die de claim indient bij de verzekeraar."}, {"v": "Wat moet ik doen als het slot van mijn appartement niet goed functioneert of als ik buitengesloten ben door een defecte cilinder?", "a": "Bij acute problemen met de cilinder waardoor u de woning niet meer in kunt, kan tijdens kantooruren contact met ons opgenomen worden en na deze tijden met de noodtelefoon. Er zal een slotenmaker worden ingeschakeld. Indien nodig kan er uit nood een basis cilinder worden geplaatst zodat u weer toegang heeft tot de woning. De kosten hiervoor zijn vaak wel voor de individuele eigenaar en zullen doorbelast worden."}, {"v": "Waarom kan een bouwkundige de doorvoer van de rookgasafvoer soms niet controleren tijdens een inspectie voor het MJOP?", "a": "Het kan voorkomen dat een bouwkundige de doorvoer niet kan controleren omdat deze is ingebouwd. In dergelijke gevallen is sloopwerk noodzakelijk om toegang te krijgen tot de doorvoer voor inspectie."}, {"v": "Wat moet ik doen als mijn buren bezwaar hebben tegen het plaatsen van zonnepanelen op het gezamenlijke dak vanwege eerdere lekkages?", "a": "Mijn advies is om in gesprek te gaan met de betreffende eigenaren om de zorgen te bespreken. Wellicht kunnen er onderling afspraken gemaakt worden. Deze afspraken zullen dan in de eerstvolgende algemene ledenvergadering vastgelegd worden."}, {"v": "Wanneer begint de officiële taakuitvoering van de beheerder voor een nieuwe vereniging?", "a": "De beheerder kan pas taken uitvoeren en iets voor de vereniging betekenen zodra de opstartvergadering heeft plaatsgevonden en de beheerder officieel als bestuurder is aangesteld."}, {"v": "Is het mogelijk om voor grotere uitgaven, zoals gevelwerkzaamheden, een extra offerte van een derde partij op te vragen om prijsverschillen in de markt te vergelijken?", "a": "Wij vragen voor grote werkzaamheden maximaal 2 offertes aan. Dit omdat het de aannemers ook veel tijd kost en dit ten koste gaat van andere werkzaamheden. Het staat u ten alle tijde natuurlijk vrij om zelf een derde offerte aan te vragen bij een partij ter vergelijking."}, {"v": "Hoe kunnen foto's van een schade worden aangeleverd als het bestand te groot is voor een e-mail?", "a": "Wanneer er te veel foto's zijn om direct bij te voegen in een e-mail, kan er gebruik worden gemaakt van een WeTransfer-link om de foto's te versturen."}, {"v": "Wat zijn de opties voor herstel wanneer een houten balkondeur niet meer goed sluit door kromming of houtrot aan de deurposten?", "a": "Wij kunnen een onderhoudspartij vragen een afspraak met u te maken om de situatie te beoordelen en naar de staat van de deur en de kozijnen te kijken. De splitsingsakte is hierin wel leidend of de kosten gemeenschappelijk of individueel zijn."}, {"v": "Wie is verantwoordelijk voor de binnenafwerking na het vervangen van een lichtkoepel of dakraam door de VvE?", "a": "De binnenafwerking na werkzaamheden aan een lichtkoepel of dakraam is doorgaans voor rekening van de bewoner zelf."}, {"v": "Wat moet ik doen als ik een openstaande factuur of herinnering niet in één keer kan betalen?", "a": "Wanneer het niet mogelijk is om het bedrag in één keer te betalen, is het advies om contact op te nemen met onze financiële afdeling om mogelijk een betalingsafspraak te maken."}, {"v": "Wat moet ik doen als ik ontdek dat het schilderwerk van kozijnen of deuren loslaat terwijl er al een offerte voor onderhoud loopt?", "a": "Wanneer er aanvullende gebreken aan het schilderwerk worden geconstateerd, kunnen deze tijdens de geplande vergadering worden besproken. We kijken dan gezamenlijk hoe we dit kunnen meenemen in de besluitvorming en de bestaande offerte, zodat er een passende oplossing wordt gevonden."}, {"v": "Wanneer is de afrekening van de servicekosten/nutsverbruik bekend?", "a": "Het moment waarop de afrekening voor het nutsverbruik beschikbaar is, varieert per aanbieder. Zodra wij deze informatie van de betreffende energieleverancier of meetdienst ontvangen, delen we deze direct met de eigenaren."}, {"v": "Zijn alle documenten direct beschikbaar op het klantportaal na het verkrijgen van toegang?", "a": "Het kan voorkomen dat nog niet alle documenten op het klantportaal staan; deze worden gaandeweg toegevoegd."}, {"v": "Worden de kosten voor het volledig vervangen van een plafond vergoed door de verzekering bij lekkage als het plafond al in slechte staat verkeerde?", "a": "Wanneer er sprake is van een oud en zeer slecht plafond, vergoedt de verzekering doorgaans alleen het herstel (zoals het verfwerk) en niet de volledige vervanging van het plafond. Het plaatsen van een volledig nieuw plafond wordt in dat geval gezien als een verbetering ten opzichte van de situatie voor de schade, wat niet onder de dekking valt."}, {"v": "Wat zijn de gevolgen van een defecte hydrofoorpomp voor de watervoorziening in het gebouw?", "a": "Bij een defecte hydrofoorpomp zullen de bewoners op de begane grond en de eerste twee verdiepingen hier vaak weinig van merken, omdat de aanvoerdruk van het water naar het gebouw meestal hoog genoeg is. Voor de hogere verdiepingen (vanaf de 3e en met name de 4e verdieping) heeft het uitvallen van de pomp tot gevolg dat er nauwelijks water uit de kraan komt, zeker als er op meerdere plaatsen gelijktijdig water wordt getapt. Voor deze bewoners is een goed werkende pomp noodzakelijk voor voldoende waterdruk."}, {"v": "Hoe kunnen onderwerpen zoals de installatie van een zonwering, fietsenrekken of een hellingbaan voor rolstoelen en fietsen worden behandeld?", "a": "Onderwerpen zoals de installatie van zonwering, fietsenstallingen of bouwkundige aanpassingen zoals een helling dienen als agendapunt besproken te worden tijdens de VvE-vergadering."}, {"v": "Wat moet ik doen als er afval of losse onderdelen zoals plafondplaten in de gemeenschappelijke gang liggen?", "a": "Wanneer er voorwerpen of defecten in de gemeenschappelijke ruimtes worden geconstateerd, kan dit worden doorgegeven aan het beheer zodat de huismeester dit kan oppakken."}, {"v": "Wat doet de VvE beheerder bij terugkerende storingen aan technische installaties zoals een lift?", "a": "Bij terugkerende problemen neemt de beheerder contact op met de installateur om de defecten kenbaar te maken en aan te dringen op een structurele oplossing. Er wordt gekeken naar de oorzaak van de storingen, zoals eventuele menselijke fouten, waarbij indien nodig duidelijke gebruikersinstructies bij het systeem worden geplaatst. Daarnaast wordt er een onderhoudscontract afgesloten inclusief een storingsnummer dat eigenaren kunnen bellen in geval van calamiteiten."}, {"v": "Bij wie kan ik terecht voor financiële vragen over de VvE?", "a": "Voor financiële vragen kun je terecht bij de financiële afdeling van Totaal VvE Beheer."}, {"v": "Wanneer moet de bouwkundige geïnformeerd worden over de start van de werkzaamheden bij bouwbegeleiding?", "a": "Bij gebruik van bouwkundige begeleiding dient de bouwkundige uiterlijk twee weken voordat de werkzaamheden starten een bericht te ontvangen, zodat er tijd vrijgemaakt kan worden voor de bouwbezoeken."}, {"v": "Is de VvE juridisch verplicht of verantwoordelijk om individuele eigenaren te ondersteunen bij het verduurzamen van oude houten kozijnen?", "a": "De VvE is juridisch niet verplicht en ook niet verantwoordelijk om individuele eigenaren te helpen om de oude houtenkozijnen te verduurzamen. De VvE kan eigenaren wel helpen en stimuleren om te investeren in het duurzaam maken van de woning. Indien nodig kan de gemeente een onderhoudslening verstrekken tegen een aantrekkelijk rentetarief."}, {"v": "Hoe kunnen bewoners van een VvE advies krijgen over het verduurzamen van hun woning?", "a": "Wanneer de VvE geïnteresseerd is in verduurzaming kan daarvoor contact opgenomen worden met de beheerder. Hij zal u van de juiste informatie voorzien en indien gewenst een afspraak plannen met een partij om inzicht te krijgen in alle verduurzamingsmogelijkheden."}, {"v": "Kan de VvE beheerder inzien of een woning met of zonder berging wordt verkocht en wie in het bezit is van de sleutel?", "a": "De VvE beheerder wordt niet bij het aan- of verkooptraject van een woning betrokken en kan dus niet zien of een woning met of zonder berging wordt overgedragen. Daarnaast beschikt de beheerder niet over gegevens van de persoon die in het bezit zou moeten zijn van de sleutels."}, {"v": "Wat moet ik doen als er sprake is van een serieuze lekkage aan de muur met schimmelvorming?", "a": "Totaal VvE Beheer kan een afspraak inplannen met een gespecialiseerde partij om de lekkage te inspecteren en te verhelpen."}, {"v": "Is het mogelijk om zelf aangeschafte materialen voor onderhoudswerkzaamheden te laten vergoeden door de VvE?", "a": "Eventuele aangeschafte materialen kunnen uit de VvE reserve betaald worden als de andere eigenaren hier ook mee akkoord zijn."}, {"v": "Wanneer vindt de uitvoering van de werkzaamheden plaats nadat een offerte is goedgekeurd?", "a": "Zodra er akkoord is gegeven op de offerte, zal het uitvoerende bedrijf contact met u opnemen om een uitvoerdatum in te plannen."}, {"v": "Bij wie moet ik een melding maken of een verzoek indienen voor de VvE?", "a": "U kunt een eventuele melding altijd bij uw VvE-beheerder uitzetten, zodat deze bij de juiste persoon of firma kan worden uitgezet."}, {"v": "Kan een afstandsbediening of zender voor de slagboom per post worden verstuurd?", "a": "Het is niet mogelijk om de zender per post te versturen. De zender dient op kantoor te worden afgehaald."}, {"v": "Waarom is het verstandig om een kennismaking of bezichtiging van het pand overdag te plannen?", "a": "Het is raadzaam om een afspraak met daglicht te organiseren, zodat ook de buitenkant van het pand goed bekeken kan worden."}, {"v": "Moet ik toegang verlenen tot mijn woning voor onderhoud aan de VvE?", "a": "Eigenaars en huurders zijn verplicht om bij onderhoud aan de gemeenschappelijke gedeelten - daar waar nodig en mogelijk - toegang en toestemming te verlenen via de individuele (privé) gedeelten."}, {"v": "Welke gedragsregels gelden er voor bewoners in de gemeenschappelijke ruimten?", "a": "Eigenaars en huurders zijn verplicht zich te onthouden van luidruchtigheid, geluidsoverlast, onredelijke hinder en onbehoorlijk gedrag. Het is niet toegestaan onnodig te verblijven in de gemeenschappelijke gedeelten of daar (brom)fietsen of andere voorwerpen te plaatsen."}, {"v": "Welke specifieke onderhoudstaken moeten eigenaren in de gaten houden?", "a": "Eigenaren dienen de volgende zaken te onderhouden en te controleren: het onderhouden van kitnaden en voegen bij de douche en het bad; het schoonhouden van het balkon en zorgen dat afvoerputjes vrij zijn; het jaarlijks laten onderhouden van de CV-ketel of boiler; het periodiek controleren of hemelwaterafvoer en dakgoten vrij zijn van bladeren; en het goed ventileren van de woning ter voorkoming van vochtaanslag op de muren."}, {"v": "Wat zijn de verplichtingen van een lid met betrekking tot het binnenonderhoud van de woning?", "a": "Conform het reglement heeft ieder lid de verplichting om zijn woning intern goed te onderhouden. Mogelijke schades door slecht onderhoud, zoals aan de douche, het bad, kitnaden, voegen, (ongeschikte) vloeren, afwatering en goten, zullen op basis van aansprakelijkheid worden verhaald op de eigenaar."}, {"v": "Hoe wordt er omgegaan met het herstellen van houtrot tijdens onderhoudswerkzaamheden?", "a": "Bij het aantreffen van houtrot kan dit zorgvuldig in kaart worden gebracht. Er worden foto’s gemaakt van de eventuele houtrot en er wordt een duidelijke prijsopgave opgesteld voor het verhelpen ervan. Deze informatie kan vervolgens aan de vereniging worden voorgelegd ter goedkeuring."}, {"v": "Welke gegevens zijn nodig voor een aanvraag bij het Warmtefonds voor de VvE?", "a": "Voor een aanvraag bij het Warmtefonds zijn legitimatiebewijzen nodig van de bestuursleden, gemachtigden, contactpersonen en UBO's om hun identiteit vast te stellen. Belangrijk hierbij is dat het BSN niet leesbaar mag zijn en de foto onzichtbaar gemaakt moet worden."}, {"v": "Wat kan ik doen als de toegang tot mijn bedrijfsruimte of garage herhaaldelijk wordt geblokkeerd door foutgeparkeerde auto's?", "a": "In het geval van parkeeroverlast die de toegang tot uw eigendom blokkeert, is het raadzaam om rechtstreeks contact op te nemen met de gemeente. De ervaring leert dat de gemeente sneller en effectiever optreedt wanneer de gedupeerde eigenaar zelf de overlast en de beperkte bereikbaarheid van het pand meldt."}, {"v": "Is hang- en sluitwerk van een appartement de verantwoordelijkheid van de individuele eigenaar?", "a": "Hang- en sluitwerk wordt doorgaans beschouwd als individueel eigendom en valt daarmee onder de verantwoordelijkheid van de individuele eigenaar."}, {"v": "Is condens tussen het glas gedekt door de glasverzekering van de VvE?", "a": "Condens tussen het glas is niet verzekerd. De glasverzekering biedt alleen dekking voor scheuren en wanneer het glas eruit ligt. Omdat dit geen gezamenlijk onderdeel is van de VvE, dient u hiervoor zelf een partij in te schakelen."}, {"v": "Hoe wordt er omgegaan met collectieve wensen voor nieuwe voorzieningen, zoals bijvoorbeeld zonwering?", "a": "Tijdens de vergadering wordt besproken of het wenselijk is dat er offertes worden opgevraagd. Op dat moment kunnen ook de specifieke wensen van de eigenaren hierin worden meegenomen."}, {"v": "Zijn onroerendezaakbelasting (OZB) en andere gemeentelijke heffingen een zaak voor de VvE of een privéaangelegenheid?", "a": "De aanslag onroerendezaakbelasting en andere gemeentelijke heffingen zijn privébelastingen voor de eigenaar van de woning en vallen niet onder de verantwoordelijkheid van de VvE."}, {"v": "Op welke manieren kan ik een melding maken of vragen stellen?", "a": "U kunt meldingen maken via ons digitale portaal Totaal Portaal of uw vragen per e-mail aan ons stellen."}, {"v": "Is er toestemming nodig van de VvE voor het ophangen van zonwering (zoals uitvalschermen of screens) aan de gevel?", "a": "Om zonwering op te hangen aan de gevel van de VvE is inderdaad toestemming nodig. U kunt dit verzoek bespreekbaar maken tijdens de Algemene Ledenvergadering (ALV) om te zien of er eventuele bezwaren zijn en of er direct een besluit over genomen kan worden."}, {"v": "Kan Totaal VvE Beheer ondersteunen bij een aanvraag voor het Nationaal Warmtefonds?", "a": "Totaal VvE Beheer kan VvE's ondersteunen met een warmtefonds aanvraag. Hiervoor is begeleiding mogelijk en kan een stappenplan worden gedeeld om inzicht te krijgen in het proces."}, {"v": "Hoe ontstaat groene aanslag op balkons en wie is verantwoordelijk voor het onderhoud hiervan?", "a": "Bij het niet schoonhouden van balkons en de aanwezigheid van planten of spullen kan groene aanslag binnen een jaar terugkeren. Eigenaren hebben een onderhoudsplicht voor hun balkons om dit te voorkomen."}, {"v": "Is de binnenafwerking van mijn woning een collectief onderdeel van de VvE?", "a": "De binnenafwerking van de woning is geen collectief onderdeel van de VvE. Een aannemer kan hiervoor worden ingeschakeld, echter dienen deze kosten door de eigenaar zelf gedragen te worden omdat het geen onderdeel is van de VvE."}, {"v": "Hoe kan ik een melding maken van urgent onderhoud, zoals een lekkage?", "a": "Voor zaken die urgent zijn qua onderhoud (zoals lekkages) kunt u een melding maken bij de beheerder."}, {"v": "Wie is verantwoordelijk voor de kosten van het verwijderen van individuele zaken, zoals een dakterras of stellages, wanneer er onderhoud aan gemeenschappelijke delen (zoals het dak of de vloer) moet plaatsvinden?", "a": "De individuele eigenaar is zelf verantwoordelijk voor de kosten van het verwijderen en terugplaatsen van persoonlijke eigendommen. Een voorbeeld hiervan is wanneer er onderhoud aan het dak uitgevoerd moet worden en er een dakterras aanwezig is; de eigenaar van het dakterras is dan verantwoordelijk voor de kosten van het verwijderen van het dakterras. De verzekering vergoedt deze kosten doorgaans niet."}, {"v": "Wie draagt de kosten wanneer de verzekering een schade afwijst en hoe wordt dit besloten?", "a": "Wanneer de verzekering een schade afwijst, is het gebruikelijk dat de kosten worden gedragen door de VvE. Hier moet dan wel een vergaderbesluit over genomen worden door de eigenaars."}, {"v": "Waarom is het belangrijk om het balkon vrij te houden van obstakels?", "a": "Het is belangrijk om het balkon vrij te maken van obstakels zodat regenwater goed kan afvoeren. Wanneer er te veel spullen op een balkon staan, kan het water niet goed wegstromen, wat het risico op wateroverlast en lekkages verhoogt."}, {"v": "Is een eigenaar verplicht om zijn woning goed te onderhouden om schade bij anderen te voorkomen?", "a": "Als eigenaar bent u verplicht om uw woning goed te onderhouden, zodat anderen er geen hinder of schade, zoals lekkage, van ondervinden. De kosten van eventuele gevolgschade bij achterstallig onderhoud zijn voor rekening van de eigenaar."}, {"v": "Kan Totaal VvE Beheer worden ingesteld als correspondentieadres bij nutsbedrijven?", "a": "Wij kunnen zorg dragen dat toekomstige correspondentie van nutsbedrijven via ons verloopt. In veel gevallen kunnen wij wijzigingen direct doorvoeren via de online portaalen van deze instanties."}, {"v": "Hoe gaat Totaal VvE Beheer om met dossiers of schades die al liepen bij een vorige beheerder?", "a": "In onze beheersovereenkomst staat dat wij vaak geen vervolg kunnen geven aan zaken die al bij de vorige beheerder liepen, zeker wanneer de gebeurtenissen niet hebben plaatsgevonden tijdens onze beheertijd en wij geen kennis hebben van deze dossiers."}, {"v": "Mag een bewoner de kleur van de dakkapellen wijzigen naar een andere kleur dan de huidige kleurstelling?", "a": "Voor het wijzigen van de kleurstelling van dakkapellen is het meestal noodzakelijk dat de rest van de VvE hier een besluit over neemt. Het is raadzaam om dergelijke verzoeken direct door te zetten naar de VvE beheerder."}, {"v": "Wie is verantwoordelijk voor de handzenders van het hek van een VvE?", "a": "Het hek is eigendom van de VvE. Voor het bestellen of kopen van een extra handzender kunt u contact opnemen met de VvE beheerder."}, {"v": "Is er een omgevingsvergunning nodig voor het realiseren van een dakterras op het dak van een woning in de gemeente Den Haag?", "a": "In de gemeente Den Haag is het in principe verplicht om een omgevingsvergunning aan te vragen voor het realiseren van een dakterras op het dak van een woning."}, {"v": "Worden er extra kosten in rekening gebracht voor het opvragen van offertes?", "a": "Het opvragen van offertes zit inbegrepen bij onze dienstverlening. Daar worden dus geen extra kosten voor in rekening gebracht. Wel is het zo dat we in de basis maximaal 2 offertes opvragen voor werkzaamheden."}, {"v": "Werkt Totaal VvE Beheer met een vaste huisaannemer voor offertes en reparaties?", "a": "Wij werken niet met een vaste huisaannemer. Elke individuele VvE beheerder bepaalt zelf waar offertes worden opgevraagd."}, {"v": "Wordt waterschade door neerslag die door de gevel naar binnen komt vergoed door de opstalverzekering?", "a": "Neerslag die door de muren of de gevel naar binnen komt, wordt doorgaans niet vergoed door de verzekeraar."}, {"v": "Wat zijn de eerste stappen voor een VvE die een groendak wil aanleggen?", "a": "De eerste stappen zijn het aanvragen van een dakinspectie om de geschiktheid van het dak te laten beoordelen door een specialist, en vervolgens het opvragen en vergelijken van offertes bij verschillende partijen."}, {"v": "Is het VvE-beheer verantwoordelijk voor gebreken aan een woning die na de aankoop van een appartement aan het licht komen?", "a": "Het VvE-beheer is geen partij bij de aan- of verkoop van een appartement. De verkopende partij heeft een informatieplicht en is wettelijk verplicht om bekende gebreken te melden, terwijl op de koper een onderzoeksplicht rust. Als beheerder van de VvE vervullen wij een administratieve en uitvoerende rol in opdracht van de leden en zijn wij niet verantwoordelijk voor de bouwkundige staat van afzonderlijke woningen of verborgen gebreken."}, {"v": "Is het mogelijk om sedum toe te passen op de daken van de VvE op een manier dat het ook weer verwijderd kan worden?", "a": "Het is mogelijk om te kiezen voor sedum-bakken. Deze hebben als voordeel dat ze eenvoudig verwijderd en weer teruggeplaatst kunnen worden als dat wenselijk is, bijvoorbeeld bij onderhoudswerkzaamheden aan het dak."}, {"v": "Waarom kan het nodig zijn om een nieuw Meerjarenonderhoudsplan (MJOP) te laten opstellen als er al een bestaand plan is?", "a": "Het kan noodzakelijk zijn om een nieuw MJOP te laten opstellen als het huidige plan van onvoldoende kwaliteit is, bijvoorbeeld als het merendeel van het onderhoud al uitgevoerd is."}, {"v": "Waarvoor blijven eigenaren zelf verantwoordelijk binnen de VvE?", "a": "Eigenaren blijven altijd eerstelijns verantwoordelijk voor de besluitvorming over groot onderhoud aan het gebouw en de opbouw van financiële reserves. De bestuurder zal waar mogelijk en naar eigen zakelijk inzicht, binnen de kaders van de beheeractiviteiten, een constructieve bijdrage leveren om de voortgang en besluitvorming binnen de vereniging te bewerkstelligen."}, {"v": "Is de beheerder aansprakelijk voor problemen uit een vorige beheerperiode?", "a": "De bestuurder is niet verantwoordelijk of aansprakelijk voor problemen die zijn ontstaan tijdens de vorige beheerperiode. Denk hierbij aan achterstallig onderhoud aan gezamenlijke delen van het gebouw, brieven van instanties of discussies over verantwoordelijkheid. Ook persoonlijke meningsverschillen tussen eigenaren vallen hier niet onder. Waar nodig en mogelijk zal de bestuurder proberen om mee te denken en ondersteuning te bieden binnen zijn taken als beheerder. Dit gebeurt op een zakelijke en praktische manier, met als doel om de samenwerking en besluitvorming binnen de VvE te verbeteren."}, {"v": "Waarvoor kan ik terecht bij de beheerder van de VvE?", "a": "De beheerder is het vaste aanspreekpunt voor alle zaken die de VvE aangaan en zorgt voor de administratieve, technische en bestuurlijke ondersteuning. Denk hierbij aan het begeleiden van onderhoudswerkzaamheden, het organiseren van vergaderingen, het opstellen van jaarstukken en het beantwoorden van praktische en inhoudelijke vragen van eigenaren."}, {"v": "Hoe pakt de VvE aanhoudende overlast van ongedierte structureel aan?", "a": "Op basis van de bevindingen van de ongediertebestrijder kan er een concreet voorstel worden uitgewerkt voor een onderhoudsabonnement voor ongediertebestrijding. Dit voorstel wordt voorgelegd aan de VvE, zodat de vereniging kan kijken naar een structurele aanpak om herhaling te voorkomen."}, {"v": "Valt het herstel van betonrot aan de binnenzijde van een woning onder de verantwoordelijkheid van de VvE?", "a": "Omdat het om de constructie gaat is het onderdeel van de VvE."}, {"v": "Wat moet er gebeuren bij een vermoedelijke rattenplaag in de kruipruimte die mogelijk veroorzaakt wordt door een defect in de riolering?", "a": "Bij een rattenplaag in combinatie met een vermoedelijk riooldefect moet er gedacht worden aan een rioolinspectie om de oorzaak te achterhalen, evenals het inschakelen van een ongediertebestrijder om de plaag te bestrijden."}, {"v": "Waarom moet ik zo vaak de meterstanden doorgeven aan de energieleverancier?", "a": "Wanneer er sprake is van een variabel energiecontract, vraagt de energieleverancier vaker om de actuele meterstanden."}, {"v": "Wat gebeurt er met schadedossiers die reeds door de verzekeraar zijn afgewezen?", "a": "Wanneer de verzekeraar een dossier heeft afgewezen, zal deze beslissing niet meer worden herzien of gewijzigd."}, {"v": "Wat is de procedure bij het melden van een nieuwe schade?", "a": "Bij een nieuwe schade moet er een schadeformulier worden aangeleverd. Het is belangrijk dat de informatie over de schade volledig wordt ingevuld voordat de zaak kan worden doorgezet naar de verzekering. Let op: het is niet raadzaam om werkzaamheden al uit te voeren voordat de schade bij de verzekering is ondergebracht, omdat de verzekeraar hier bezwaar tegen kan maken."}, {"v": "Kan ik rechtstreeks contact opnemen met de tussenpersoon of verzekeraar over een lopende schade?", "a": "Nee, het wordt dringend verzocht om geen direct contact op te nemen met de tussenpersoon of de verzekeraar. Dit verstoort het proces en belemmert een correcte afhandeling van de schade."}, {"v": "Is er naast toestemming van de VvE ook een vergunning van de gemeente nodig voor een airco-unit?", "a": "In sommige gevallen is ook een vergunning van de gemeente vereist, zeker als het pand een beschermd stadsgezicht betreft of als de unit zichtbaar is vanaf de openbare ruimte. Het is raadzaam om dit na te vragen bij de afdeling Vergunningen van de gemeente of via het Omgevingsloket online."}, {"v": "Waarvoor kan een VvE een lening aangaan?", "a": "Een VvE kan in principe alleen een lening aangaan voor verduurzaming en/of het wegwerken van achterstallig onderhoud. Het afsluiten van een lening om openstaande rekeningen te betalen valt hier niet onder."}, {"v": "Is schade als gevolg van een ondeugdelijke constructie (zoals niet correct geplaatste zonnepanelen) gedekt door de VvE-verzekering?", "a": "De VvE is niet verzekerd voor schade als gevolg van een ondeugdelijke constructie."}, {"v": "Is het mogelijk om bij gepland dakonderhoud direct verduurzamingsmaatregelen uit te voeren die aansluiten op een bestaand maatwerkadvies?", "a": "Het is een goed idee om het dak direct te verduurzamen wanneer er werkzaamheden gepland staan. Dit kan goed aansluiten op een liggend maatwerkadvies. Indien er binnen de VvE voldoende animo en interesse is van meerdere eigenaren, kunnen de mogelijkheden worden bekeken en eventueel offertes worden opgevraagd."}, {"v": "Wat moet ik doen als er een stukje sleutel in het slot is afgebroken, maar de deur nog wel open en dicht kan?", "a": "Een stukje sleutel dat vastzit in het slot kan meestal vrij eenvoudig worden verwijderd door een slotenmaker. Dit is doorgaans een kleine en relatief voordelige klus. U kunt ervoor kiezen om zelf een slotenmaker in te schakelen of het beheer te vragen dit voor u te organiseren."}, {"v": "Is het toegestaan om een balkonkast of vergelijkbaar object op mijn balkon te plaatsen?", "a": "Het plaatsen van een kast op een balkon die zichtbaar is vanaf de straat of aangrenzende percelen is in de regel alleen toegestaan met expliciete toestemming van de VvE, conform het splitsingsreglement. Dergelijke toevoegingen mogen bovendien niet leiden tot wijzigingen aan de constructie, het aanzicht of de draagbelasting van het gebouw zonder een besluit van de Algemene Ledenvergadering (ALV)."}, {"v": "Wat kan de oorzaak zijn van scheuren en loskomend beton bij een balkon?", "a": "Dit kan worden veroorzaakt door het aantasten van de uitdragers (de stalen balken die het balkon dragen). Als dit staal gaat roesten, gaat het uitzetten, waardoor het beton naar buiten wordt gedrukt. Hierdoor ontstaan scheuren en kan er beton loskomen."}, {"v": "Waarom kan er een verschil zitten tussen de oppervlakte in een splitsingsakte en de oppervlakte van de WOZ-data?", "a": "Dit verschil ontstaat doordat in splitsingsaktes gebruik wordt gemaakt van bruto oppervlakten vanaf de tekeningen, terwijl de WOZ-waarde of gebruiksoppervlakte volgens andere meetmethodes wordt berekend. Verschillende meetmethodes leiden tot verschillende uitkomsten."}, {"v": "Op basis waarvan worden de breukdelen in een VvE splitsing vastgesteld bij een verbouwing?", "a": "De breukdelen worden opnieuw vastgesteld op basis van de bruto vloeroppervlakten volgens de splitsingstekening. Hierbij wordt niet gekeken naar de gebruiksoppervlakte of de WOZ-oppervlakte."}, {"v": "Ben ik verplicht om aangifte te doen bij de politie in geval van opzettelijke schade voor de opstalverzekering?", "a": "Volgens de polisvoorwaarden van de opstalverzekering is het verplicht om aangifte bij de politie te doen wanneer er sprake is van opzettelijke schade."}, {"v": "Is het noodzakelijk om aangifte te doen bij het indienen van een schadeclaim?", "a": "Voor het indienen van een claim is het noodzakelijk dat er aangifte wordt gedaan door een eigenaar. Zodra de aangifte is ontvangen, kan het dossier compleet worden gemaakt en worden ingediend bij de verzekeraar."}, {"v": "Is het raadzaam om sedum (een groendak) aan te leggen op een dak waar ook zonnepanelen en veiligheidsankers aanwezig zijn?", "a": "Het wordt afgeraden om sedum te plaatsen op daken waar zonnepanelen en veiligheidsankers aanwezig zijn. De beschikbare ruimte is vaak beperkt, en de aanwezigheid van sedum bemoeilijkt het toekomstig onderhoud aan zowel de zonnepanelen als het dak. Daarnaast levert het aanbrengen van sedum rondom zonnepanelen geen significant voordeel op, terwijl het onderhoud complexer wordt."}, {"v": "Worden onderwerpen uit het verleden behandeld tijdens de vergadering?", "a": "Tijdens de vergadering worden geen onderwerpen behandeld die zich hebben voorgedaan vóór de start van het beheer door Totaal VvE Beheer."}, {"v": "Wat is de verhouding tussen het huishoudelijk reglement en de akte van splitsing?", "a": "Het huishoudelijk reglement is in rang ondergeschikt aan het splitsingsreglement, de akte van splitsing en de splitsingstekeningen. Eventuele bepalingen uit het huishoudelijk reglement die daarmee in strijd zijn, zijn niet verbindend."}, {"v": "Waarom zijn elektrische voertuigen soms niet toegestaan in een parkeergarage van een VvE?", "a": "Een verbod op elektrische voertuigen in parkeergarages wordt vaak ingesteld vanuit veiligheids- en verzekeringsperspectief. Elektrische auto’s brengen bij brand een ander risicoprofiel met zich mee dan voertuigen met een verbrandingsmotor. Het blussen van een accu-brand vergt een specifieke aanpak en kan leiden tot extreme hitteontwikkeling, waarbij standaard brandbestrijdingsmiddelen in een inpandige parkeergarage mogelijk tekortschieten. Daarnaast zijn niet alle garages qua ventilatie, branddetectie en blusvoorzieningen geschikt of gecertificeerd voor het opladen en stallen van elektrische voertuigen. Verzekeraars stellen bovendien vaak extra eisen wanneer elektrische auto's structureel in een gebouw worden geplaatst."}, {"v": "Wat kan de VvE doen aan overlast en onveiligheid door onbevoegden in het portiek?", "a": "Wanneer er sprake is van onveiligheid of hinder door onbevoegden in het portiek, kan er worden onderzocht welke bouwkundige of technische opties er zijn om de toegang te beperken. Mogelijke oplossingen zijn het aanbrengen van een nachtslot of het installeren van een toegangscontrolesysteem met een code."}, {"v": "Kan een VvE-beheerder contante betalingen verrichten voor gemaakte onkosten?", "a": "Wij beschikken niet over contant geld van de VvE. Voor de vergoeding van onkosten dient u een bewijsstuk of foto van de rekening aan te leveren, waarna het bedrag per bank wordt overgemaakt."}, {"v": "Is het toegestaan om persoonlijke eigendommen of meubilair in de algemene ruimtes van het pand te plaatsen?", "a": "Het is niet toegestaan om goederen, meubilair of andere spullen in de algemene ruimtes te plaatsen. Dit verbod is ingesteld in verband met de brandveiligheid en het vrijhouden van vluchtroutes, conform de geldende wet- en regelgeving."}, {"v": "Is het toegestaan om fietsen of scooters in de gemeenschappelijke gang te plaatsen?", "a": "Het is niet toegestaan om voertuigen of obstakels in de gemeenschappelijke gang te plaatsen. De doorgang moet te allen tijde vrij blijven omdat het de vluchtroute belemmert bij calamiteiten zoals brand, het bij inspecties kan leiden tot een verminderde of zelfs afgewezen verzekeringsdekking en het bij schade of letsel kan leiden tot aansprakelijkheidsrisico’s voor de VvE."}, {"v": "Is het mogelijk om alleen het financiële beheer van een VvE uit te besteden, bijvoorbeeld voor het opstellen van de jaarrekening?", "a": "Tegenwoordig voeren wij alleen nog het complete beheer van een VvE uit. Wanneer u uitsluitend op zoek bent naar financieel beheer voor bijvoorbeeld een jaarrekening, kunt u overwegen hiervoor een boekhouder in te huren. Houd er echter rekening mee dat u dan nog steeds zelf verantwoordelijk bent voor de maandelijkse betalingen en overige taken."}, {"v": "Wat houdt de rol van een technische commissie of technisch contactpersoon binnen de VvE in?", "a": "Het fungeert als sparringspartner voor de beheerder bij technische kwesties, zoals het meedenken over onderhoud, het bekijken van een offerte of het beoordelen van werkzaamheden. Het is een rol van meedenken waar nodig en dient als praktisch klankbord bij vragen of onderhoudsplannen."}, {"v": "Beheert Totaal VvE Beheer ook kleine VvE’s?", "a": "Ja, wij beheren VvE’s vanaf 2 appartementen. Juist bij kleine verenigingen bieden wij schaalvoordeel, ontzorgen wij bestuurders en houden we de kosten laag."}, {"v": "Wat maakt de aanpak van Totaal VvE Beheer anders dan die van andere beheerders?", "a": "Wij combineren persoonlijke betrokkenheid met professionele processen door te werken met één vast aanspreekpunt, in-house technische controle zodat u niet afhankelijk bent van derden, proactief meedenken over verduurzaming en besparingen, en het bieden van volledig inzicht via ons online VvE-portaal."}, {"v": "Is het mogelijk om de kleur van de gevel volledig te veranderen of zijn er beperkingen vanuit de gemeente?", "a": "Het volledig veranderen van de kleur is meestal niet mogelijk. Vaak kan er wel gekozen worden binnen een specifieke kleurgroep, zoals verschillende tinten (gebroken) wit. Bij twijfel over de regelgeving van de gemeente kan er navraag worden gedaan bij een contactpersoon bij de gemeente om te controleren of een specifieke kleuraanpassing is toegestaan."}, {"v": "Op welke termijn kunnen werkzaamheden van een aannemer starten nadat een offerte is goedgekeurd?", "a": "Totaal VvE Beheer kan niet aangeven op welke termijn een aannemer zou kunnen starten. Wij adviseren u om dit rechtstreeks met de desbetreffende aannemer af te stemmen."}, {"v": "Houdt de VvE beheerder bij hoeveel woningen binnen een complex verhuurd zijn?", "a": "In de administratie is niet altijd met zekerheid terug te zien of en hoeveel woningen er op een specifiek moment verhuurd zijn binnen een complex. Vaak is dit niet officieel geregistreerd binnen de VvE-administratie."}, {"v": "Is het voor eigenaren verplicht om een glasvezelaansluiting in hun woning te laten installeren?", "a": "Eigenaren kunnen zelf kiezen of zij een glasvezelkabel in hun woning willen laten installeren."}, {"v": "Binnen welke termijn worden de notulen na een vergadering doorgaans verzonden?", "a": "Normaal gesproken streven wij ernaar om de notulen uiterlijk binnen twee weken na de vergadering te versturen."}, {"v": "Wat moet ik doen als ik vermoed dat een aannemer of ingeschakeld bedrijf schade heeft veroorzaakt tijdens werkzaamheden aan het pand?", "a": "Wanneer er schade is ontstaan tijdens werkzaamheden, leggen wij deze melding direct voor aan de aannemer en de betrokken onderaannemer. Om de aansprakelijkheid goed te kunnen beoordelen en de schade te kunnen verhalen, wordt u vaak gevraagd om bewijsmateriaal, zoals camerabeelden of foto's, aan te leveren waarop de gebeurtenis zichtbaar is. Zodra hiermee bevestigd kan worden dat de schade door de medewerkers is veroorzaakt, zal er samen met u naar een oplossing worden gezocht."}, {"v": "Wat kan de VvE doen bij schade die veroorzaakt is door een extern bedrijf?", "a": "De VvE kan hierin slechts een bemiddelende rol vervullen. Er wordt geadviseerd om rechtstreeks met het betreffende bedrijf in gesprek te gaan."}, {"v": "Hoe vaak vindt een liftkeuring plaats en door wie wordt dit uitgevoerd?", "a": "Een liftkeuring vindt één keer per anderhalf jaar plaats en wordt uitgevoerd door een ander bedrijf dan het onderhoudsbedrijf."}, {"v": "Waarom zijn mijn betalingen nog niet zichtbaar in het portaal?", "a": "Omdat de VvE gebruikmaakt van een externe bank kan er soms enige vertraging zitten in het verversen van de transacties in het portaal."}, {"v": "Moeten auto's uit de parkeergarage worden verwijderd tijdens onderhoudswerkzaamheden aan de parkeerplateaus?", "a": "Hoewel monteurs vaak om auto's heen kunnen werken die onder de parkeerplateaus staan, verdient het de voorkeur om eigenaren de mogelijkheid te geven hun auto te verplaatsen voordat het onderhoud wordt uitgevoerd."}, {"v": "Is het mogelijk om bij een offerteaanvraag extra opties zoals een groen dak of specifieke isolatie mee te laten nemen?", "a": "Punten die niet in de oorspronkelijke aanvraag zaten, kunnen alsnog bij de betreffende bedrijven worden opgevraagd om als optie in de offerte mee te nemen."}, {"v": "Hoe werkt de opbrengst van zonnepanelen op een VvE-gebouw?", "a": "De zonnepanelen zijn aangesloten op de gemeenschappelijke meters. Dat betekent dat de opgewekte stroom direct wordt gebruikt voor de gemeenschappelijke ruimtes, zoals verlichting in de hal en andere gezamenlijke voorzieningen. De opbrengst wordt vaak meteen verbruikt, waardoor er nagenoeg niets overblijft. Dit wordt doorgaans pas na een volledig jaar goed zichtbaar op de energienota, omdat er dan een totaaloverzicht is van zowel de opbrengsten als het verbruik in verhouding tot de gemeenschappelijke kosten."}, {"v": "Mogen reparateurs direct een noodoplossing uitvoeren bij acute schade?", "a": "Wanneer een noodoplossing mogelijk is, mogen herstelbedrijven dit binnen het afgegeven mandaat direct uitvoeren om verdere schade te voorkomen."}, {"v": "Wat kan de oorzaak zijn van nare geuren uit de hemelwaterafvoer (HWA) bij een gemengd rioolstelsel tijdens droge periodes?", "a": "Wanneer het rioolstelsel tijdens droge periodes droog komt te staan, kan er een nare lucht uit de put of de hemelwaterafvoer (HWA) komen. Een tijdelijke oplossing is om af en toe een emmer water in de put te gooien, al is het effect hiervan beperkt. Voor een structurele oplossing kan advies worden ingewonnen bij een rioolservicepartij."}, {"v": "Kunnen omgangsvormen tussen bewoners worden opgenomen in de reglementen?", "a": "Omgangsvormen kunnen op de agenda van de vergadering worden geplaatst en eventueel worden toegevoegd aan het Huishoudelijk Reglement."}, {"v": "Wanneer wordt een concept Huishoudelijk Reglement officieel vastgesteld?", "a": "Wanneer het concept van het Huishoudelijk Reglement helemaal is afgerond, zal dit ter goedkeuring worden voorgelegd aan de vergadering om het te formaliseren."}, {"v": "Is het mogelijk om een hek of afsluiting te plaatsen bij de entree van de VvE om overlast te voorkomen?", "a": "Voor het plaatsen van een hek is toestemming van de gemeente vereist. Dit betekent dat er door de VvE of een groep bewoners een officiële aanvraag bij de gemeente moet worden ingediend. Zonder deze vergunning kan er geen hek geplaatst worden. Daarnaast moet er nagedacht worden over de praktische uitvoering, zoals de wijze van toegang (sleutels, tags of intercom), de kosten voor aanschaf en onderhoud, en de impact op de gemeenschappelijke ruimtes. De eerste stap is dus het indienen van een aanvraag bij de gemeente. Zodra daar duidelijkheid over is, kan de VvE verder kijken naar de uitvoering."}, {"v": "Waarvoor dient een algemene watermeter binnen de VvE?", "a": "Een algemene watermeter binnen de VvE is bedoeld voor gemeenschappelijk gebruik, zoals bijvoorbeeld voor de schoonmaakwerkzaamheden in de centrale ruimtes."}, {"v": "Heeft de beheerder juristen in dienst om namens de VvE partijen aansprakelijk te stellen?", "a": "Wij hebben geen juristen in dienst en kunnen niet zomaar namens de VvE iemand aansprakelijk stellen."}, {"v": "Aan welke richtlijnen moeten nieuwe cilindersloten voldoen met betrekking tot de inbraakveiligheid en het uitsteken van de cilinder?", "a": "Volgens de richtlijnen van het Politiekeurmerk Veilig Wonen (PKVW) mag een cilinder, in combinatie met het gebruik van gecertificeerd inbraakwerend beslag, maximaal 3 mm uitsteken. Cilinders die verder uitsteken zijn minder inbraakwerend omdat deze van buitenaf makkelijker te grijpen zijn door inbrekers."}, {"v": "Kan de beheerder zelfstandig een besluit nemen over de aanschaf van een nieuw intercomsysteem?", "a": "Besluiten over dergelijke investeringen vallen buiten het mandaat van de beheerder; het besluit zal altijd voorgelegd moeten worden aan de leden van de VvE."}, {"v": "Hoe kunnen afspraken of besluiten over persoonlijke investeringen in relatie tot de VvE via de mail officieel worden vastgelegd?", "a": "Om een afspraak of besluit officieel vast te leggen, is het van belang dat alle andere eigenaren akkoord geven. De e-mailcorrespondentie kan vervolgens als officieel besluit worden opgeslagen in de administratie."}, {"v": "Wat moet ik doen als mijn parkeervergunning op eigen terrein wordt afgewezen door de gemeente?", "a": "Wanneer een parkeervergunning wordt afgewezen terwijl er volgens u recht op is, dient u zelf een e-mail te sturen naar de gemeente via parkeren@denhaag.nl. De VvE-beheerder kan hierin niets betekenen; de aanvrager moet dit zelf rechtstreeks met de gemeente afhandelen en de instructies in de officiële brief van de gemeente volgen."}, {"v": "Waarom is het verstandig om verouderde dakramen volledig te vervangen in plaats van alleen de gootstukken te vernieuwen?", "a": "Hoewel het plaatsen van nieuwe gootstukken technisch mogelijk is, zijn verouderde dakramen vaak aan het einde van hun levensduur. Door alleen de gootstukken te vervangen, loopt u het risico dat de ramen kort daarna alsnog volledig afgeschreven zijn en vervangen moeten worden, waardoor eerdere investeringen minder rendabel zijn."}, {"v": "Hoe kan ik contact opnemen met bedrijven voor een offerte of vragen stellen over de aanvraag?", "a": "U kunt de bedrijven rechtstreeks bellen of e-mailen. Daarnaast kunt u uw vraag aan ons stellen, zodat wij contact met hen kunnen opnemen."}, {"v": "Kan de VvE beslissen over de toekenning van bewonersparkeervergunningen op eigen terrein?", "a": "De VvE speelt geen rol in de besluitvorming rondom bewonersparkeervergunningen. Dit is een besluit dat uitsluitend door de gemeente wordt genomen. De VvE kan geen oordeel of bevestiging geven over het al dan niet toekennen van deze vergunningen. Bewoners dienen voor vragen hierover rechtstreeks contact op te nemen met de betreffende afdeling van de gemeente."}, {"v": "Wanneer word ik geïnformeerd over geplande werkzaamheden aan het complex?", "a": "Wij streven ernaar om eigenaren minimaal twee weken van tevoren te informeren over de uitvoering van werkzaamheden, zodat iedereen tijdig rekening kan houden met eventuele overlast of parkeersituaties."}, {"v": "Is het mogelijk om een na-inspectie of controlemeting in te plannen na eerdere herstelwerkzaamheden aan een lekkage?", "a": "Het is mogelijk om een offerte aan te vragen bij het bedrijf dat de oorspronkelijke lekdetectie heeft uitgevoerd. Op die manier kan er een nieuwe meting worden gedaan en kunnen de waardes worden vergeleken met de eerdere resultaten."}, {"v": "Wat is de procedure bij de VvE voor het verlenen van toestemming voor de aanleg van een glasvezelnetwerk?", "a": "Zodra het plaatsingsdocument van de netwerkbeheerder binnen is, wordt er een e-mail naar alle eigenaren gestuurd om te peilen of er bezwaar is tegen het verlenen van toestemming of wordt er gekeken naar een eerder verleend akkoord in de voorgaande vergadering. Wanneer er geen bezwaren zijn, kan de toestemming formeel worden gegeven en kan de netwerkbeheerder verder met de aansluiting."}, {"v": "Is onderhuur toegestaan binnen de VvE en met wie wordt hierover gecommuniceerd?", "a": "Als er sprake is van onderhuur, dan is dat conform de splitsingsakte over het algemeen niet toegestaan. De VvE heeft hierbij geen directe relatie met de huurders, maar uitsluitend met de eigenaar. Vanuit de VvE kan de eigenaar schriftelijk worden aangesproken op dit feit."}, {"v": "Waar kan ik de geveltekeningen en plattegronden van het complex vinden?", "a": "De plattegronden (splitsingstekeningen) zijn terug te vinden in de splitsingsaktes van de VvE."}, {"v": "Hoe kan ik een nieuw naamplaatje voor bij de voordeur aanvragen?", "a": "U kunt een verzoek voor een nieuw naamplaatje indienen via het Totaal Portaal. In dit digitale portaal kunt u reparatieverzoeken en overige meldingen doorgeven. Onze beheerder zal de aanvraag vervolgens in behandeling nemen en de benodigde partijen inschakelen."}, {"v": "Kan ik als bewoner namens de VvE subsidie aanvragen?", "a": "Als u subsidie wilt aanvragen namens de VvE kan u dit als bewoner doorgaans niet zelf doen."}, {"v": "Is een inspectie ter plaatse door aannemers betrouwbaarder voor het uitbrengen van een juiste offerte dan enkel het gebruik van foto's?", "a": "Inspectie ter plaatse is de voorkeur. Om onduidelijkheden te voorkomen en een juiste offerte op te stellen, wordt aan aannemers gevraagd om op locatie een afspraak te maken zodat zij gezamenlijk de situatie kunnen bekijken en de offerte hierop kunnen aanpassen."}, {"v": "Is een huurder verplicht zich te melden bij de VvE?", "a": "Wanneer er sprake is van verhuur, dient de huurder zich als gebruiker te melden in de zin van het reglement. De huurder moet zich houden aan de regels van de VvE om wantrouwen en onrust bij omwonenden te voorkomen."}, {"v": "Is het mogelijk om de servicevorm van een lopend onderhoudscontract voor technische systemen aan te passen?", "a": "Aan het einde van het eerste contractjaar kan er worden besloten of de uitgebreide service wordt voortgezet, of dat het contract wordt aangepast naar een lichtere vorm."}, {"v": "Wat kan de VvE doen als er structureel scooters of bromfietsen verkeerd worden geparkeerd bij de ingang van het complex?", "a": "Wanneer berichten naar bewoners geen effect hebben, kan de VvE besluiten om fysieke maatregelen te nemen zoals het plaatsen van een parkeerverbodsbord en het aanbrengen van witte belijning (bijvoorbeeld een kruis) op de grond. Indien het voertuig niet van een bewoner is en blijft staan, kan er contact worden opgenomen met de gemeente om dit verder op te pakken."}, {"v": "Kan Totaal VvE Beheer zomaar telefoonnummers van contactpersonen of uitvoerders verstrekken?", "a": "Nee, Totaal VvE Beheer mag telefoonnummers niet zomaar verstrekken aan derden."}, {"v": "Biedt de VvE beheerder ondersteuning bij kleine klusjes in de woning, zoals het ophangen van rolgordijnen?", "a": "Hoewel dit normaal gesproken geen VvE-klus is, kan de beheerder u in contact brengen met een externe partij die dergelijke werkzaamheden kan uitvoeren."}, {"v": "Wat moet ik doen als er na werkzaamheden door een externe partij (zoals rioolservice) nog steeds klachten zijn zoals stankoverlast?", "a": "Wanneer er na uitgevoerde werkzaamheden nog steeds klachten zijn, adviseren wij u om direct contact op te nemen met het uitvoerende bedrijf om een controle-afspraak in te plannen."}, {"v": "Is het mogelijk om een dak te isoleren zonder de bestaande dakbedekking te verwijderen?", "a": "Het is helaas niet mogelijk om het dak te isoleren zonder dat de oude dakbedekking volledig verwijderd wordt."}, {"v": "Aan welke eisen moet een offerte van een aannemer voldoen voor een subsidieaanvraag voor kozijnen?", "a": "De aannemer moet in de offerte een duidelijke tekening van de kozijnen toevoegen en de meldcodes en het aantal vierkante meters (m2) omschrijven."}, {"v": "Waar kan ik informatie vinden over subsidies voor het verduurzamen van mijn woning, zoals het vervangen van kozijnen?", "a": "U kunt informatie over landelijke subsidies vinden via de Rijksdienst voor Ondernemend Nederland (RVO) op de pagina over de ISDE-subsidie voor woningeigenaren. Daarnaast biedt de gemeente vaak specifieke subsidies en leningen aan voor duurzame maatregelen voor particulieren."}, {"v": "Vervalt de garantie op de warmtepompen als het onderhoud door een andere partij dan de oorspronkelijke installateur wordt uitgevoerd?", "a": "Wanneer er nog garantie op de warmtepompen zit, kan deze vervallen als het onderhoud door een andere partij wordt uitgevoerd. Het is daarom raadzaam om eerst te controleren of de garantieperiode nog loopt voordat er een nieuwe partij wordt ingeschakeld."}, {"v": "Waarom worden sommige ramen aan de voorzijde van een pand niet meegenomen in de collectieve offerte voor glasbewassing?", "a": "Het kan voorkomen dat ramen aan de voorzijde van een pand niet in een collectieve offerte worden opgenomen wanneer deze vanaf de openbare weg vrij toegankelijk zijn. In die gevallen kan de eigenaar zelf bepalen of en door wie hij deze ramen laat wassen."}, {"v": "Zijn aannemers of externe partijen die werkzaamheden verrichten in het gebouw verzekerd voor schade?", "a": "Bedrijven die werkzaamheden verrichten horen zakelijk verzekerd te zijn voor eventuele schade. Wanneer er sprake is van schadeherstel, is een partij vaak bereid een zeker bedrag te vergoeden. Echter, als schadeherstel leidt tot een verbetering van de eigendom (zoals het volledig vervangen van een onderdeel in plaats van enkel het herstellen van de werking), worden de volledige kosten voor een nieuw product doorgaans niet volledig gedekt."}, {"v": "Controleert de VvE regelmatig de gas- en elektra-installaties of moeten eigenaren dit zelf doen?", "a": "De gemeenschappelijke installaties worden periodiek gekeurd door een gecertificeerd installateur."}, {"v": "Is het toegestaan om vogels te voeren rondom het VvE-gebouw?", "a": "Wij verzoeken u vriendelijk om geen voedsel (zoals brood, vlees of vis) rond het gebouw of bij de in-/uitgang van de parkeergarage achter te laten. Hoewel dit vaak goed bedoeld is – bijvoorbeeld om vogels te voeren – kan het ongewenste dieren aantrekken, zoals ratten of ander ongedierte. Daarnaast kan het leiden tot vervuiling en overlast voor medebewoners."}, {"v": "Moet ik zelf nog iets regelen voor de nieuwe eigenaren na de verkoop van mijn woning?", "a": "De nieuwe eigenaren ontvangen van ons een welkomstbrief, dus u hoeft verder niets voor hen te regelen."}, {"v": "Hoe kan ik een ledenmelding doorgeven?", "a": "U kunt hiervoor het Totaal Portaal gebruiken of rechtstreeks een e-mail sturen naar uw beheerder."}, {"v": "Wie is er verantwoordelijk voor eventuele verzakkingen of structurele gevolgen na verbouwingswerkzaamheden in mijn appartement?", "a": "Als eigenaar bent u verantwoordelijk voor eventuele verzakkingen of andere structurele gevolgen die ontstaan als gevolg van de werkzaamheden die in uw appartement worden uitgevoerd. Deze verantwoordelijkheid omvat zowel directe als indirecte schade aan de structuur van het gebouw of aan omliggende appartementen, indien kan worden aangetoond dat deze schade het gevolg is van door u uitgevoerde wijzigingen (zoals het verwijderen van wanden of wijzigingen aan de draagconstructie). De Vereniging van Eigenaren (VvE) en de beheerder spelen hierin geen rol en kunnen niet aansprakelijk worden gesteld voor gebreken of gevolgen die voortvloeien uit deze werkzaamheden."}, {"v": "Wat is de procedure als een offerte van de VvE wordt aangepast na een aanvullend verzoek?", "a": "Wanneer een offerte op verzoek wordt aangepast, is er opnieuw een akkoord nodig van alle betrokken eigenaren/bestuursleden voordat de gewijzigde offerte kan worden verwerkt."}, {"v": "Wie is verantwoordelijk voor het aanpassen van het huishoudelijk reglement bij wijzigingen?", "a": "Wanneer een VvE zelf het huishoudelijk reglement heeft opgesteld, is het verstandig dat de VvE ook zelf de gewenste aanpassingen hierin doorvoert zodra dit nodig is."}, {"v": "Is schade aan het stucwerk van het plafond verzekerd onder de collectieve verzekering van de VvE?", "a": "Wanneer stucwerk is losgelaten zonder dat daar een lekkage aan vooraf is gegaan, is dit niet verzekerd onder de collectieve verzekering van de VvE."}, {"v": "Wat moet ik doen als er water op het balkon blijft staan door een verstopping?", "a": "Wanneer er water op het balkon blijft staan, is vaak het putje bij de hemelwaterafvoer (HWA) verstopt. Het is belangrijk dat dit putje vrij blijft van blaadjes en ander afval. Eigenaren dienen dit putje zelf schoon te houden om een goede afwatering te waarborgen en schade op lange termijn te voorkomen."}, {"v": "Is het mogelijk om een interne groencommissie op te richten voor het onderhoud van de VvE?", "a": "Er kan een interne groencommissie worden opgericht die op vrijwillige basis zorg draagt voor het onderhoud van het gezamenlijke groen, zoals de entreehal en de binnentuin. Hierdoor is het niet langer nodig om hiervoor een externe partij in te schakelen en kosten te maken. Indien er in de toekomst budget nodig is voor de aanschaf van materiaal of gereedschap, kan dit ter goedkeuring aan de VvE worden voorgelegd of er kan besloten worden om een mandaat af te geven."}, {"v": "Hoe worden de kosten voor onderhoud en schoonmaak verdeeld tussen appartementen en bedrijfsruimtes?", "a": "In de splitsingsakte staat precies beschreven welke appartementen en bedrijfsruimtes meebetalen aan welke onderhoudskosten. Het komt voor dat bedrijfsruimtes niet bijdragen aan de schoonmaakkosten van de algemene ruimtes, omdat zij hier geen gebruik van maken."}, {"v": "Waarom zou de verzekering schade door een lekkage niet dekken?", "a": "In bepaalde situaties is schade niet verzekerd omdat het wordt gezien als de verantwoordelijkheid van de eigenaar om te zorgen dat apparatuur, zoals een slang van een wasmachine of vaatwasser, goed is aangesloten. Bij een individuele oorzaak kan het bovendien zijn dat het eigen risico wordt doorbelast aan de veroorzaker."}, {"v": "Is het mogelijk om een onafhankelijke bouwkundige in te schakelen voor controle op uitgevoerd werk?", "a": "Het is mogelijk om een onafhankelijke bouwkundige in te schakelen om het werk te controleren, bijvoorbeeld voor een eindinspectie."}, {"v": "Wanneer kan ik een nieuwe sleutel voor de centrale toegangsdeur ophalen bij het kantoor van Totaal VvE Beheer?", "a": "Als de sleutel bijgemaakt is en op ons kantoor is aangekomen krijgt u van ons een bericht. U kunt de sleutel dan bij ons op kantoor komen halen tussen 09:00 en 16:00 op vertoon van uw ID."}, {"v": "Waarom staat er een datum voor de ledenvergadering in het portaal terwijl er nog geen uitnodiging is verstuurd?", "a": "De datum in het klantportaal is een richtdatum totdat de officiële uitnodiging is verstuurd."}, {"v": "Wat betekent foutcode E124 op een cv-ketel en wat kan ik hier zelf aan doen?", "a": "Foutcode E124 op een cv-ketel duidt vaak op een probleem met de stromingsschakelaar of een te lage waterdruk, wat de warmteafgifte verhindert. U kunt dit controleren door de cv-installatie te ontluchten en de waterdruk te controleren en eventueel bij te vullen. Als het probleem zich blijft voordoen, kan een monteur nodig zijn om de stromingsschakelaar of de aanvoersensor te inspecteren."}, {"v": "Wat moet ik doen als de politie schade heeft veroorzaakt of een nieuw slot heeft geplaatst aan mijn woning?", "a": "U kunt bij de politie een proces-verbaal of schadeclaim indienen via hun officiële website. De kosten voor een door de politie geplaatst slot kunnen helaas niet door de VvE worden vergoed."}, {"v": "Valt de deur van een schuurtje die uitkomt op een privétuin onder de verantwoordelijkheid van de VvE?", "a": "Als de deur van een schuurtje uitkomt op een privétuin, dan valt deze onder individueel eigendom en niet onder het gemeenschappelijk deel van de VvE."}, {"v": "Wat moet ik doen als er een onjuist huisnummer wordt weergegeven in het Totaal Portaal?", "a": "In het portaal hoort uw eigen huisnummer te staan. Indien dit onjuist is, wordt dit doorgegeven aan de systeembeheerder om te worden aangepast."}, {"v": "Wie is verantwoordelijk voor het onderhoud van de leidingen binnen een appartement?", "a": "De standleidingen vallen onder de VvE, maar de liggende afvoeren binnen de appartementen (zoals voor keuken of douche) zijn voor rekening van de eigenaar zelf."}, {"v": "Wie is verantwoordelijk voor achterstallig onderhoud binnen de VvE?", "a": "De VvE is zelf verantwoordelijk voor achterstallig onderhoud. De VvE bepaalt hierin de koers; de beheerder voert uit wat de VvE besluit."}, {"v": "Welke internet-aansluiting heeft mijn gebouw en hoe regel ik dit?", "a": "Meestal is er glasvezel aangelegd tot de voorkant van het pand. Of er al een aansluiting aanwezig is, kun je vaak zien in de meterkast. Je besluit als eigenaar zelf of je de aansluiting naar binnen wilt laten aanleggen; dit dien je zelf te regelen via je eigen provider."}, {"v": "Hebben verenigingsleden inspraak op besluiten over groot onderhoud of offertes?", "a": "Iedere eigenaar in een VvE heeft een bepaald aantal stemmen, vermeld in de splitsingsakte van de VvE. Op de Algemene Ledenvergadering kunnen zij deze stem uitbrengen inzake groot onderhoud of offertes die op de agenda staan."}, {"v": "Zijn alle woningen en bedrijfspanden standaard inbegrepen bij de collectieve schoonmaak en glasbewassing van de VvE?", "a": "Nee, het kan voorkomen dat bepaalde woningen of bedrijfspanden zijn uitgesloten van deelname aan de collectieve schoonmaak en glasbewassing. In dat geval is de eigenaar zelf verantwoordelijk voor het regelen en bekostigen van deze werkzaamheden."}, {"v": "Wat moet ik doen bij een vermoeden van acuut gevaar of ernstige overlast?", "a": "Bij een vermoeden van acuut gevaar of onveilige situaties kunt u het beste direct contact opnemen met de politie of de brandweer."}, {"v": "Waar moet ik rekening mee houden als ik mijn CV-ketel wil laten vervangen binnen de VvE?", "a": "Bij het vervangen van een CV-ketel moet u rekening houden met de volgende zaken: de afvoer voor rookgassen en aanvoer voor frisse lucht moeten voldoen aan de huidige veiligheidsnormen en mogen niet zonder overleg met de VvE worden aangepast, omdat ze vaak een gemeenschappelijk onderdeel vormen met andere woningen. De afvoer van het condenswater moet goed aangesloten zijn op de bestaande afvoer om lekkage of stank te voorkomen. Het wordt geadviseerd om de installatie te laten uitvoeren door een Kiwa- of InstallQ-gecertificeerd bedrijf."}, {"v": "Wat is de procedure voor het installeren van laadpalen in de parkeergarage van de VvE?", "a": "Eerst is van belang dat er door de VvE goedkeuring gegeven wordt, daarna kan er gestart worden met de benodigde documenten en checks om te bepalen of de parkeergarage aan de technische eisen voldoet."}, {"v": "Hoe wordt bepaald welke ramen door de glazenwasser worden gewassen als ik er zelf niet bij kan?", "a": "Er wordt samen met de eigenaar en de glazenwasser op locatie bekeken welke ramen niet zelf bereikbaar zijn, zodat deze kunnen worden opgenomen in de offerte voor de glazenwasser."}, {"v": "Wat zijn de voordelen van een digitale (4G) lifttelefoonmodule ten opzichte van een analoge lijn?", "a": "Een digitale 4G-module maakt de lift toekomstbestendig omdat er geen analoge lijn meer nodig is. Voordelen zijn onder andere 24/7 bereikbaarheid via een gespecialiseerde alarmcentrale, transparantie via een portaal voor monitoring en storingsmeldingen, en financiële overzichtelijkheid doordat er geen aparte telefoonfacturen meer zijn; de kosten worden vaak opgenomen in het onderhoudscontract."}, {"v": "Hoe moet ik omgaan met een gebrek aan een individueel onderdeel binnen de VvE dat door de verkopende partij afgehandeld moet worden?", "a": "U dient dit zelf kenbaar te maken bij de verkopende partij. Omdat het een individueel onderdeel binnen de VvE betreft, ligt de verantwoordelijkheid bij de eigenaar en de verkoper. Indien u bewijzen heeft door middel van een rapport, kunt u dit overleggen aan de betreffende partij om de melding te onderbouwen."}, {"v": "Waarom is de informatie in het nieuwe klantportaal nog niet volledig?", "a": "Het nieuwe portaal is op dit moment nog niet zo compleet als het uiteindelijk moet worden. De komende periode zullen er steeds meer functionaliteiten aan worden toegevoegd."}, {"v": "Wat zijn veelvoorkomende oorzaken van lekkages in de badkamer?", "a": "De meeste lekkages in de badkamer worden veroorzaakt door slechte, versleten of verouderde kitvoegen. Hoewel dit onschuldig kan lijken, kunnen dergelijke voegen leiden tot vochtpenetratie en lekkages naar ondergelegen ruimtes."}, {"v": "Heeft de beheerder een overzicht van de locaties van de meters (zoals warmte- of watermeters) in mijn woning?", "a": "Wij hebben zelf geen overzicht van de locaties van de meters in de woningen in ons bezit."}, {"v": "Hoe kan ik voorkomen dat er lekkages optreden bij de schoorstenen?", "a": "Het plaatsen van CV-kapjes op de schoorstenen kan voorkomen dat er lekkages optreden."}, {"v": "Zijn aanpassingen aan een woning (zoals een balkondeur) na oplevering gedekt door de garantie als het een wens betreft en geen gebrek?", "a": "Wanneer een bewoner een woning accepteert zoals deze is vastgelegd in het contract, zijn latere wensen voor aanpassingen (geen gebreken) niet gedekt door de garantie. Indien een bewoner zaken wenst te veranderen aan het eigen bezit, is dat toegestaan, maar zijn de kosten hiervoor voor rekening van de eigenaar zelf. Het koopcontract is hierin leidend."}, {"v": "Wat moet ik doen als de glazenwasser langskomt voor werkzaamheden?", "a": "Wij verzoeken iedereen om ervoor te zorgen dat alle ramen goed gesloten zijn en dat eventuele obstakels bij de ramen worden verwijderd, zodat de werkzaamheden zonder problemen kunnen worden uitgevoerd."}, {"v": "Wat kan ik doen als er sprake is van overlast door bouwwerkzaamheden en rommel in de gemeenschappelijke ruimtes?", "a": "Wanneer er sprake is van overlast in de gemeenschappelijke ruimtes, vragen wij u om foto’s van de huidige situatie te sturen. Op basis van dit bewijsmateriaal kunnen wij de verantwoordelijke hierop aanspreken en hen verzoeken de situatie direct op te lossen."}, {"v": "Wat moet ik doen bij zware overlast door omwonenden?", "a": "Bij zware overlast wordt geadviseerd om aangifte te doen bij de politie."}, {"v": "Is het Totaal Portaal nog in ontwikkeling en worden er nog verbeteringen doorgevoerd?", "a": "We zijn inderdaad nog bezig met de ontwikkeling van het nieuwe portaal. De basis staat, maar er wordt achter de schermen nog gewerkt aan verbeteringen, uitbreidingen en een duidelijkere manier van informatie tonen."}, {"v": "Is het toegestaan om een fatbike of de bijbehorende accu in de woning of algemene ruimtes te stallen of op te laden?", "a": "Het is niet toegestaan om fietsen of accu’s in de woning of algemene ruimtes te stallen of op te laden. Het opladen en opslaan van een (fatbike) accu in de woning brengt risico’s met zich mee; bij oververhitting of een defect kan een lithium-ionaccu brand veroorzaken, wat gevolgen heeft voor het hele gebouw."}, {"v": "Moet ik overlast in de gemeenschappelijke ruimtes melden?", "a": "Ja, het is goed om overlast of onjuist gebruik van gemeenschappelijke ruimtes altijd te melden bij de VvE beheerder, zodat hier actie op ondernomen kan worden richting de veroorzaker."}, {"v": "Met welke zaken moet ik rekening houden bij een verbouwing in het VvE-complex?", "a": "Bij een verbouwing gelden diverse regels om overlast te beperken en de kwaliteit van het gebouw te waarborgen. Belangrijke punten zijn: gebruik een gesloten container voor bouwafval, gebruik de lift niet voor het afvoeren van puin of het verplaatsen van zware materialen, en houd u aan de vastgestelde verbouwtijden (verbouwen op zondag is vaak niet toegestaan). Meld de start- en einddatum van de verbouwing bij de VvE in verband met de toegang van werklieden tot het gebouw. Zorg dat het complex dagelijks schoon wordt achtergelaten en deel contactgegevens voor eventuele klachten. Bij werkzaamheden aan de meterkast moet altijd een gecertificeerd bedrijf worden ingeschakeld. Indien het water moet worden afgesloten, dient dit minimaal 10 werkdagen van tevoren te worden gemeld. Tot slot is er vaak een wettelijke eis voor de isolatiewaarde van de ondervloer om geluidsoverlast te voorkomen."}, {"v": "Hoe worden eigenaren geïnformeerd over belangrijke stemmingen op de agenda?", "a": "Als er belangrijke punten op de agenda staan waar over gestemd moet worden en die niet bij iedereen bekend zijn, worden eigenaren hier per e-mail over geïnformeerd. Punten die jaarlijks terugkomen en geen extra uitleg behoeven, worden tijdens de vergadering behandeld."}, {"v": "Waarom wordt er gebruikgemaakt van BCC in e-mails in plaats van dat iedereen elkaars e-mailadres kan zien?", "a": "Wij maken vaak gebruik van BCC zodat niet iedereen elkaars e-mailadres kan zien, aangezien veel eigenaren dit vanwege privacyoverwegingen niet wenselijk vinden. Daarnaast voorkomt het dat eigenaren onbedoeld op 'allen beantwoorden' klikken voor zaken die niet voor iedereen relevant zijn. Indien de volledige VvE hier anders over denkt en expliciet aangeeft dat de e-mailadressen gedeeld mogen worden, kan hiervan worden afgeweken."}, {"v": "Worden de kosten voor de aanschaf en installatie van een airconditioning betaald vanuit het VvE-budget?", "a": "De kosten voor het aanschaffen en installeren van een airconditioner zijn een individuele aangelegenheid; de eigenaar dient dit zelf te betalen."}, {"v": "Wat moet ik doen als mijn deurbel of intercom niet meer werkt?", "a": "Wanneer er problemen zijn met de deurbel of intercom, is het voor de reparateur handig om vooraf een foto te ontvangen van het toestel zodat het merk en type bepaald kunnen worden. Op basis daarvan kan de juiste apparatuur of vervangende onderdelen worden meegenomen voor de reparatie."}, {"v": "Wat moet ik doen bij vochtschade in de flat die van buitenaf lijkt te komen?", "a": "Bij vochtschade kunt u contact met ons opnemen. Wij zullen dan een aannemer inschakelen om de situatie te beoordelen en het probleem op te lossen."}, {"v": "Zijn er kosten verbonden aan de goedkeuring voor het aanleggen van glasvezel tot de voorkant van het pand?", "a": "Hier zijn geen kosten aan verbonden. De eigenaar kan daarna zelf kiezen om de glasvezel aan te leggen in de woning."}, {"v": "Wat mag er wel en niet worden doorgespoeld in het toilet om verstoppingen te voorkomen?", "a": "Alleen toiletpapier mag worden doorgespoeld. Er mogen geen doekjes, schoonmaak- of vochtige tissues, vetresten of ander afval via het toilet worden geloosd om schade, overlast en onnodige kosten te voorkomen."}, {"v": "Mag ik als eigenaar zelf beplanting, zoals een boom, snoeien die voor mijn woning staat?", "a": "Wat betreft het snoeien van beplanting: indien de beplanting eigendom is van de VvE mag u deze snoeien. Echter, indien de beplanting eigendom is van de gemeente, kan de VvE hier geen toestemming voor geven."}, {"v": "Biedt een opstalverzekering dekking voor lekkages veroorzaakt door bouwkundige gebreken of bouwfouten?", "a": "De opstalverzekering biedt in de regel geen dekking voor schade die voortvloeit uit bouwfouten of bouwkundige gebreken. In dergelijke gevallen ligt de verantwoordelijkheid voor herstel doorgaans bij de aannemer. Bovendien kan het indienen van dergelijke claims leiden tot een verhoging van het eigen risico of de premie van de VvE."}, {"v": "Wat moet ik doen als er een lekkage is bij de hemelwaterafvoer (HWA) die zorgt voor vochtplekken in de woning?", "a": "Wanneer een defect aan de hemelwaterafvoer leidt tot directe schade zoals vochtplekken, is het raadzaam om op korte termijn een noodoplossing te laten realiseren. Wij kunnen een aannemer inschakelen om dit op zeer korte termijn uit te voeren om verdere schade te voorkomen."}, {"v": "Wat moet ik doen als ik last heb van een rioleringslucht uit het afvoerputje van de douche?", "a": "Peil eerst bij de andere bewoners of zij dezelfde klachten ervaren. Indien er meerdere meldingen zijn of het probleem aanhoudt, kan er verder onderzoek worden gedaan."}, {"v": "Hoe lang is een taxatierapport voor de verzekering geldig?", "a": "Een rapport is 6 jaar geldig wanneer er een index op de polis van toepassing is."}, {"v": "Blijft de opstalverzekering doorlopen na de opzegging van het beheercontract?", "a": "Ja, de opstalverzekering blijft gewoon doorlopen."}, {"v": "Hoe wordt de verzekeringspremie over de verschillende appartementsrechten binnen een VvE verdeeld?", "a": "In principe gaat de premie naar rato van het aandeel van het appartement in de gemeenschap. Indien gewenst kan de verzekeraar worden gevraagd om een eventuele meerpremie (bijvoorbeeld door een verhoogd risicoprofiel) te specificeren, zodat dit specifiek kan worden doorbelast."}, {"v": "Wat moet ik doen als ik vermoed dat het centrale ventilatiesysteem van het gebouw niet goed functioneert, bijvoorbeeld door kookluchten of rook van buren in mijn woning?", "a": "Wanneer er aanwijzingen zijn dat het centrale ventilatiesysteem of de betreffende ventilatiekolom niet naar behoren functioneert, kan de VvE beheerder een specialist inschakelen om een controle uit te voeren en te laten onderzoeken of er een technisch defect is of dat het systeem gereinigd moet worden."}, {"v": "Wat kan de oorzaak zijn van schimmelvorming in de woning ondanks goed ventileren?", "a": "Schimmelvorming kan worden veroorzaakt door koudebruggen in de constructie van het gebouw. In dergelijke gevallen is er vaak niet direct een bouwkundige oplossing beschikbaar en blijft het advies om extra goed te blijven ventileren om vochtproblemen te minimaliseren."}, {"v": "Moet de opstalverzekering van de VvE worden aangepast bij een uitbreiding van het woonoppervlak, bijvoorbeeld door de opbouw van een extra etage of dakopbouw?", "a": "Wanneer het woonoppervlak van een appartement toeneemt door bijvoorbeeld een dakopbouw of de realisatie van een extra etage, moet dit worden doorgegeven aan de verzekeraar. De verzekeringspolis moet hierop worden aangepast om onderverzekering te voorkomen."}, {"v": "Wat is de status van een gemelde schade en hoe verloopt de beoordeling door de verzekeraar?", "a": "Nadat een schade is gemeld bij de verzekeraar, zal deze de melding beoordelen. De doorlooptijd van deze beoordeling kan variëren, mede afhankelijk van drukte en feestdagen. Zodra er een reactie van de verzekeraar is ontvangen, wordt u hierover direct geïnformeerd."}, {"v": "Wat kan een VvE doen als een externe partij slecht werk levert en niet reageert op herstelverzoeken?", "a": "In het geval dat een externe partij gebrekkig werk levert en niet reageert op contactpogingen, kan er een aangetekende brief worden gestuurd met een ingebrekestelling en een sommatie om de gebreken binnen een redelijke termijn (bijvoorbeeld 2 maanden) op te lossen. Indien hier geen reactie op komt, kan worden overwogen om een advocaat in te schakelen, hoewel de kosten hiervan moeten worden afgewogen tegen de verwachte opbrengst. Het wordt ten zeerste geadviseerd om als VvE een rechtsbijstandverzekering af te sluiten."}, {"v": "Moeten kopers bij het oprichten van een VvE ook een machtigingsformulier tekenen?", "a": "Het machtigingsformulier hoeft niet door de kopers getekend te worden; dit is alleen nodig van de huidige eigenaar."}, {"v": "Beschikt de vaste beheerder/accountmanager over juridische en technische kennis?", "a": "De accountmanager cq beheerder beschikt tot een bepaalde hoogte over juridische en technische kennis en kan indien nodig een beroep doen op collega's."}, {"v": "Zijn de benodigde VvE-stukken beschikbaar voor de verkoop van een complex dat door jullie wordt beheerd?", "a": "Ja, voor de complexen die wij in beheer hebben zijn de verkoopstukken beschikbaar, met uitzondering van de meest recente jaarrekening als deze nog niet is vastgesteld."}, {"v": "Met wie kan ik contact opnemen voor (vragen over) mijn VvE?", "a": "Totaal VvE Beheer is de beheerder van uw VvE. In het portaal staat vermeld wie de vaste beheerder en het directe aanspreekpunt voor uw VvE is; u kunt deze beheerder rechtstreeks mailen voor een snelle opvolging. Indien het e-mailadres van uw beheerder niet bij u bekend is, kunt u gebruikmaken van het algemene e-mailadres info@totaalvve.nl."}, {"v": "Wat moet ik doen als er lekkage optreedt die mogelijk gerelateerd is aan eerder uitgevoerde werkzaamheden door een aannemer?", "a": "Wanneer er sprake is van een lekkage na werkzaamheden, kan de VvE beheerder contact opnemen met de uitvoerende partij om de situatie te laten beoordelen. Indien de schade voortkomt uit een gebrek in de uitgevoerde werkzaamheden (zoals een scheur in een coating), kan herstel mogelijk onder garantie plaatsvinden. Let wel op dat werkzaamheden die oorspronkelijk niet in de opdracht waren inbegrepen, zoals het impregneren van gevels, doorgaans buiten deze garantie vallen. Houd rekening met een wachttijd vanwege de drukte bij aannemers."}, {"v": "Hoe worden eigenaren geïnformeerd over preventieve maatregelen en verzekeringsclausules?", "a": "Preventieve maatregelen en verzekeringsclausules worden expliciet benoemd tijdens de Algemene Ledenvergadering (ALV) en opgenomen in de notulen om eigenaren hiervan op de hoogte te stellen."}, {"v": "Biedt de energieleverancier waar de contracten worden ondergebracht ook een app die inzicht geeft in het verbruik?", "a": "Wij brengen veelal contracten onder bij Audax Renewables maar het is niet altijd direct bekend of zij ook een app hebben welke inzicht geeft in verbruik; dit wordt per situatie uitgezocht."}, {"v": "Waarom staat er soms geen aandeelvermelding voor een berging in de splitsingsakte?", "a": "Wanneer er in de splitsingsakte geen aandeelvermelding van een berging staat, betekent dit dat de berging geen verschuldigde bijdrage heeft binnen de VvE."}, {"v": "Is het mogelijk voor een lid van de technische commissie om zelf benodigdheden aan te schaffen en deze te declareren bij de VvE?", "a": "Ja, dat is mogelijk. Indien u zelf aankopen doet voor de VvE, kunt u de bon insturen. Wij zorgen er vervolgens voor dat het aankoopbedrag zo snel mogelijk op uw rekening wordt teruggestort."}, {"v": "Is het mogelijk om de vergaderingen van een onder- en hoofdsplitsing apart van elkaar te houden, of is het raadzaam om ze gezamenlijk te organiseren?", "a": "In principe is het raadzaam om de vergadering gezamenlijk te houden met alle eigenaren van zowel de bovenwoningen als de benedenwoningen. Indien tijdens of na de vergadering blijkt dat hier bezwaar tegen is, kan er in de toekomst voor gekozen worden om eerst met de ondersplitsing te vergaderen en aansluitend met de hoofdsplitsing."}, {"v": "Is het mogelijk om zelf een aannemer of partij aan te dragen voor het opstellen van een offerte voor planmatig onderhoud?", "a": "Ja, het is mogelijk om zelf een partij aan te dragen voor het opvragen van een offerte. Belangrijk hierbij is dat de betreffende aannemer aantoonbaar gespecialiseerd is in de specifieke werkzaamheden (zoals gevelwerk of balkoncoatings) om de kwaliteit te waarborgen."}, {"v": "Wanneer komt de aannemer langs voor de reparatie nadat een melding is doorgegeven?", "a": "In verband met drukte bij aannemers kan er geen exacte zekerheid worden gegeven wanneer men kan langskomen. Indien u na enkele dagen nog niets heeft vernomen van de aannemer voor het maken van een afspraak, kunt u contact opnemen."}, {"v": "Worden reparaties aan de buitenzijde en herstelwerkzaamheden aan de binnenzijde na een lekkage tegelijkertijd uitgevoerd?", "a": "Het is aan te bevelen om de schade aan de binnenzijde pas te laten opnemen zodra zeker is dat de oorzaak van de lekkage aan de buitenzijde is verholpen en de binnenzijde de kans heeft gehad om op te drogen."}, {"v": "Dienen betonnen dorpels bij een VvE gecoat te worden voor onderhoud?", "a": "Ja, betonnen dorpels (onderdeel van gevels, balkons) vallen meestal onder de verantwoordelijkheid van de VvE voor groot onderhoud, inclusief preventieve bescherming zoals coating om betonrot te voorkomen, wat essentieel is voor de veiligheid en levensduur van het gebouw."}, {"v": "Wat moet ik doen als er tijdens een bouwkundige inspectie voor het MJOP een lekkage wordt geconstateerd?", "a": "Wanneer er tijdens een inspectie voor het MJOP een lekkage wordt geconstateerd, zal de bouwkundige de beheerder informeren. In overleg met de bewoner kan er vervolgens een aannemer worden ingeschakeld om de (vermoedelijke) oorzaak van de lekkage te verhelpen of een noodreparatie uit te voeren."}, {"v": "Wat kan ik doen als het niet lukt om contact te krijgen met een andere beheerder of instantie voor het beëindigen van het beheer?", "a": "Indien telefonisch of per e-mail geen contact verkregen kan worden, adviseren wij om een formeel schrijven te verzenden. Dit dient zowel per e-mail als aangetekend per post te gebeuren. Eventueel kan een voorbeelddocument worden gebruikt als basis voor deze correspondentie."}, {"v": "Is het noodzakelijk om een offerte fysiek te printen, te tekenen en weer te scannen voor akkoord?", "a": "U kunt gewoon akkoord geven per e-mail."}, {"v": "Is het mogelijk om bij het vervangen van een collectieve cv-ketel voor elk appartement een aparte ketel of meter te installeren?", "a": "Vanwege de technische aard van deze vraag adviseren wij om direct contact op te nemen met de installateur of leverancier. Zij kunnen u adviseren over de technische (on)mogelijkheden binnen uw specifieke complex."}, {"v": "Wanneer vindt over het algemeen de kennismaking met een nieuwe beheerder plaats?", "a": "De kennismaking met de nieuwe beheerder vindt doorgaans plaats tijdens de eerstkomende algemene ledenvergadering."}, {"v": "Maakt een uitbouw in de achtertuin van een woning op de begane grond onderdeel uit van de VvE?", "a": "Een uitbouw maakt doorgaans geen onderdeel uit van de VvE. Deze staat dan ook niet vermeld in de splitsingsakte. Mocht deze gewijzigd zijn en de uitbouw is toegevoegd aan de splitsingsakte dan wordt hier ook vermeld wie verantwoordelijk is voor de kosten van het onderhoud hiervan."}, {"v": "Wanneer kan de vervolgschade binnen in de woning worden opgenomen en hersteld na een lekkage?", "a": "Het is raadzaam om de schade na ongeveer 1 à 1,5 maand te laten opnemen voor de verzekering. Op deze manier heeft de ondergrond voldoende tijd om te drogen voordat het herstel plaatsvindt."}, {"v": "Valt het oplossen van geluidsoverlast van buren onder de verantwoordelijkheid van de VvE?", "a": "De primaire verantwoordelijkheid voor geluidsoverlast valt niet onder de VvE. Geluidsoverlast moet primair onderling opgelost worden als buren. Het eerste advies is te allen tijde het gesprek aan te gaan met uw buur."}, {"v": "Welk mandaat heeft de beheerder of dakdekker bij (nood)reparaties aan het dak?", "a": "Dit verschilt per vereniging; de beheerder krijgt vaak een specifiek mandaat om bij lekkages direct een onderzoek te laten uitvoeren en een (nood)oplossing te bieden. De dakdekker koppelt de bevindingen terug aan de beheerder. Indien herstel binnen het bestuurdersmandaat valt, kan dit direct worden uitgevoerd. Voor uitgebreid herstel buiten het mandaat wordt een offerte opgesteld die ter beoordeling aan de eigenaren wordt voorgelegd. Indien werkzaamheden betrekking hebben op aangrenzende panden, vindt uitvoering plaats in overleg met de buren."}, {"v": "Wat zijn de wettelijke verplichtingen voor een VvE bij activatie?", "a": "Voor een VvE gelden een aantal wettelijke verplichtingen, te weten: de inschrijving bij de Kamer van Koophandel (KvK), het afsluiten van een collectieve opstal- en aansprakelijkheidsverzekering en het aanhouden van een minimale reservering voor onderhoud."}, {"v": "Is het toegestaan om mijn appartement te verhuren en biedt de verzekeringspolis van de VvE dan nog dekking?", "a": "Er zijn vanuit de VvE of de verzekeraar geen belemmeringen voor het verhuren van een appartement, zolang het gaat om reguliere verhuur. Andere vormen van verhuur, zoals kamerverhuur, verhuur via Airbnb of shortstay, zijn niet toegestaan."}, {"v": "Hoe wordt de afwikkeling van de kosten voor de centrale verwarming en nutsvoorzieningen geregeld wanneer dit niet collectief in de splitsingsakte is vastgelegd?", "a": "Wanneer de nutsvoorzieningen niet collectief in de splitsingsakte van de VvE zijn geregeld, valt de afhandeling en beantwoording hiervan buiten het beheer van de VvE en dient dit door de desbetreffende vastgoedbeheerder of verhuurder te worden opgepakt."}, {"v": "Is de VvE aansprakelijk voor schade aan een voertuig als gevolg van onjuist gebruik van de garagedeur?", "a": "De VvE accepteert geen aansprakelijkheid voor schade die is veroorzaakt door onjuist gebruik van de garage, de garagedeur of de bijbehorende bedieningselementen. Indien schade aan de deur ontstaat door onjuist gebruik door een gebruiker of huurder, zal de VvE deze partij aansprakelijk stellen voor de herstelkosten."}, {"v": "Worden claims nog gedekt nadat de Aansprakelijkheidsverzekering voor Bedrijven (AVB) is beëindigd?", "a": "Voor een aansprakelijkheidsverzekering geldt doorgaans dat een claim niet gedekt wordt als deze na de beëindigingsdatum van de verzekering wordt gemeld, zelfs als de gebeurtenis plaatsvond toen de verzekering nog liep. Het is daarom belangrijk om mogelijke schadegevallen of omstandigheden die tot een claim kunnen leiden tijdig te melden voor de einddatum van de polis."}, {"v": "Wie draagt zorg voor de betaling van de verzekeringspremie van de VvE?", "a": "Totaal VvE Beheer draagt zorg voor de betaling van de verzekeringspremie aan de verzekeringstussenpersoon."}, {"v": "Wat houdt de clausule 'Duurzaamheid' in bij de gebouwenverzekering van de VvE?", "a": "De clausule 'Duurzaamheid' dekt de extra kosten die na schade gemaakt moeten worden om het herstel op een duurzame wijze uit te voeren. Deze extra kosten worden vergoed tot een bepaald percentage van het verzekerd bedrag."}, {"v": "Wie fungeert er als voorzitter tijdens de vergadering van de VvE?", "a": "Aan het begin van elke vergadering dient een voorzitter te worden benoemd. Het is gebruikelijk dat de beheerder deze rol op zich neemt om het proces professioneel te begeleiden, zeker wanneer er vanuit de eigenaren geen animo voor is. De beheerder stuurt de uitnodigingen en agenda's uit, terwijl het bestuur verantwoordelijk blijft voor de inhoud. Bij veel beheerders is deze begeleiding inbegrepen in de dienstverlening."}, {"v": "Wat moet ik doen als de deurdranger de deur niet goed sluit, bijvoorbeeld bij wind of als deze niet goed in het slot valt?", "a": "Wanneer een deur niet goed sluit, kan dit liggen aan de afstelling van de deurdranger, bijvoorbeeld als het laatste 'zetje' niet krachtig genoeg is bij wind. In dergelijke gevallen kan de beheerder een uitvoerder inschakelen om de afstelling te controleren en te corrigeren, zeker als er nog sprake is van garantie op het geleverde werk."}, {"v": "Worden extra bijdragen voor verzekeringspremies specifiek verwerkt in de administratie en de jaarrekening?", "a": "Wanneer een extra bijdrage specifiek bestemd is voor de verzekeringspremie, wordt dit als zodanig verwerkt in de administratie en de jaarrekening van de VvE."}, {"v": "Is Totaal VvE Beheer aanwezig wanneer bedrijven de locatie bezoeken om offertes op te maken voor werkzaamheden?", "a": "Nee, wij zijn bij de opname van offertes doorgaans niet aanwezig. Wij wijzen u erop dat de opname ten behoeve van de offerte wordt uitgevoerd op basis van de tijdens het bezoek waarneembare situatie en de door de vereniging aangewezen en toegankelijke onderdelen. Van eigenaars wordt verwacht dat zij tijdens de opname eventuele relevante aandachtspunten, wensen of bijzonderheden tijdig kenbaar maken en zorgdragen voor de benodigde toegang. Na afronding van de opname en het uitbrengen en delen van de offerte kunnen aanvullingen of wijzigingen die voortkomen uit niet eerder gemelde of niet toegankelijke onderdelen leiden tot extra (opname)kosten, aangepaste offerte en vertraging in de voortgang van het traject."}, {"v": "Wanneer en hoe worden begeleidingskosten bij schade- of onderhoudswerkzaamheden bepaald?", "a": "Onderhouds- en schadewerkzaamheden kunnen desgewenst door ons kantoor worden begeleid. Afhankelijk van de grootte van een project kan hier op verzoek van de VvE een voorstel voor worden gedaan. Deze kosten worden enkel in rekening gebracht indien begeleiding van dit onderhoud of schade vanuit ons kantoor gewenst is. Te denken valt aan de aanvraag en beoordeling van offertes, het maken van een gunningsadvies, een kick-off meeting met de gekozen aannemer, één of meerdere tussentijdse controles/keuringen tijdens/na uitvoer van het werk en het uitvoeren van een opleverkeuring. Wij brengen deze kosten niet in rekening als voornoemde werkzaamheden niet van ons worden verlangd."}, {"v": "Hoe worden bewoners geïnformeerd over de definitieve startdatum van geplande onderhoudswerkzaamheden aan het pand?", "a": "De eigenaren en bewoners worden door de uitvoerende aannemers rechtstreeks geïnformeerd over de definitieve startdatum en de verwachtingen omtrent de werkzaamheden."}, {"v": "Is voor het vervangen van balkons (binnen een VvE) een vergunning vereist?", "a": "Het vervangen van balkons is altijd vergunningsplichtig."}, {"v": "Wat is er nodig om een goede vergelijking te maken tussen verschillende energieleveranciers?", "a": "Om een goede vergelijking te kunnen maken tussen energieleveranciers zijn de kale leveringstarieven (exclusief btw, energiebelasting en netbeheerkosten) van de huidige of alternatieve aanbiedingen nodig."}, {"v": "Kan de VvE gebruikmaken van specifieke energietarieven via het kantoor van de beheerder?", "a": "Mocht de VvE een contract via onze geselecteerde partner willen afsluiten, dan moet dit via ons kantoor worden gefaciliteerd om gebruik te kunnen maken van de betreffende collectieve tarieven. Uiteraard staat het contract alsmede de facturen op naam van de VvE zelf."}, {"v": "Welke specialistische en financiële ondersteuning biedt Totaal VvE Beheer bij groot onderhoud?", "a": "Totaal VvE Beheer beschikt over een specialistisch loket voor de technische waarborging van (groot) onderhoud en de financiële waarborging van de uitvoering hiervan met behulp van nationale en lokale leningen en/of subsidies."}, {"v": "Wat moet ik doen als er houtworm wordt aangetroffen in een gezamenlijke ruimte van de VvE?", "a": "U kunt dit melden bij de VvE beheerder zodat er actie ondernomen kan worden. Om de ernst van de situatie te beoordelen en een effectief behandelplan op te stellen, ontvangen wij graag, indien beschikbaar, foto's van de aangetroffen houtworm."}, {"v": "Is het mogelijk om een jaarrekening te ontvangen van een VvE die net is opgericht?", "a": "Wanneer een VvE pas officieel van start gaat (bijvoorbeeld vanaf de startdatum van de betaling van de bijdragen), kan er nog geen jaarrekening over het voorgaande jaar worden overlegd. De VvE moet eerst een volledige boekhoudcyclus hebben doorlopen."}, {"v": "Wat gebeurt er met de overige appartementsrechten en stemrechten als een appartementsrecht wordt onderverdeeld in twee woningen na een transformatie?", "a": "Bij een splitsing van een appartementsrecht in meerdere woningen wijzigt de omvang van de overige appartementsrechten in het gebouw niet. Ook de aandelen van de andere appartementsrechten en het bijbehorende stemrecht veranderen niet bij een dergelijke wijziging van de splitsingsakte."}, {"v": "Wat zijn de SLV-kosten op een factuur voor liftonderhoud?", "a": "De SLV zijn de kosten verbonden aan de spreekluisterverbinding van de lift."}, {"v": "Hoe wordt de decharge van het bestuur over het gevoerde beleid van voorgaande jaren geregeld op de vergadering?", "a": "Het verlenen van decharge aan het bestuur over het gevoerde beleid vindt plaats door het jaarverslag over het voorgaande jaar goed te keuren tijdens de algemene ledenvergadering. Dit punt wordt als vast onderdeel op de agenda van de vergadering geplaatst."}, {"v": "Is het mogelijk om een specifiek verzoek of agendapunt, zoals de installatie van automatische deursluiters ter voorkoming van geluidsoverlast, te bespreken tijdens de Algemene Ledenvergadering?", "a": "Uiteraard is het geen enkel probleem om specifieke verzoeken of verbeterpunten met betrekking tot het complex te bespreken tijdens de aankomende ledenvergadering."}, {"v": "Wat moet er gebeuren met de conceptnotulen wanneer de breukdelen van een VvE worden aangepast naar aanleiding van een nieuwe splitsingsakte?", "a": "Wanneer de breukdelen van een VvE veranderen, worden de conceptnotulen aangepast om de nieuwe breukdelen en de bijbehorende nieuwe periodieke bijdragen vast te leggen."}, {"v": "Is het mogelijk om de begroting of notulen aan te passen wanneer elk appartement een eigen watermeter krijgt en de collectieve watervoorschotten komen te vervallen?", "a": "Ja, de documenten kunnen worden aangepast om de nieuwe breukdelen en bijdragen te verwerken, waarbij het voorschot voor water wordt verwijderd."}, {"v": "Is het wassen van de ramen inbegrepen in de VvE-bijdrage?", "a": "Het wassen van de ramen is niet standaard inbegrepen in de VvE. Eigenaren die hier gebruik van maken, hebben dit doorgaans individueel geregeld met de glazenwasser."}, {"v": "Is het gebruikelijk dat een kozijnleverancier om een schriftelijke machtiging van het VvE-bestuur of de beheerder vraagt voordat zij een offerte uitbrengen?", "a": "Hoewel dit verzoek niet erg gebruikelijk is voor een oriënterende offerteaanvraag, kunt u via e-mail aan de leverancier laten weten dat u vanuit de VvE toestemming heeft om de offerte op te vragen. Indien gewenst kan de beheerder namens de VvE deze toestemming formeel bevestigen."}, {"v": "Waarom heeft de VvE beheerder de contactgegevens van huurders nodig?", "a": "De contactgegevens van huurders worden door de VvE beheerder uitsluitend gebruikt in het geval van een echt noodgeval."}, {"v": "Is het mogelijk om de verzekeringsdekking van de VvE uit te breiden met een rechtsbijstandverzekering?", "a": "Het is mogelijk om namens de Vereniging van Eigenaren een uitbreiding van de dekking voor rechtsbijstand aan te vragen bij de verzekeraar. Na de aanvraag zal de verzekeraar een nieuw polisblad inclusief de eventuele meerpremie verstrekken."}, {"v": "Hoe worden de kosten verdeeld voor onderhoud aan een gemeenschappelijke goot tussen twee verschillende VvE's?", "a": "Wanneer een goot eigendom is van twee verschillende VvE's, dienen de kosten voor het onderhoud door beide partijen voor 50% te worden gedragen."}, {"v": "Is het mogelijk om correspondentie met betrekking tot het beheer van een woning naar een extern kantoor of beheerder te laten sturen?", "a": "Ja, het mailadres voor correspondentie kan worden genoteerd en aangepast in de administratie."}, {"v": "Is het mogelijk om in de jaarafrekening de kostenposten voor (groot) onderhoud per onderdeel inzichtelijk te maken, zoals voor schilderwerk of kelders?", "a": "M.b.t. groot onderhoud kan dat inzichtelijk worden gemaakt in de jaarrekening. Het is dan wel noodzakelijk dat de begroting vooraf ook deze specifieke posten bevat, aangezien er een vergelijking wordt gemaakt tussen begrote en gerealiseerde kosten. Als u per onderdeel een specificatie wenst, is het raadzaam dit al direct in de begroting vast te leggen."}, {"v": "Wat moet ik doen als ik een uitnodiging voor de ALV heb ontvangen zonder agenda?", "a": "In dergelijke gevallen kunt u de uitnodiging en agenda opvragen bij de VvE-beheerder. De agenda is meestal te vinden op de tweede pagina van de uitnodiging."}, {"v": "Kan ik een offerte voor het reinigen en impregneren van mijn gevel laten goedkeuren door de VvE?", "a": "De offertes kunnen worden meegenomen in de vergadering. Het is echter de vraag of dit niet voor de gehele VvE moet gebeuren, aangezien het plaatselijk impregneren van een deel van de gevel vaak niet aan te raden is."}, {"v": "Wanneer kan er iemand komen kijken naar gebreken aan de lateien van het pand?", "a": "U kunt hiervoor foto's sturen zodat we de situatie kunnen beoordelen. Daarnaast kunnen dergelijke onderhoudszaken ter sprake worden gebracht tijdens de Algemene Ledenvergadering (ALV)."}, {"v": "Worden bestaande schoonmaakcontracten automatisch overgenomen bij de activering van een nieuwe VvE?", "a": "Indien er bij de overdracht niets is vermeld over bestaande contracten, zullen er nieuwe offertes opgesteld moeten worden die door de Algemene Ledenvergadering (ALV) goedgekeurd dienen te worden."}, {"v": "Is het mogelijk om inzage te krijgen in offertes voor herstelwerkzaamheden naar aanleiding van schade aan het pand?", "a": "Nadat de offerte voor de schade is ontvangen, zal deze naar de betrokkenen worden verzonden zodat deze kritisch kan worden bekeken voordat er verdere stappen worden ondernomen."}, {"v": "Hoe wordt de datum voor de uitvoering van het ladderrecht bepaald in de communicatie naar de buren?", "a": "In de brief aan de buren kan de gelegenheid worden gegeven om zelf een datum voor te stellen voor het uitoefenen van het ladderrecht, zodat de uitvoerende partij zich hierop kan aanpassen."}, {"v": "Welke stappen moeten er ondernomen worden bij het herstellen van een tuinmuur die onder beschermd stadsgezicht valt?", "a": "Wanneer een tuinmuur onder beschermd stadsgezicht valt, moet de aanvraag voor herstel eerst gemeld worden bij Bouw- en Woningtoezicht. Daarnaast kan er een bodemonderzoek noodzakelijk zijn en dient een architect de juiste tekeningen aan te leveren voordat er een prijsopgave kan worden opgesteld."}, {"v": "Zijn buren verplicht om mee te werken (bijvoorbeeld door toegang te verlenen via hun terrein) als er onderhoud aan het naburige pand moet worden uitgevoerd?", "a": "Buren zijn wettelijk verplicht medewerking te verlenen (het zogenaamde ladderrecht) wanneer dit noodzakelijk is voor het onderhoud van het naburige pand."}, {"v": "Mag ik zelfstandig onderhoud uitvoeren aan een gemeenschappelijke gevel zonder te wachten op een algemeen besluit voor het hele gebouw?", "a": "Nee, de gevel is een gemeenschappelijk onderdeel en onderhoud hieraan dient eerst met alle eigenaren besproken en goedgekeurd te worden."}, {"v": "Wie is er verantwoordelijk voor de VvE-bijdrage en het onderhoud wanneer een woning op naam van de kinderen is gekocht?", "a": "Juridisch gezien zijn de kinderen de eigenaren van de woning. Bij een Vereniging van Eigenaren (VvE) geldt dat de eigenaar van het appartement verplicht is de maandelijkse VvE-bijdrage te betalen. De eigenaar is ook verantwoordelijk voor het onderhoud van de woning. Als de woning slecht wordt onderhouden en er ontstaat daardoor schade of gevaar, zijn de eigenaren (in dit geval de kinderen) daarvoor verantwoordelijk."}, {"v": "Hoeveel Verenigingen van Eigenaren (VvE's) heeft Totaal VvE Beheer momenteel in beheer?", "a": "Totaal VvE Beheer heeft inmiddels meer dan 2900 VvE's in beheer."}, {"v": "Moet een VvE een creditnota betalen?", "a": "Een creditnota hoeft de VvE niet te betalen; dit is een bedrag dat de VvE terugontvangt of dat wordt verrekend met openstaande facturen."}, {"v": "Hoe kan ik instellen of ik de vergaderstukken digitaal of per post ontvang?", "a": "Standaard worden documenten per post verzonden naar het adres dat bij ons bekend is (vaak op basis van het Kadaster). Zodra uw e-mailadres bij ons is geregistreerd voor digitale verzending, ontvangt u de stukken voortaan per e-mail. Indien u een specifieke voorkeur heeft voor ontvangst per post of juist digitaal, kunt u dit aangeven bij uw beheerder om dit te laten aanpassen."}, {"v": "Kan ik informatie over de ledenvergadering en mijn financiële bijdrage vinden in het portaal?", "a": "Ja, in het portaal worden de datum, het tijdstip en de locatie van de volgende voorgestelde ledenvergadering getoond. U ontvangt hier een officiële uitnodiging voor door uw beheerder.  Pas na deze uitnodiging is de datum definitief. Daarnaast is er een weergave van de hoogte van de periodieke VvE-bijdrage beschikbaar."}, {"v": "Kan ik via het portaal reparatieverzoeken indienen of de status van meldingen inzien?", "a": "Ja, via de knop 'Melding maken' kunt u direct een reparatieverzoek indienen. Daarnaast is er een overzicht beschikbaar van uw lopende meldingen inclusief de huidige status."}, {"v": "Welke informatie over commissies en het bestuur kan ik terugvinden in het portaal?", "a": "Indien van toepassing op uw VvE worden de namen van de bestuursleden, de technische commissie, de adviescommissie/raad van toezicht en de kascommissie getoond in het portaal."}, {"v": "Welke algemene informatie over de VvE en de beheerder is zichtbaar in het portaal?", "a": "In het dashboard van het portaal zijn de basisgegevens van de VvE zichtbaar, zoals de naam, het adres, het KvK-nummer en het rekeningnummer. Ook vindt u daar de naam van de beheerder, de beheerovereenkomst en de algemene voorwaarden."}, {"v": "Wie treedt op als bestuurder van de VvE en hoe wordt dit vastgelegd?", "a": "Totaal VvE Beheer treedt op als bestuurder van de VvE. Bij de oprichting is het de bedoeling dat Totaal VvE Beheer als bestuurder wordt opgenomen in de akte. De eigenaar van Totaal VvE Beheer is zelfstandig bevoegd om namens de organisatie te tekenen."}, {"v": "Kunnen watermeters in een pand met slechts twee appartementen op naam van de individuele bewoners worden gezet in plaats van op naam van de VvE?", "a": "Wanneer een pand uit slechts twee appartementen bestaat en er aparte watermeters aanwezig zijn, kunnen deze aansluitingen op naam van de bewoners zelf worden gesteld in plaats van op naam van de VvE."}, {"v": "Hoe moet er worden gehandeld bij overlast van ongedierte in de VvE?", "a": "Bij overlast van ongedierte kan de VvE, indien de betrokken eigenaren hiermee instemmen, zelf direct contact opnemen met een ongediertebestrijder om een afspraak te maken. De factuur voor de bestrijding kan na uitvoering van de werkzaamheden naar de beheerder worden gestuurd ter betaling, gezien het gezamenlijke belang."}, {"v": "Wordt het conceptjaarverslag voorafgaand aan de VvE-vergadering gedeeld met de leden?", "a": "Het is gebruikelijk om de uitnodigingen en agenda's voor de vergadering tijdig te versturen, tezamen met het conceptjaarverslag, zodat de leden voorafgaand aan de vergadering over de benodigde financiële informatie beschikken."}, {"v": "Is het toegestaan voor leden van de VvE om zelf aannemers te benaderen voor het uitvoeren van onderhoudswerkzaamheden?", "a": "Een ieder is vanzelfsprekend vrij om zelf aannemers te benaderen bij of voor de uitvoering van onderhoudswerkzaamheden. Als het om werkzaamheden gaat aan gemeenschappelijke delen dan zal de offerte eerst besproken moeten worden met alle eigenaren. Zijn het werkzaamheden aan de individuele delen dan is dit niet nodig."}, {"v": "Zijn er nog mogelijkheden om nieuwe VvE's aan te melden voor beheer bij Totaal VvE Beheer?", "a": "U kan ten alle tijde een vrijblijvende offerte aanvragen om uw beheer uit te besteden. Hierin zal dan vermeld worden wat de eerst mogelijke datum zal zijn om het beheer over te nemen."}, {"v": "Ik ben eigenaar van meerdere appartementen binnen de VvE, maar na het inloggen in de backoffice-omgeving zie ik slechts informatie van één adres. Hoe zorg ik ervoor dat al mijn dossiers zichtbaar zijn onder hetzelfde e-mailadres?", "a": "Wanneer u eigenaar bent van meerdere eenheden binnen de VvE en bij beide hetzelfde e-mailadres is ingevuld, maar u slechts informatie van één adres ziet, moet er een koppeling worden gemaakt in de backoffice-omgeving om beide dossiers zichtbaar te maken."}, {"v": "Bemiddelt de VvE beheerder in discussies tussen een koper en verkoper?", "a": "De VvE beheerder bemiddelt niet in geschillen tussen koper en verkoper. Discussies over zaken als tussenmeters of specifieke afspraken bij de verkoop van een appartementsrecht dienen door de betrokken eigenaren onderling te worden opgelost."}, {"v": "Mag een eigenaar een dakterras aanleggen of zonnepanelen plaatsen op het dak van een appartementencomplex?", "a": "Voor het maken van een dakterras of het plaatsen van zonnepanelen op een dakvlak boven een appartementsrecht is goedkeuring en instemming van de VvE vereist. Dit moet eveneens passen binnen het vigerende bestemmingsplan en de bijbehorende kosten komen voor rekening van de aanvrager."}, {"v": "Wat is de procedure voor de uittreding van een bestuurder die bij de KvK staat ingeschreven?", "a": "Na ontvangst van uw BSN-nummer wordt er vanuit de KvK een link gestuurd met het verzoek de stappen te volgen voor uw uittreding als bestuurder."}, {"v": "Kan een VvE een aanvraag indienen voor een DMJOP (Duurzaam Meerjarenonderhoudsplan)?", "a": "Ja, een VvE kan ook voor een DMJOP een aanvraag indienen. Hierdoor wordt er een duidelijk overzicht gecreëerd om in kaart te brengen welke verduurzamingsmogelijkheden de VvE heeft en waar eventueel subsidie voor kan worden aangevraagd."}, {"v": "Wat is de procedure voor het definitieve herstel van braakschade nadat deze is gemeld bij de verzekeraar?", "a": "Zodra de verzekeraar de schade heeft beoordeeld en akkoord heeft gegeven op de offerte voor het herstel, kan de opdracht voor het definitieve herstel worden verstrekt."}, {"v": "Welke documenten zijn nodig voor het indienen van een schademelding na een inbraak?", "a": "Voor het in behandeling nemen van een schademelding zijn een ingevuld en getekend schadeformulier, het proces-verbaal van de politie, foto's van de schade en een offerte voor de herstelwerkzaamheden benodigd."}, {"v": "Hoe kan ik mijn e-mailadres voor de correspondentie met de VvE laten wijzigen?", "a": "U kunt uw juiste e-mailadres doorgeven aan de beheerder, waarna dit direct in het systeem wordt aangepast om ervoor te zorgen dat u alle stukken en uitnodigingen voor de Algemene Ledenvergadering op het juiste adres ontvangt."}, {"v": "Wat is het proces bij het activeren van een splitsing en een daaropvolgende ondersplitsing?", "a": "Het beheer start met het activeren van de hoofdsplitsing zodra de opdracht daartoe is verleend. Zodra er een (concept) splitsingsakte voor de ondersplitsing beschikbaar is, kan er gestart worden met de werkzaamheden voor de ondersplitsing."}, {"v": "Is het mogelijk dat medewerkers van externe partijen (zoals glasvezelleveranciers) de algemene sleutel van de voordeur bij de beheerder ophalen en weer terugbrengen?", "a": "Ja, voor externe partijen die toegang nodig hebben tot de algemene ruimten van de VvE kan er een sleutel worden klaargelegd bij de beheerder om afgehaald te worden. Hierbij wordt geregistreerd wanneer en door wie de sleutel is opgehaald en weer is teruggebracht."}, {"v": "Is individuele bemetering een vereiste voor de afrekening van stroom, gas en water binnen een ondersplitsing van een VvE?", "a": "Het is niet verplicht om individuele bemetering als eis te stellen; een afrekening zonder tussenmeters is mogelijk en in de praktijk vaak eenvoudiger uitvoerbaar. Daarnaast zijn de appartementsrechten binnen de ondersplitsing verplicht om voorschotten te betalen voor het verbruik."}, {"v": "Is het toegestaan om trespa of kunststof te gebruiken bij het herstel van houten betimmering?", "a": "Het is niet de bedoeling om trespa of kunststof te plaatsen ter vervanging van houten betimmering, dit om problemen met vocht en schimmelvorming te voorkomen. U dient de houten betimmering te herstellen en te voorzien van een passend verfsysteem."}, {"v": "Is het toegestaan om een nest van vogels te verwijderen tijdens het broedseizoen?", "a": "Gedurende het broedseizoen is het officieel niet toegestaan om nesten te verwijderen. Vanwege deze regelgeving kan er haast geboden zijn bij het uitvoeren van dergelijke werkzaamheden voordat het seizoen begint."}, {"v": "Wat is het verschil tussen de splitsingsaktes in het portaal en andere verzoeken tot wijziging?", "a": "De akte van splitsing en de gewijzigde akte van splitsing in het portaal zijn officiële aktes die zijn opgesteld door de notaris. Overige wijzigingen die niet officieel notarieel zijn vastgelegd, worden in principe niet direct als officiële splitsingsakte geüpload, tenzij hier expliciet opdracht voor wordt gegeven."}, {"v": "Worden documenten die geen formeel notarieel document zijn ook op het klantportaal geplaatst?", "a": "Hoewel documenten die geen formeel notarieel document zijn (zoals informele wijzigingen op een splitsingsakte) strikt genomen niet op de formele plek in het portaal thuishoren, kunnen deze op verzoek van de VvE alsnog aan het portaal worden toegevoegd."}, {"v": "Tot welke ruimtes heeft een taxateur toegang nodig bij een taxatie van het VvE-gebouw en kan een fysieke bezichtiging van appartementen vervangen worden door foto's?", "a": "De taxateur wil in elk geval één van de woonappartementen fysiek zien en alle bedrijfsruimten. Het makkelijkste is als de taxateur de toegang tot de benedenwoning en een tussenwoning verleend wordt. In het geval van bedrijfsruimten volstaat doorgaans de mededeling dat deze tijdens normale werktijden geopend zijn voor inspectie. Foto's zijn voor appartementen niet voldoende."}, {"v": "Op welke dagen kan er een VvE-vergadering worden ingepland?", "a": "Vergaderingen kunnen worden ingepland van maandag tot en met vrijdag."}, {"v": "Welke documenten moet ik meenemen naar een eerste afspraak of overdracht?", "a": "Neem indien beschikbaar betaalde facturen, recente rekeningafschriften en een kopie van de meest recente verzekeringspolissen mee."}, {"v": "Wat moet ik doen als het houtwerk aan de buitenzijde van mijn woning beschadigd is en er mogelijk een raam vervangen moet worden?", "a": "Wanneer er sprake is van schade aan houten kozijnen of ramen, kan de VvE beheerder een timmerman of schilder inschakelen voor herstel. Indien het lastig is om op korte termijn een vakman te vinden, kan de verzekeraar worden gevraagd of zij een rol kunnen spelen in het proces. Vooruitlopend op het herstel van het houtwerk kan een afspraak met de glaszetter voor het vernieuwen van ruiten eventueel tijdelijk worden opgeschort."}, {"v": "Maakt Totaal VvE Beheer gebruik van datumprikkers voor het plannen van vergaderingen?", "a": "Wij werken niet met datumprikkers. Gezien de hoeveelheid VvE-vergaderingen die wij wekelijks houden, is het organisatorisch niet haalbaar om op deze wijze data voor te stellen en te blijven schuiven met opties. Wij doen in plaats daarvan concrete voorstellen voor data."}, {"v": "Is het mogelijk om de VvE-vergadering te verplaatsen naar de avonduren?", "a": "Het is mogelijk om de vergadering naar de avonduren te verplaatsen. Houd er echter rekening mee dat hieraan meerkosten verbonden zijn die bij de VvE in rekening worden gebracht. In beginsel plannen wij vergaderingen tijdens kantooruren om deze kosten te voorkomen."}, {"v": "Wat is leidend als eigenaars het niet eens kunnen worden over de verdeling van onderhoudskosten of de hoogte van de financiële bijdrage?", "a": "Mochten de eigenaren er in de vergadering niet uitkomen wat betreft de redelijkheid van de bijdragen voor het onderhoud, dan is de splitsingsakte altijd leidend."}, {"v": "Is een vordering voor stookkosten nog verhaalbaar als de woning is overgedragen en de beheerder bij de notaris heeft verklaard dat er geen verdere schulden te verrekenen zijn?", "a": "Wanneer een woning is verkocht en de (voormalige) beheerder heeft bij de notaris aangegeven dat er geen verdere schulden meer te verrekenen zijn, kunt u proberen zich daarop te beroepen om de vordering af te wijzen."}, {"v": "Wat is er nodig om een wijziging in de splitsingsakte bij de notaris te laten passeren nadat de volmacht is getekend?", "a": "Nadat de volmacht is getekend, dient de betreffende persoon contact op te nemen met de notaris voor legalisatie van de handtekening. Pas na legalisatie kan de akte van splitsing officieel bij de notaris passeren."}, {"v": "Hoe wordt er omgegaan met garantie op injectiewerk in algemene ruimtes?", "a": "Doorgaans wordt bij garantieclaims op injectiewerk contact opgenomen met de oorspronkelijke uitvoerder of verkoper. Indien werkzaamheden in het verleden niet correct zijn uitgevoerd door een partij, dient de VvE de afweging te maken of zij herstel door dezelfde partij wenst of dat er een andere partij wordt ingeschakeld."}, {"v": "Is er garantie op uitgevoerd gevelwerk?", "a": "Van garantie op gevelwerk is niet automatisch sprake. Het is raadzaam om bij gebreken een deskundige partij aanvullend naar de gevel te laten kijken en een advies voor herstelwerkzaamheden op te laten nemen in een (aanvullende) offerte."}, {"v": "Wat is er nodig om de bestemming van een appartementsrecht in de splitsingsakte te wijzigen, bijvoorbeeld van bedrijfsruimte naar wonen?", "a": "Om de splitsingsakte te wijzigen en de bestemming van een appartementsrecht te veranderen, moet er over dit voorstel worden vergaderd door de VvE. Er dient een formeel besluit te worden genomen door de vergadering van eigenaars voor het wijzigen van de splitsingsakte en het verlenen van toestemming voor de bestemmingswijziging. Bij de oproeping voor deze vergadering kan de vernieuwde splitsingstekening als bijlage worden meegezonden."}, {"v": "Kan de VvE toestemming weigeren voor de realisatie van een dakterras in afwachting van een MJOP?", "a": "De VvE kan besluiten om vooralsnog geen toestemming te geven voor de realisatie van een dakterras als er eerst een Meerjarenonderhoudsplan (MJOP) opgesteld moet worden. Dit is met name relevant wanneer er twijfels zijn over de staat van het dak. Het wordt als onwenselijk en onverstandig beschouwd om toestemming te geven voordat duidelijk is of het dak op korte termijn (bijvoorbeeld binnen drie jaar) vervangen moet worden, om te voorkomen dat het nieuwe dakterras direct weer verwijderd moet worden."}, {"v": "Bij wie moeten lopende verzoeken of vragen worden neergelegd tijdens een overstapperiode naar een nieuwe beheerder?", "a": "Tijdens de overstapperiode kunnen lopende zaken nog bij de huidige beheerder worden neergelegd tot de officiële overdrachtsdatum."}, {"v": "Welke documenten zijn nodig om een juiste waardevaststelling (taxatie) van de opstallen te laten uitvoeren?", "a": "Om tot een juiste waardevaststelling te komen zijn de actuele splitsingstekeningen en/of digitale bouwtekeningen (plattegronden, doorsnedetekeningen en gevelaanzichten, voorzien van schaalaanduiding) van de gebouwen in pdf-formaat nodig. Indien beschikbaar zijn ook het aantal zonnepanelen, NEN 2580 meetstaten of overzichten met het bruto vloeroppervlak en oude verzekeringstaxatierapporten van belang."}, {"v": "Wat gebeurt er als een verschuldigde VvE-bijdrage niet tijdig wordt betaald?", "a": "Bij het uitblijven van betaling van de VvE-bijdrage binnen de gestelde termijn, schrijft het beheer de eigenaar aan. Indien betaling na meerdere brieven uitblijft, is het beheer verplicht de vordering over te dragen aan een incassobureau. De bijkomende kosten hiervan zijn voor rekening van de eigenaar."}, {"v": "Wat doet de VvE beheerder als een aannemer of partij gemaakte afspraken niet nakomt?", "a": "Indien een partij niet reageert of afspraken niet nakomt, zal de beheerder deze namens de VvE in gebreke stellen."}, {"v": "Kan de elektricien van het beheerbedrijf ook werken aan specifieke intercomsystemen zoals die van Comelit?", "a": "Comelit is een bekend type intercomsysteem waar de elektricien doorgaans veel mee werkt en ervaring mee heeft."}, {"v": "Is het noodzakelijk om originele facturen of bonnen per post op te sturen voor de administratie?", "a": "Een kopie of een duidelijke foto van de bon is voldoende. Het is niet nodig om de originele bonnen per post op te sturen."}, {"v": "Is het verstandig om geadviseerde werkzaamheden uit een MJOP gefaseerd uit te voeren?", "a": "Niet alle geadviseerde werkzaamheden kennen een gelijke prioriteit. Hoewel een gefaseerde uitvoering op basis van prioriteit mogelijk is, verdient een gecombineerde uitvoering vaak de voorkeur met het oog op efficiëntie. Gefaseerde uitvoering resulteert veelal in hogere algemene kosten en meer overlastmomenten."}, {"v": "Wie is er verantwoordelijk voor de opgave van de juiste herbouwwaarde of verzekerde som van het VvE-gebouw?", "a": "De VvE (de vergadering van eigenaars) is zelf verantwoordelijk voor de opgave van een juiste herbouwwaarde / verzekerde som ten behoeve van de verzekering."}, {"v": "Kan het onderhoud van de gemeenschappelijke tuin worden betaald vanuit de VvE in plaats van door individuele bewoners?", "a": "Het onderhoud van een gemeenschappelijke tuin is een VvE-aangelegenheid. Voorstellen voor structurele kostenposten of wijzigingen in het tuinonderhoud kunnen worden meegenomen in de eerstvolgende vergadering van eigenaars voor besluitvorming."}, {"v": "Wat moet er gebeuren als er sprake is van ongedierte, zoals ratten, waardoor er schade aan de bestrating ontstaat?", "a": "Wanneer er sprake is van ongedierte dat schade veroorzaakt, wordt dit aangemerkt als een VvE-aangelegenheid waarbij direct actie moet worden ondernomen om verdere schade of overlast te beperken."}, {"v": "Kan de tenaamstelling van mijn account in het portaal worden gewijzigd?", "a": "Ja, de tenaamstelling van uw account kan direct door ons worden gewijzigd in het systeem."}, {"v": "Is het kantoor van Totaal VvE Beheer gesloten tijdens officiële feestdagen?", "a": "Totaal VvE Beheer is gesloten op officiële feestdagen zoals Pasen, Pinksteren, Koningsdag, Hemelvaartsdag, Bevrijdingsdag, Kerst en Nieuwjaarsdag."}, {"v": "Welke documenten zijn nodig voor het voorbereiden van een algemene ledenvergadering (ALV) waarbij een nieuwe splitsingsakte en verzekeringsaanpassing op de agenda staan?", "a": "Voor het opstellen van de agenda en de voorbereiding van de vergadering zijn een kopie van de concept splitsingsakte en een kopie van de huidige verzekeringspolis benodigd."}, {"v": "Wat moet er gebeuren als de gemeente een aanschrijving oplegt vanwege loszittend gevelwerk bij een appartement?", "a": "Wanneer er sprake is van loszittend gevelwerk en een mogelijke aanschrijving vanuit de gemeente, kan dit worden opgepakt door de VvE. Om dit proces in gang te zetten, dienen er foto's van de situatie gedeeld te worden met de beheerder, zodat op basis daarvan de nodige acties kunnen worden ondernomen."}, {"v": "Is een vergadering noodzakelijk voor het formeel vastleggen en bepalen van de voorschotten van de VvE?", "a": "Een vergadering is raadzaam om de voorschotten formeel te bepalen en vast te leggen."}, {"v": "Moet een bewoner de VvE op de hoogte stellen van een geplande badkamerverbouwing?", "a": "Het is niet verplicht om de VvE op de hoogte te stellen maar wel raadzaam om het te doen. Hierdoor kunnen de buren ook rekening houden met enige geluidsoverlast en zijn ze op de hoogte."}, {"v": "Wat moet ik doen als mijn bel (intercomsysteem) defect is en gerepareerd moet worden?", "a": "Wanneer er sprake is van een defect aan de bel of het intercomsysteem, kan de beheerder een elektricien inschakelen om een afspraak te maken voor inspectie en herstel van de installatie."}, {"v": "Wat moet Totaal VvE Beheer ontvangen om een bestuurder te kunnen uitschrijven bij de Kamer van Koophandel?", "a": "Om een bestuurder uit te schrijven is een specifiek machtigingsformulier nodig dat door de eigenaar is ingevuld en ondertekend."}, {"v": "Moet er voor gezamenlijke nutsvoorzieningen binnen de VvE een aparte bankrekening worden geopend?", "a": "Kosten voor de nutsvoorzieningen kunnen via de normale VvE-rekening verlopen."}, {"v": "Welke functies biedt de klantenservice chatbot voor bewoners en VvE-besturen?", "a": "De chatbot is 24/7 beschikbaar, beantwoordt veelgestelde vragen over onderhoud, financiën en vergaderingen, en kan direct tickets aanmaken en doorsturen naar de juiste afdeling."}, {"v": "Vallen problemen met de draagmuur of optrekkend vocht in de kruipruimte onder de verantwoordelijkheid van de VvE?", "a": "Dit valt inderdaad onder de VvE."}, {"v": "Is een rechtsbijstandverzekering verplicht voor een VvE en waarvoor kan deze worden gebruikt?", "a": "Rechtsbijstand is geen verplichte verzekering. De rechtsbijstand kan worden gebruikt bij geschillen met derden, zoals bijvoorbeeld aannemers."}, {"v": "Wordt de presentielijst van een vergadering standaard toegevoegd aan de notulen?", "a": "De presentielijst is een intern administratief document. Deze wordt niet aan de notulen van een vergadering toegevoegd, maar in het dossier van de Vereniging van Eigenaren opgeslagen."}, {"v": "Zijn de kosten voor het afstellen van een deur die niet goed sluit of schuurt voor de VvE?", "a": "Valt het afstellen onder de VvE? Ons digitale portaal, genaamd Totaal Portaal, is speciaal ingericht voor uw VvE en eigenaren. Hier kunt u documenten terugvinden, waaronder aktes en notulen, om na te gaan welke onderdelen en onderhoudstaken onder de gezamenlijke verantwoordelijkheid van de VvE vallen."}, {"v": "Wat houdt een bouwkundige inspectie voor het meerjarenonderhoudsplan (MJOP) in en hoe lang duurt dit per woning?", "a": "De bouwkundige inspectie betreft het totale pand, inclusief de daken, balkons en kozijnen. Een dergelijke inspectie duurt circa 15 minuten per woning."}, {"v": "Hoe is de begroting van een Meerjarenonderhoudsplan (MJOP) doorgaans opgebouwd?", "a": "De begroting is inclusief BTW, opslagen voor directievoering, benaderings- en algemene bouwplaatskosten en een jaarlijkse indexatie. Tevens wordt er een jaarlijkse post onvoorzien opgenomen."}, {"v": "Waar kan ik een review achterlaten voor Totaal VvE Beheer?", "a": "U kunt een review achterlaten via Google."}, {"v": "Met welke partij werkt de beheerder bij voorkeur samen voor het opstellen van een Meerjarenonderhoudsplan (MJOP)?", "a": "Wij werken samen met verschillende bouwinspecteurs voor het opstellen van een MJOP."}, {"v": "Wie stelt de beheerder aansprakelijk bij schade aan de buitenkant van het pand door een verhuizing?", "a": "De beheerder stelt namens de VvE bij voorkeur de eigenaar aansprakelijk in plaats van rechtstreeks de verhuizer. Hiervoor moet wel eerst een gedegen offerte voor het herstel van de schade aanwezig zijn."}, {"v": "Welke verzekeringen zijn doorgaans inbegrepen bij het beheer en wat dekken deze?", "a": "De verzekeringen betreffen de opstal-, glas- en aansprakelijkheidsverzekering. Deze zijn inclusief appartementenclausule en een 6-jarige garantie tegen onderverzekering."}, {"v": "Hoe lang duurt het voordat er een beslissing wordt genomen op een subsidieaanvraag voor verduurzaming?", "a": "Binnen 6 tot 8 weken na ontvangst van de subsidieaanvraag wordt er een beslissing op de aanvraag genomen."}, {"v": "Worden reparaties aan dakgoten en regenpijpen gedekt door de verzekering van de VvE?", "a": "Reparaties aan dakgoten en regenpijpen worden doorgaans aangemerkt als onderhoudskosten voor de VvE. Voor de reparatie van deze zaken zal de verzekeraar over het algemeen geen rol van betekenis spelen."}, {"v": "Hoe vaak en wanneer vindt de algemene ledenvergadering doorgaans plaats?", "a": "Vergaderingen vinden doorgaans één keer per jaar plaats, meestal in dezelfde periode als het jaar ervoor. Indien er een reden of wens is om eerder te vergaderen, dan is dat altijd mogelijk."}, {"v": "Hoe werkt de glasverzekering binnen een VvE als er sprake is van een zakelijke bestemming op de begane grond?", "a": "De glaspremie wordt berekend over het gehele gebouw, waarbij glas met een zakelijke bestemming vaak is uitgesloten van de collectieve dekking."}, {"v": "Wat kan er gedaan worden als de feitelijke situatie rondom huisnummering afwijkt van wat er in een oude splitsingsakte staat?", "a": "Bij een zeer oude akte is een rectificatie door de notaris vaak niet meer mogelijk. In de toekomst zouden de eigenaren een wijziging van de akte kunnen overwegen, hoewel dit kostbaar kan zijn. In de huidige situatie zullen er meestal geen grote problemen ontstaan, hooguit wat verwarring."}, {"v": "Is er een besluit nodig om het voorschot van de servicekosten te verlagen?", "a": "Om de servicekosten of het voorschotbedrag te verlagen, moet er doorgaans een officieel besluit worden genomen door de Vereniging van Eigenaren (VvE)."}, {"v": "Is het vervangen van enkel glas door dubbel glas een taak van de VvE?", "a": "Het vernieuwen van enkel naar dubbel glas betreft een verbetering en geen regulier onderhoud. De VvE is verantwoordelijk voor het in stand houden van het onderhoud van het gebouw. Indien er sprake is van een gewenste verbetering, zal dit projectmatig voor de gehele VvE bekeken moeten worden en als voorstel aan de vergadering moeten worden voorgelegd."}, {"v": "Met welke doorlooptijd moet ik rekening houden bij een aanvraag voor VvE beheer en het openen van een bankrekening?", "a": "Het totale proces voor VvE beheer kan 4 tot 5 maanden duren, mede door factoren zoals de 'beleggersclausule'. Voor het openen van een bankrekening op naam van de VvE maken wij gebruik van de goedgekeurde notulen; dit specifieke onderdeel duurt ongeveer 3 tot maximaal 4 weken."}, {"v": "Hoe krijg ik een bewijs van verzekering of een nieuw polisblad als de huidige polis een einddatum in het verleden toont?", "a": "Wij ontvangen niet jaarlijks een nieuw polisblad. U kunt de recent betaalde premiefactuur gebruiken als bewijs van dekking. Mocht de verzekeraar aangeven dat de polis doorlopend is, dan volstaat de premiebetaling als bewijs van verzekering."}, {"v": "Wat wordt er bedoeld met ruim van tevoren een opdracht of afspraak inplannen?", "a": "Bij voorkeur houden wij een termijn van 2 à 3 weken aan."}, {"v": "Wanneer valt een gebrek aan de woning of het complex onder de garantie bij de aannemer?", "a": "Om te bepalen of een defect onder de garantie valt, moet de precieze oorzaak van het probleem bekend zijn. Op basis van de specifieke oorzaak kan er een beoordeling worden gemaakt of een bericht of opdracht aan de desbetreffende aannemer gestuurd kan worden om dit onder garantie te herstellen."}, {"v": "Zijn de algemene voorwaarden van Totaal VvE Beheer onderhandelbaar of aanpasbaar per VvE?", "a": "Nee, de algemene voorwaarden staan vast en worden niet per individuele VvE aangepast."}, {"v": "Wat zijn de parkeermogelijkheden bij het kantoor van Totaal VvE Beheer?", "a": "Parkeren kan in de garage onder het gebouw."}, {"v": "Hoeveel tijd wordt er doorgaans uitgetrokken voor een eerste vergadering?", "a": "Bij een kleine VvE is doorgaans 1 uur voldoende."}, {"v": "Welke onderdelen kan ik selecteren bij het indienen van een reparatieverzoek voor de buitenzijde van het pand?", "a": "Bij het indienen van een reparatieverzoek via het portaal kunt u onder het onderdeel 'overig' kiezen voor de categorieën: Gebreken gevel VvE, Gebreken dak VvE en Overige gebreken buitenzijde VvE. Na het selecteren van een categorie kunt u in het tekstvak de gewenste reparatie omschrijven en foto's bijvoegen."}, {"v": "Waarom worden de maandelijkse kosten 'VvE bijdrage' genoemd in plaats van servicekosten?", "a": "De benaming 'maandelijkse VvE bijdrage' wordt gebruikt omdat de term 'servicekosten' een andere verwachting schept over de dekking van de kosten."}, {"v": "Kan ik een voorkeurstijd opgeven bij het indienen van een reparatieverzoek?", "a": "Bij het indienen van een reparatieverzoek kunt u een voorkeur voor bepaalde dagdelen aangeven. Houd er echter rekening mee dat dit altijd op basis van beschikbaarheid van het servicebedrijf is. Het is niet mogelijk om een specifieke voorkeurstijd in het tekstvak aan te geven."}, {"v": "Wat moet ik doen bij een liftstoring?", "a": "Wanneer er iemand in de lift vastzit, dient u direct contact te leggen via de spreekluisterverbinding met het liftbedrijf of het noodnummer te bellen dat bij de lift vermeld staat. Bel alleen bij een levensbedreigende situatie de brandweer (112). Bij een kleine storing waarbij niemand vastzit, kunt u eerst de beheerder van uw VvE informeren."}, {"v": "Wanneer worden de overige bewoners en eigenaren geïnformeerd over de overdracht van het beheer?", "a": "De overige bewoners worden geïnformeerd bij de verzending van de stukken voor de eerstvolgende geplande vergadering."}, {"v": "Is het toegestaan om zonder voorafgaande toestemming van de VvE werkzaamheden aan het dak uit te voeren?", "a": "Voor werkzaamheden aan het dak moet vooraf altijd toestemming worden gevraagd. Dit geeft de VvE de gelegenheid om het dak zelf eerst te inspecteren voorafgaand aan de werkzaamheden."}, {"v": "Wat moet ik doen als een raam in de woning niet goed sluit of is doorgezakt?", "a": "U kunt een melding maken bij de VvE beheerder. Deze zal uitzoeken of de kosten gemeenschappelijk of individueel zijn. Indien het binnen het mandaat valt, zal er een opdracht worden verstrekt aan een onderhoudspartij om een afspraak te maken voor reparatie om verdere schade, zoals regenwaterlekkage, te voorkomen. Zijn de kosten gemeenschappelijk dan worden deze vanuit de VvE reserve betaald, zijn de kosten individueel dan worden ze doorbelast aan desbetreffende eigenaar."}, {"v": "Welke documenten of gegevens zijn er nodig om een subsidieaanvraag voor dakisolatie in te dienen?", "a": "Voor het aanvragen van de subsidie zijn de staatssteunverklaring, de offerte van de dakdekker, het aantal m2 en de meldcode benodigd."}, {"v": "Worden bedragen in de begroting van de VvE inclusief of exclusief btw weergegeven?", "a": "In de begrotingen worden alle bedragen inclusief btw weergegeven. De VvE is niet btw-plichtig en kan de btw daarom niet terugvorderen of verrekenen."}, {"v": "Biedt de verzekeraar kosteloze taxaties aan voor de VvE?", "a": "Sommige verzekeraars voeren een taxatie kosteloos uit, maar dit is vaak gebonden aan een maximale herbouwwaarde (bijvoorbeeld tot 5 miljoen euro). Indien de herbouwwaarde hierboven uitkomt, zijn er kosten aan de taxatie verbonden. Ook zijn er verzekeraars die wel kosten rekenen voor een taxatie door een externe partij. Dit is dus geheel afhankelijk van welke verzekeraar de VvE gebruikt."}, {"v": "In welke taal kan de vergadering en de communicatie plaatsvinden?", "a": "Vergaderen kan in het Engels, maar de (schriftelijke) communicatie zal in het Nederlands plaatsvinden."}, {"v": "Hoe werkt de garantie van de verkoper na de oplevering van een woning binnen een VvE?", "a": "Garantie wordt, indien van toepassing, op individuele titel aan een eigenaar gegeven. Indien u aanspraak wilt maken op garantie van de verkoper, dient u dit zelf bij hen onder de aandacht te brengen. De beheerder of de VvE zijn hierin geen partij."}, {"v": "Wat is het advies van de VvE beheerder met betrekking tot de kosteloze aanleg van glasvezel?", "a": "Wanneer de betreffende werkzaamheden voor de aanleg van glasvezel kosteloos worden aangeboden, adviseren wij hiervan gebruik te maken om in de toekomst hoge kosten voor de aanleg te voorkomen."}, {"v": "Is het mogelijk om gebruik te maken van de dienstverlening op een afwijkende wijze dan in de offerte is voorgesteld?", "a": "Het is niet mogelijk om op een afwijkende wijze gebruik te maken van onze dienstverlening. Wij bieden uitsluitend het in de offerte aangeboden dienstenpakket."}, {"v": "Hoe worden de kosten voor onderhoud aan hekwerk, verlichting en groenvoorziening verdeeld?", "a": "Alle kosten ter zake van onderhoud en instandhouding aan/van het hekwerk, lichtvoorziening en groenvoorziening worden conform breukdeel verdeeld."}, {"v": "Hoe worden administratiekosten binnen een VvE doorgaans toegerekend?", "a": "Administratiekosten worden voor gelijke gedeelten toegerekend aan de appartementsrechten."}, {"v": "Worden er tijdens de opstartvergadering van een nieuwe VvE alleen administratieve zaken geregeld of worden er ook daadwerkelijk besluiten genomen?", "a": "Tijdens de opstartvergadering worden er wel degelijk besluiten genomen. Punten die op de agenda staan zijn onder andere: het aannemen van het kantoor als bestuurder/administrateur, de overschrijving bij de Kamer van Koophandel, het openen van een bankrekening, het vaststellen van de hoogte van de maandelijkse bijdragen, en het eventueel oversluiten van verzekeringen tegen betere voorwaarden."}, {"v": "Vallen herstelwerkzaamheden aan vloerbalken van woningen onder de gezamenlijke verantwoordelijkheid van de VvE?", "a": "Volgens de splitsingsakte behoren vloeren tot de gemeenschappelijke gedeelten van het gebouw. In de meeste aktes staat dat tot de gemeenschappelijke gedeelten onder meer de funderingen, dragende muren, kolommen en het geraamte van het gebouw worden gerekend, alsmede de vloeren. Hierdoor vallen herstelwerkzaamheden aan de vloerconstructie, zoals vloerbalken in woon- of slaapkamers, onder de gezamenlijke kosten van de VvE."}, {"v": "Wanneer en hoe ontvang ik de nieuwe verzekeringspolis en de bijbehorende voorwaarden?", "a": "Zodra de verzekeringen zijn aangevraagd en de polis is opgemaakt, ontvangen eigenaren hiervan een kopie per e-mail. Daarnaast worden de polisbladen en de voorwaarden automatisch opgeslagen in het portaal, waar u deze direct kunt terugvinden."}, {"v": "Naar welk adres wordt de uitnodiging en agenda voor de VvE-vergadering verstuurd?", "a": "Wettelijk zijn wij verplicht om het adres te gebruiken dat bekend is bij het Kadaster. De uitnodiging en agenda voor de vergadering worden daarom naar dit specifieke correspondentieadres verzonden."}, {"v": "Hoe worden de breukdelen voor de verdeling van de kosten bepaald?", "a": "De breukdelen worden gevolgd zoals deze zijn vastgelegd in de aangeleverde splitsingsakte."}, {"v": "Waarom moeten eigenaren jaarlijks hun aandeel in de onderhoudsreserve van de VvE opvragen?", "a": "Jaarlijks moeten eigenaren hun aandeel in de VvE onderhoudsreserve opgeven aan de Belastingdienst in het kader van Box III."}, {"v": "Heeft een VvE-vergadering altijd een absolute meerderheid van stemmen nodig om rechtsgeldige besluiten te nemen?", "a": "Niet altijd. Hoewel er meestal met een meerderheid van stemmen rechtsgeldige besluiten kunnen worden genomen, is de exacte vereiste afhankelijk van de bepalingen in de akte of het reglement van de VvE (bijvoorbeeld artikel 33 lid 1). Hierin kan zijn vastgelegd dat voor specifieke besluiten een ander aantal stemmen of een gekwalificeerde meerderheid nodig is."}, {"v": "Is het mogelijk om de VvE-bijdrage maandelijks te betalen in plaats van jaarlijks?", "a": "De eigenaar kan de wens kenbaar maken om de VvE-kosten maandelijks te betalen in plaats van één keer per jaar. Dergelijke verzoeken kunnen worden meegenomen in de besluitvorming of administratieve verwerking door de beheerder."}, {"v": "Wat is de gemiddelde contractduur en de opzegtermijn van de beheerovereenkomst?", "a": "In beginsel gaat dit om een contract voor onbepaalde tijd. De overeenkomst is dagelijks opzegbaar met een opzegtermijn van 3 maanden."}, {"v": "Waarom staat de offerte in het portaal in plaats van de beheerovereenkomst?", "a": "Wanneer de offerte met algemene stemmen in de opstartvergadering akkoord is bevonden, dient de offerte ook als de beheerovereenkomst."}, {"v": "Wanneer moet een subsidieaanvraag voor verduurzaming, zoals het isoleren van het dak of de kozijnen (SVVE), worden ingediend?", "a": "Een subsidieaanvraag voor verduurzamingswerkzaamheden moet altijd worden aangevraagd voordat de werkzaamheden worden uitgevoerd."}, {"v": "Welke muren en kolommen binnen een VvE worden als gemeenschappelijk aangemerkt?", "a": "Alle dragende muren en kolommen dienen als gemeenschappelijk te worden aangemerkt conform de splitsingsakte."}, {"v": "Kan Totaal VvE Beheer de jaarrekening aanpassen of opstellen over een periode van vóór de start van hun beheer?", "a": "Het aanpassen of opstellen van de jaarrekening uit een periode die niet onder onze beheerperiode valt, doen wij niet. De hiervoor benodigde bestanden kunnen wij veelal niet uitlezen van de bank in onze software."}, {"v": "Is het gebruikelijk dat partijen bij een offerteaanvraag voor groot onderhoud hun eigen onderzoek willen uitvoeren?", "a": "Het is gebruikelijk dat partijen zelf hun eigen onderzoek willen uitvoeren, maar het is mogelijk om hen te voorzien van informatie uit reeds uitgevoerde onderzoeken door andere deskundige partijen."}, {"v": "Mag een individuele eigenaar zelfstandig een vergadering bijeenroepen?", "a": "Een individuele eigenaar is in zijn eentje niet bevoegd tot het bijeenroepen van een vergadering."}, {"v": "Hoe kunnen besluiten over gemeenschappelijk onderhoud worden genomen tijdens een vergadering?", "a": "Om besluiten te kunnen nemen over gemeenschappelijk onderhoud dient dit expliciet en duidelijk als agendapunt op de agenda van de vergadering te staan."}, {"v": "Wie mag het woord voeren namens een ondersplitsing in de vergadering van de hoofdsplitsing?", "a": "Het bestuur van de ondersplitsing dient gemachtigd te worden om namens de ondersplitsing het woord te voeren in de vergadering van de hoofdsplitsing. Andere eigenaren binnen de ondersplitsing mogen de vergadering van de hoofdsplitsing gewoon bijwonen, maar alleen het bestuur van de ondersplitsing voert daar het woord."}, {"v": "Wie is verantwoordelijk voor de kosten van het onderhoud aan de schil van een gebouw bij een hoofdsplitsing en een ondersplitsing?", "a": "De schil van het gebouw komt doorgaans voor rekening van de hoofdsplitsing. Vrijwel al het onderhoud dient vanaf de rekening van de hoofdsplitsing te worden voldaan, waarbij de ondersplitsing verplicht is om haar aandeel in de gemeenschappelijke kosten op de rekening van de hoofdsplitsing over te maken."}, {"v": "Is het de taak van de administrateur om bouwtechnische inspecties op locatie uit te voeren?", "a": "Een bezoek op locatie voor bouwtechnische inspecties valt niet onder de taakomschrijving van de administrateur. De rol van de administrateur is gericht op het administratieve beheer. Voor technische zaken en de status van werkzaamheden wordt contact gelegd met de uitvoerende partijen of bouwkundig adviseurs."}, {"v": "Hoe kan de staat van bouwdelen (zoals lateien) het beste worden getoetst voor het onderhoudsplan?", "a": "Het laten toetsen door een bouwkundige door een inspectie uit te laten voeren of een Meerjarenonderhoudsplan (MJOP) op te laten stellen is de beste weg om te bewandelen. Op basis van het advies kan worden bepaald of directe uitvoering noodzakelijk is of dat er nog tijd is om hiervoor te reserveren."}, {"v": "Wat kan de VvE doen bij aanhoudende criminaliteit, overlast van onbevoegden en veiligheidsproblemen in de gemeenschappelijke ruimtes zoals het portiek?", "a": "Bij acute veiligheidsproblemen en criminaliteit adviseren wij om direct contact op te nemen met de wijkagent. De VvE-beheerder is geen opsporingsinstantie. Bewoners kunnen zelf voorstellen ter verbetering van de veiligheid, zoals extra beveiligingsmaatregelen, indienen om te laten bespreken en besluiten tijdens de algemene ledenvergadering."}, {"v": "Kan ik de werkzaamheden van mijn eigen ingeschakelde glaszetter laten afstemmen met de aannemer of schilder die door de VvE is ingeschakeld?", "a": "Zolang hier geen extra kosten uit volgen, kunt u uw glaszetter contact laten opnemen met de uitvoerder van de VvE-werkzaamheden om de planning af te stemmen. Een logische volgorde is dat de kozijnen eerst worden hersteld, waarna de ruiten geplaatst worden, zodat alles daarna direct netjes geschilderd kan worden."}, {"v": "Repareert een schilder ook houtrot tijdens de uitvoering van het werk?", "a": "Een schilder repareert in de regel geen houtrot; daar wordt een timmerman voor ingeschakeld. Het is logisch dat deze werkzaamheden door verschillende specialisten worden uitgevoerd."}, {"v": "Wat gebeurt er met de huidige verzekeringen bij de overstap naar een nieuw pakket?", "a": "Wij zullen de huidige verzekeringen (laten) beëindigen, u krijgt dan restitutie op uw rekening overgemaakt. Per datum beëindiging laten wij de nieuwe verzekeringen ingaan."}, {"v": "Wat moet ik doen als onderhoudswerkzaamheden niet conform de offerte zijn uitgevoerd?", "a": "Wanneer werkzaamheden niet conform de offerte zijn uitgevoerd, kunnen wij onze technisch manager langssturen om de situatie ter plaatse te beoordelen."}, {"v": "Is het mogelijk om de verzekeringen van de VvE bij een eigen partij onder te brengen?", "a": "Het onderbrengen van de verzekeringen bij een externe partij is mogelijk en kan in het voorstel worden aangepast."}, {"v": "Wat gebeurt er met de verzekeringspremie als een dekking, zoals de glasverzekering, wordt beëindigd?", "a": "Bij het royeren van een verzekering of het laten vervallen van een dekking zal de premie hierop worden aangepast door de verzekeraar."}, {"v": "Kunnen zakelijke facturen voor onderhoudswerkzaamheden worden verrekend met de privébijdrage aan de VvE?", "a": "Onderhoudswerkzaamheden die namens een bedrijf worden uitgevoerd, staan geheel los van de privé betaalverplichting (zoals de maandbijdrage of een extra bijdrage) aan de VvE. Deze bedragen kunnen niet tegen elkaar worden weggestreept."}, {"v": "Wat zijn de mogelijkheden voor glasdekking binnen de VvE-verzekering als de dekking niet gelijk is voor alle eenheden, zoals bij een mix van woningen en commerciële ruimtes?", "a": "Het is mogelijk om de glasdekking te laten vervallen voor de gehele VvE wanneer er geen overeenstemming is over een gezamenlijke dekking of wanneer de dekking niet voor alle eenheden (zoals appartementen en winkelpanden) gelijkwaardig kan worden toegepast. In dat geval wordt de verzekeraar verzocht de glasdekking uit de polis te verwijderen."}, {"v": "Deelt de beheerder financiële informatie van de VvE met derden?", "a": "Wij zullen nimmer financiële informatie met derden delen. In dergelijke gevallen zult u de verhuurder of de eigenaar van het betreffende pand moeten raadplegen."}, {"v": "Tot wanneer mag een huidige eigenaar besluiten nemen die invloed hebben op de VvE-bijdrage bij de verkoop van een woning?", "a": "Besluiten liggen tot het moment van overdracht bij de (huidige) eigenaar."}, {"v": "Met welke opzegtermijn moet de VvE rekening houden voor het opzeggen van de opstalverzekering?", "a": "De opstalverzekering heeft een opzegtermijn van 2 maanden voor de hoofdpremievervaldatum, of kan worden opgezegd indien er een wijzigings- of verlengingsvoorstel wordt afgegeven waar de VvE niet mee akkoord gaat."}, {"v": "Hoe werkt de opbouw van polisnummers bij een collectieve opstalverzekering?", "a": "Bij een collectieve contractvorm (moederpolis) krijgt elke VvE onder dit contract het hoofdpolisnummer met een toevoeging van drie cijfers specifiek voor die betreffende VvE."}, {"v": "Hoe kan ik zien of de herbouwwaarde op de verzekeringspolis is gebaseerd op een taxatierapport?", "a": "Kijkend naar de polis zou dat daarop aangetekend moeten staan indien de herbouwwaarde is gebaseerd op een taxatierapport. Als dit niet vermeld staat, is er in de regel geen officieel taxatierapport aan de polis gekoppeld."}, {"v": "Wat zijn de risico's en gevolgen van een te lage herbouwwaarde zonder garantie tegen onderverzekering?", "a": "Wanneer de herbouwwaarde handmatig wordt aangepast of te laag is ingeschat, vervalt de garantie tegen onderverzekering. Dit betekent dat de verzekeraar bij schade mogelijk onvoldoende uitkeert om tot volledig herstel of herbouw over te gaan, wat grote financiële risico's met zich meebrengt voor de VvE en het bestuur. Om dit te voorkomen kan de VvE een officieel taxatierapport of onderhoudsplan laten opstellen, hoewel hier kosten aan verbonden zijn."}, {"v": "Wanneer is een herzien taxatierapport rechtsgeldig?", "a": "Het taxatierapport is pas rechtsgeldig nadat het door assuradeuren op de polis is aangetekend."}, {"v": "Is het mogelijk om de oprichtingsvergadering online te laten plaatsvinden?", "a": "Het is mogelijk om de oprichtingsvergadering online bij te wonen; u ontvangt hiervoor een uitnodiging."}, {"v": "Hoe kan ik extra sleutels laten bijmaken of een slot laten vervangen als hier een certificaat voor nodig is?", "a": "De VvE beheerder kan u voorzien van informatie over het bijmaken van gecertificeerde sleutels; hiervoor kunt u contact opnemen met de beheerder voor het benodigde certificaat of de officiële toestemming. Let op: indien de beheerder zelf niet over het fysieke certificaat beschikt voor specifieke sloten of sleutels, kan deze u informeren over de te volgen procedure namens de VvE."}, {"v": "Wat is de procedure rondom het opstellen van de concept notulen na een voorstel voor de maandelijkse bijdragen?", "a": "Zodra er een akkoord is op het voorstel met de te verwachten maandelijkse bijdragen, worden de concept notulen opgemaakt."}, {"v": "Is het mogelijk om een gedeeltelijk of uitgekleed pakket af te nemen in plaats van het totaalpakket?", "a": "Wij bieden geen uitgeklede pakketten aan, maar uitsluitend het aangeboden totaalpakket. Dit doen wij omdat we leden en klanten niet willen teleurstellen wanneer zij technische ondersteuning nodig hebben bij bijvoorbeeld een lekkage, verstopping of een andere calamiteit. Door uitsluitend het totaalpakket aan te bieden, voorkomen we dat klanten dergelijke problemen zelf moeten oplossen omdat zij enkel administratieve dienstverlening zouden afnemen."}, {"v": "Is het eigenarenbelang van een appartement met zakelijke bestemming hetzelfde verzekerd als dat van een appartement met particuliere bestemming?", "a": "Eigenarenbelang van een appartement met zakelijke bestemming is niet te vergelijken met het eigenarenbelang van een appartement met particuliere bestemming. Daarom is in de clausule vaak opgenomen dat het eigenarenbelang voor het gedeelte van het gebouw met zakelijke bestemming niet is meeverzekerd op de collectieve polis. De ondernemer dient het eigenarenbelang zelf mee te verzekeren op de daarvoor bestemde inventaris- of goederenverzekering."}, {"v": "Wat houdt het eigen risico op de zaakschade in bij de aansprakelijkheidsverzekering?", "a": "Het eigen risico op de zaakschade betreft het eigen risico per zaak welke aangemeld wordt op de aansprakelijkheidsverzekering."}, {"v": "Valt een lekkage vanuit een dakkapel onder de verantwoordelijkheid van de VvE?", "a": "Een lekkage die voortkomt uit een dakkapel valt buiten de verantwoordelijkheid van de VvE. In dergelijke gevallen is er geen actie vereist vanuit de VvE of de beheerder."}, {"v": "Moet een jaarlijkse evaluatie worden opgenomen in de beheerovereenkomst?", "a": "Een jaarlijkse evaluatie behoeft niet in een overeenkomst te worden opgenomen. Indien dit een wens is van de eigenaren, dient dit aan de agenda voor een Algemene Ledenvergadering (ALV) te worden toegevoegd."}, {"v": "Is het BSN-nummer van alle eigenaren nodig voor de inschrijving bij de Kamer van Koophandel (KvK)?", "a": "Het BSN van één van de eigenaren is in dit geval voldoende voor de KvK."}, {"v": "Wat zijn de opties als een schoorsteen in slechte staat verkeert?", "a": "Er zijn doorgaans twee opties: 1. Volledige verwijdering van de schoorsteen (waarbij niemand er meer gebruik van kan maken). 2. Sloop en het opnieuw opmetselen van de huidige schoorsteen."}, {"v": "Kan de VvE beheerder zelfstandig beslissen over het verwijderen van een schoorsteen?", "a": "De VvE beheerder heeft niet de bevoegdheid om zelfstandig te beslissen over het verwijderen van een schoorsteen. Indien één of meerdere eigenaren nog gebruikmaken van de schoorsteen, is het niet toegestaan om deze eigenaren te dwingen dit gebruik te beëindigen. Besluitvorming hierover kan alleen plaatsvinden in overleg met de betreffende eigenaren."}, {"v": "Wanneer verstuurt de beheerder een opleverbrief na onderhoudswerkzaamheden aan het pand?", "a": "Een opleverbrief wordt verstuurd wanneer een VvE geen externe bouwbegeleiding heeft. Indien er wel bouwbegeleiding aanwezig is, stelt de bouwbegeleider een proces-verbaal van oplevering op dat vervolgens met de VvE wordt gedeeld voor input."}, {"v": "Wat is een veelvoorkomende oorzaak van inregening en lekkageschade via het dak?", "a": "Een veelvoorkomende oorzaak van inregening is het ontbreken van kappen op de rookgasafvoeren en schoorsteenkanalen."}, {"v": "Kan Totaal VvE Beheer onderhoudsopdrachten verstrekken voordat de beheerovereenkomst volledig is geëffectueerd en er een reservefonds is?", "a": "Zolang het kantoor nog niet officieel is geregistreerd als bestuurder, er geen toegang is tot een bankrekening van de VvE en er geen onderhoudsreserve is opgebouwd via eigenaarsbijdragen, kunnen wij geen onderhoudsopdrachten accepteren of uitzetten. In dergelijke gevallen wordt van de eigenaren verwacht dat zij gezamenlijk optreden om calamiteiten op te lossen."}, {"v": "Wie verzorgt de uitnodigingen en de agenda voor de VvE-vergadering?", "a": "De uitnodigingen en agenda's worden vanuit het kantoor van Totaal VvE Beheer verstuurd."}, {"v": "Naar welk adres moet een door de notaris origineel gewaarmerkt afschrift van de akte van ondersplitsing worden verzonden?", "a": "U kunt dit sturen naar onze postbus: Postbus 89, 2280 AB Rijswijk."}, {"v": "Is eigenarenbelang standaard meeverzekerd bij appartementen met een woonbestemming?", "a": "De verzekeraar heeft bevestigd dat het eigenarenbelang voor de appartementsrechten met bestemming wonen kosteloos is meeverzekerd."}, {"v": "Wat moet ik doen als ik een melding 'niet beveiligd' krijg bij het bezoeken van het Totaal Portaal?", "a": "Deze melding kan verschijnen bij het gebruik van verouderde browserversies. Wij adviseren u om uw internetbrowser (zoals Chrome of Safari) bij te werken naar de meest recente versie. Mocht het probleem aanhouden, stuur dan een screenshot van de volledige foutmelding voor verdere ondersteuning."}, {"v": "Wat moet ik doen als gegevens in het nieuwe portaal niet lijken te kloppen of niet goed synchroniseren?", "a": "Het is bekend dat het systeem in sommige gevallen nog niet vlekkeloos synchroniseert met het oude portaal. Er wordt gewerkt aan een oplossing."}, {"v": "Wat moet ik doen als ik een e-mail van het Totaal Portaal niet heb ontvangen?", "a": "Controleer of de e-mail in de ongewenste of spamfolder is binnengekomen."}, {"v": "Is er toestemming nodig van alle eigenaren voor een structurele wijziging zoals een muurdoorbraak?", "a": "Alvorens de VvE akkoord kan geven op een dergelijke wijziging, is een schriftelijke bevestiging van het akkoord van alle eigenaren vereist. Dit wordt in het dossier van de Vereniging opgeslagen om achteraf discussies te voorkomen. Tevens dient er een rapport van een constructeur overlegd te worden voor het dossier."}, {"v": "Ik zie PHP-bestanden in het portaal in plaats van PDF-bestanden, hoe kan dit?", "a": "Wij plaatsen documenten normaliter als PDF-bestand in het portaal. Als u een bestand ziet met een .php extensie dat niet geopend kan worden, ontvangen wij graag een screenshot van de melding en, indien mogelijk, het betreffende bestand als bijlage zodat wij dit technisch kunnen laten nakijken."}, {"v": "Moet ik als eigenaar aanwezig zijn bij de oplevering van onderhoudswerkzaamheden aan het gebouw?", "a": "Het is voor u niet noodzakelijk om tijdens het bezoek voor de oplevering van de werkzaamheden aanwezig te zijn."}, {"v": "Wat kan ik doen als ik wel kan inloggen op het portaal, maar geen gekoppelde VvE zie, of de melding 'No VvE’s found' krijg?", "a": "Het Totaal Portaal herkent klanten aan het (primaire) e-mailadres dat in onze administratie bekend is. Als u geen gekoppelde VvE ziet, of de melding 'No VvE’s found' krijgt, kan het zijn dat het gebruikte e-mailadres niet gekoppeld is aan de juiste adresgegevens in onze administratie. U kunt contact opnemen om te laten verifiëren aan welk adres uw e-mailadres is gekoppeld."}, {"v": "Welke kosten mogen via de VvE aan de eigenaren worden doorbelast als de splitsingsakte alleen toestemming geeft voor g/w/l?", "a": "Wanneer de akte alleen toestemming geeft voor het berekenen van (voorschot)kosten voor gas, water en licht, vallen zaken als glasbewassing, schoonmaak en internet/tv hier in principe buiten. Deze diensten moeten dan onderling door de eigenaren worden geregeld of de overeenkomsten moeten worden beëindigd. Kosten voor het onderhoud van de cv-ketel en administratiekosten voor de afrekening kunnen eventueel wel worden opgenomen in de begroting."}, {"v": "Op welke manieren kan onderhoud worden afgehandeld bij de oprichting van een VvE en uitponding van een pand?", "a": "Er zijn in de basis twee opties: 1) De huidige eigenaren zorgen zelf voor de uitvoering van direct noodzakelijke herstelwerkzaamheden voorafgaand aan de verkoop, waarbij een MJOP de toekomstige kosten in beeld brengt voor de begroting. 2) De VvE wordt opgericht inclusief een duidelijke opgave van de te verwachten onderhoudskosten op korte termijn, waarbij extra bijdragen worden vastgesteld die door de eigenaren op een bepaald moment betaald moeten worden. Bij de tweede optie is het raadzaam dit op te nemen in de koopovereenkomsten en leveringsaktes. Een nadeel van deze optie is dat als eigenaren niet betalen, de VvE geen opdrachten kan verstrekken, wat tot extra kosten kan leiden. Ook kan financiering via banken bij deze optie lastiger zijn."}, {"v": "Kan Totaal VvE Beheer helpen bij het besparen op verzekeringspremies?", "a": "Ja, via onze verzekeraar kunnen wij vaak op de premie besparen met gelijkende voorwaarden en dekking."}, {"v": "Mogen facturen voor raambekleding worden meegenomen in een financiering of bijleenregeling via de VvE?", "a": "Nee, facturen voor raambekleding worden aangemerkt als roerende zaken en mogen daarom niet worden meegenomen."}, {"v": "Is er toestemming nodig van de medebewoners voor een ondersplitsing binnen de VvE?", "a": "Of er toestemming nodig is voor een ondersplitsing hangt af van de specifieke bepalingen in de splitsingsakte en het splitsingsreglement. Indien er geen toestemmingsvereiste in de akte en het reglement staat vermeld, kan de ondersplitsing in principe zonder toestemming van de buren/medebewoners worden uitgevoerd."}, {"v": "Wat moet ik doen als mijn account is geblokkeerd na meerdere mislukte inlogpogingen?", "a": "Wanneer u minimaal drie keer een verkeerd wachtwoord heeft ingevuld, blokkeert het systeem de toegang. We raden u in dat geval aan om opnieuw een nieuw wachtwoord aan te vragen om het proces te herstellen."}, {"v": "Welke gegevens heb ik nodig om een declaratie in te dienen?", "a": "Voor het in behandeling nemen van een declaratie dienen de volgende gegevens te worden verstrekt: voorletters en naam, rekeningnummer, het te declareren bedrag, de reden van de declaratie en een eventuele toelichting."}, {"v": "Komt dakisolatie in aanmerking voor subsidie van de Rijksoverheid?", "a": "Isolatie voor het dak kan - onder voorwaarden - voor subsidie in aanmerking komen via de Rijksoverheid. De kosten voor het toepassen hiervan bedragen doorgaans tussen de 70 en 110 euro per m2."}, {"v": "Heeft het kantoor van de VvE beheerder reservesleutels van mijn appartement?", "a": "Ons kantoor is niet in het bezit van sleutels van de appartementen."}, {"v": "Welke informatie is er nodig voor een digitale overschrijving bij de Kamer van Koophandel (KvK)?", "a": "Voor een digitale overschrijving bij de KvK dient onder andere het BSN-nummer van de betreffende persoon te worden aangeleverd. Een andere optie is om de overschrijving via papieren formulieren te regelen."}, {"v": "Is Totaal VvE Beheer ook actief in Rotterdam voor het beheer of de oprichting van een VvE?", "a": "Ja hoor, Rotterdam is geen probleem voor onze dienstverlening."}, {"v": "Moet de splitsingsakte al gepasseerd zijn voordat de verzekering van de VvE aangepast kan worden naar de nieuwe situatie?", "a": "De feitelijke situatie moet verzekerd worden, ongeacht of de splitsingsakte wel of niet is aangepast."}, {"v": "Wat moet ik doen als er maar één centrale watermeter aanwezig is in het pand, terwijl dit niet zo is vastgelegd in de splitsingsakte?", "a": "Idealerwijs staat de feitelijke situatie in de akte, maar als er slechts één watermeter aanwezig is terwijl de akte anders voorschrijft, moet de huidige situatie geaccepteerd worden. Een oplossing is om alsnog tussenmeters te laten plaatsen om het verbruik per eenheid in kaart te brengen."}, {"v": "Hoe wordt de herbouwwaarde bepaald en ben ik beschermd tegen onderverzekering?", "a": "De verzekeraar berekent de herbouwwaarde op basis van specifieke criteria via Infofolio. Op basis van de daaruit voortvloeiende waarde wordt een garantie tegen onderverzekering (bijvoorbeeld voor 6 jaar) op de polis aangetekend."}, {"v": "Wat gebeurt er als ik mijn meterstanden niet tijdig doorgeef?", "a": "Als u de meterstanden niet aan ons doorgeeft, wordt uw verbruik op basis van een schatting berekend."}, {"v": "Hoe zit het met de bemiddeling van verzekeringen voor VvE's?", "a": "Totaal VvE Beheer bemiddelt in verzekeringen voor VvE’s onder de verantwoordelijkheid van Eijgendaal & Van Romondt B.V. (AFM-vergunningsnummer 12005222). Meer informatie over de rol, beloning en dienstverlening is beschikbaar in de Dienstenwijzer."}, {"v": "Welke professionele partij kan worden ingezet voor de bestrijding van rattenoverlast?", "a": "Hoewel wij niet veel gebruikmaken van dergelijke diensten, is Rentokil een partij die benaderd kan worden voor professionele ongediertebestrijding."}, {"v": "Hoe gaat de VvE om met lopende contracten voor gas, elektra en water bij de oprichting?", "a": "Bij de oprichting van de VvE worden de lopende contracten voor gas, elektra en water op naam van de VvE gezet."}, {"v": "Is schade aan leidingwerk in de muur een zaak voor de VvE of voor de individuele eigenaar?", "a": "In de akte is bepaald dat leidingwerk dat uitsluitend dienstbaar is aan één privégedeelte voor rekening en risico is van de eigenaar van dat appartementsrecht. In dat geval is het geen onderdeel van de VvE."}, {"v": "Hoe worden de maandelijkse VvE-bijdragen bepaald, en moeten deze gebaseerd worden op het aantal vierkante meters of op de breukdelen in de splitsingsakte?", "a": "De hoogte van de maandelijkse VvE-bijdragen wordt bepaald op basis van het breukdeel van het appartementsrecht zoals vastgelegd in de splitsingsakte. De bepalingen in de splitsingsakte met betrekking tot de breukdelen van de appartementen in de gemeenschap zijn leidend. De maandelijkse bijdragen dienen te worden vastgesteld op basis van deze breukdelen en niet op basis van het aantal vierkante meters."}, {"v": "Houdt Totaal VvE Beheer zich bezig met huurzaken of bemiddeling tussen huurders?", "a": "Totaal VvE Beheer doet uitsluitend het VvE beheer voor eigenaren en houdt zich niet bezig met huurzaken, zoals huurnota's, indexeringen of het organiseren van afspraken bij overlast. Wij verzenden geen rechtstreekse berichten naar huurders; zaken tussen eigenaren en huurders dienen door de eigenaren zelf onderling geregeld te worden."}, {"v": "Dien ik de maandelijkse VvE-bijdrage zelf over te maken of wordt deze via een automatische incasso geïnd?", "a": "Totaal VvE Beheer biedt geen automatische incasso's aan. U kunt zelf een maandelijkse automatische overboeking instellen, bij voorkeur op de 1e van de maand. Let er daarbij op dat banken vaak automatisch een einddatum aan een periodieke overboeking koppelen."}, {"v": "Kan Totaal VvE Beheer de VvE juridisch vertegenwoordigen bij de rechtbank?", "a": "Totaal VvE Beheer kan de VvE vertegenwoordigen en bij de zitting(en) aanwezig zijn. Deze dienstverlening valt echter buiten het standaardtarief; hiervoor wordt een aanvullende prijsopgave verstrekt. Mocht u zelf in de gelegenheid zijn en bij de zaak aanwezig willen zijn, dan is dat uiteraard ook mogelijk."}, {"v": "Wat houdt het mandaat van de bestuurder binnen de VvE precies in?", "a": "Het mandaat van de bestuurder is bedoeld voor spoedeisende situaties, zoals bijvoorbeeld lekkages of andere directe schadegevallen waarbij snel handelen nodig is."}, {"v": "Wat is de opzegtermijn voor een bestuurdersaansprakelijkheidsverzekering?", "a": "De bestuurdersaansprakelijkheidsverzekering is op te zeggen met een maand opzegtermijn."}, {"v": "Wanneer moet de splitsingsakte worden aangepast als appartementen niet officieel benoemd zijn?", "a": "Om zaken officieel te regelen moeten alle appartementen een eigen indexnummer hebben in de splitsingsakte, zodat ze gezien kunnen worden als losse eenheden. Als de appartementen momenteel niet specifiek benoemd zijn in de akte, zal deze moeten worden aangepast."}, {"v": "Is er toestemming nodig voor het installeren van een keukenafzuiging door het gemeenschappelijke dak van de VvE?", "a": "Voor het installeren van een keukenafzuiging door het gemeenschappelijke dak van de VvE is akkoord van de eigenaren vereist. Eventuele schade als gevolg van de installatie, evenals het toekomstige onderhoud aan de afzuiging, kan niet ten laste van de Vereniging van Eigenaren worden gebracht."}, {"v": "Wanneer kunnen de periodieke bijdragen van de VvE worden aangepast?", "a": "De bijdragen worden vastgesteld op basis van de in de vergadering goedgekeurde begroting. Dit kan in een volgende Algemene Ledenvergadering worden aangepast. Let wel op dat er bij aanpassing nog steeds voldoende gereserveerd wordt, conform de 'Wet verbetering functioneren VvE'. Indien de reserveringen niet aan de wettelijke eisen voldoen, kan dit in de toekomst problemen opleveren bij de verkoop van het appartement."}, {"v": "Wat gebeurt er met bestaande leveranciers als een VvE actief wordt?", "a": "Bij het activeren van de VvE kunnen de bestaande leveranciers gewoon in stand gehouden worden."}, {"v": "Wat moet ik doen als de gemeenschappelijke CV-installatie foutmeldingen geeft (zoals een te laag drukverschil of te lage waterdruk) en mijn appartement niet verwarmt?", "a": "Wanneer er problemen zijn met de centrale verwarming, kan het beheer iemand langs laten komen om de installatie te controleren. Hiervoor kan een afspraak worden gemaakt met de betreffende bewoner."}, {"v": "Is de VvE verantwoordelijk voor het herstel van een defect kraantje in de berging?", "a": "Als de kraan zich in het privégedeelte (zoals de berging) bevindt, is dit geen VvE-aangelegenheid en valt het herstel niet onder de verantwoordelijkheid van de VvE."}, {"v": "Welke rol speelt de beheerder bij het begeleiden van groot onderhoud binnen een VvE?", "a": "Bij groot onderhoud wordt het volledige traject begeleid: van de eerste technische inventarisatie en het voortraject tot de offertevergelijking en besluitvorming in de Algemene Ledenvergadering (ALV). Daarnaast wordt er gezorgd voor heldere communicatie met bewoners en toezicht tijdens de uitvoering om de kwaliteit en planning te bewaken."}, {"v": "Kan Totaal VvE Beheer het beheer van een Vereniging van Eigenaren overnemen als er sprake is van een lopende aanschrijving of last onder dwangsom?", "a": "Ervaringen uit het verleden hebben ons geleerd geen dossiers met een lopende aanschrijving in beheer te nemen. Wij brengen graag een offerte uit voor het beheren van de Vereniging, maar pas nadat de last onder dwangsom is opgeheven."}, {"v": "Waar kan ik de agenda voor de vergadering vinden?", "a": "De agenda kan je terugvinden op de achterkant van de uitnodiging en in de digitale versie die per e-mail wordt toegestuurd."}, {"v": "Is het mogelijk om naast de maandelijkse VvE-bijdrage ook het voorschot voor de levering van elektra, gas en water via de VvE te laten verlopen?", "a": "Ja, dit is mogelijk. Om dit te verwerken dient u door te geven welke voorschotten gehanteerd moeten worden voor gas, water en licht. Vervolgens wordt er een nieuw voorstel opgesteld middels conceptnotulen en ter akkoord voorgelegd aan de betrokken eigenaren."}, {"v": "Kan Totaal VvE Beheer assisteren bij de aanvraag van een lening of subsidie voor de VvE?", "a": "Ons kantoor kan assisteren bij de aanvraag van een lening en/of subsidie. U kunt per e-mail aangeven wat de precieze wensen zijn van de VvE en of het gaat om een lening of een subsidieaanvraag. Op basis van deze informatie kunnen wij informatie verstrekken over de hieraan verbonden kosten en de verder benodigde informatie."}, {"v": "Is lekkage door kitwerk of een douchecabine een verantwoordelijkheid van de VvE?", "a": "Nee, wanneer er sprake is van een lekkage veroorzaakt door gebreken aan het kitwerk of de douchecabine in een woning, is dit geen VvE-aangelegenheid. De verantwoordelijkheid en de kosten liggen bij de eigenaar van de woning waar de oorzaak zich bevindt."}, {"v": "Zijn de kosten voor isolatie en een warmtepomp voor rekening van de VvE?", "a": "Het isoleren en plaatsen van een warmtepomp betreft een verbetering van het eigen privégedeelte, waardoor de kosten niet voor rekening zijn van de VvE. Indien de werkzaamheden uitsluitend binnen de grenzen van het privégedeelte worden uitgevoerd, kunt u hier zonder toestemming van de VvE mee aan de slag gaan."}, {"v": "Is voor het vernieuwen van leidingwerk in de eigen woning toestemming van de VvE nodig?", "a": "Leidingwerk dat uitsluitend dienstbaar is aan een privégedeelte is geen onderdeel van de VvE. Het leidingwerk van de eigen woning kunt u dan ook zonder toestemming van de Vereniging vernieuwen."}, {"v": "Wat moet ik doen als er een regenpijp kapot is die voor wateroverlast zorgt?", "a": "U kunt dit bij ons melden. Voor het inplannen van de reparatie hebben wij de contactgegevens nodig van de persoon met wie de loodgieter een afspraak kan maken om ter plaatse te komen."}, {"v": "Wat is de procedure wanneer er een (deel)vervanging van een standleiding nodig is?", "a": "Wij verzoeken de gespecialiseerde partij om een offerte uit te brengen. Na ontvangst van de offerte wordt deze per e-mail aan de eigenaren voorgelegd voor besluitvorming."}, {"v": "Heeft het zin om zelf contact op te nemen met een door de VvE ingeschakelde reparatiedienst als zij nog geen contact hebben opgenomen?", "a": "Het kan helpen om zelf even te bellen met de betreffende partij om het proces te versnellen. Daarbij kan indien nodig worden gerefereerd aan eerdere correspondentie vanuit de VvE-beheerder."}, {"v": "Is het mogelijk om een contract voor een gezamenlijke watermeter op naam van de VvE te zetten?", "a": "Wanneer er sprake is van een gezamenlijke meter voor het waterverbruik, kan het bestaande contract op naam van de VvE worden gezet."}, {"v": "Is het mogelijk om een btw-factuur te ontvangen?", "a": "Verzending van een btw-factuur kan te zijner tijd uiteraard worden verzorgd."}, {"v": "Hoe verloopt het proces als er toestemming nodig is voor wijzigingen aan de woning?", "a": "Dit kan schriftelijk. Zodra de gewenste informatie (zoals specificaties en maten) beschikbaar is, kan dit ter goedkeuring per e-mail aan de eigenaren worden voorgelegd."}, {"v": "Is er toestemming nodig voor het uitvoeren van leidingwerkzaamheden en het aanleggen van vloerverwarming?", "a": "Leidingwerkzaamheden en vloerverwarming kunnen zonder toestemming aangelegd worden."}, {"v": "Is het mogelijk om de mobiele of zakelijke telefoonnummers van de accountmanagers te ontvangen voor direct contact?", "a": "Helaas hebben wij geen zakelijke telefoonnummers die wij kunnen delen."}, {"v": "Is het mogelijk om een bestaand MJOP te laten updaten door een nieuwe beheerder?", "a": "Het updaten van een bestaand plan kan in de regel alleen door de opsteller van het betreffende MJOP worden gedaan. Indien dit niet mogelijk is, kan er een geheel nieuw MJOP worden opgesteld."}, {"v": "Wat zijn de gebruikelijke administratiekosten bij een eigendomsoverdracht binnen een VvE?", "a": "Bij een eigendomsoverdracht worden administratiekosten in rekening gebracht voor de mutatie en het verstrekken van de benodigde informatie. De kosten hiervoor bedragen € 75,- (excl. btw) voor de koper en € 75,- (excl. btw) voor de verkoper. Deze kosten mogen alleen in rekening worden gebracht indien er daadwerkelijk administratieve werkzaamheden zijn verricht."}, {"v": "Hoe kan ik een aanvulling of wijziging voorstellen op de notulen van de ledenvergadering?", "a": "Een aanvulling of wijziging op de notulen kan worden voorgesteld in de eerstvolgende ledenvergadering."}, {"v": "Wanneer kan de eerste Algemene Ledenvergadering (ALV) worden ingepland na een overstap van beheerder?", "a": "De planning van de eerste Algemene Ledenvergadering is afhankelijk van de ontvangst van de jaarrekening van het voorgaande jaar en het volledige dossier van de vorige beheerder. De jaarrekening moet namelijk met de stukken voor de ALV worden meegestuurd naar de leden."}, {"v": "Wordt er voor het beheer van de VvE altijd een specifiek beheercontract opgesteld?", "a": "Er wordt niet altijd een specifiek beheercontract opgesteld; het officiële besluit van de VvE om de offerte (waarin wordt verwezen naar de van toepassing zijnde algemene voorwaarden) te accorderen is rechtsgeldig en voldoende."}, {"v": "Biedt Totaal VvE Beheer ondersteuning bij de verrekening van nutsvoorzieningen op basis van tussenmeters?", "a": "Nee, verrekeningen op basis van een complexe verdeling met diverse water-, elektra- en gasmeters inclusief tussenmeters verzorgen wij niet. Hier is onze dienstverlening niet op ingericht; hiervoor moet een andere oplossing worden gezocht."}, {"v": "Wie beslist er over de keuze voor het type apparatuur bij vervanging, zoals de keuze tussen een touchscreen of een intercom met hoorn?", "a": "Het is gebruikelijk om de keuze tussen verschillende typen apparatuur, zoals een touchscreen of een intercom met hoorn, bij de eigenaren zelf neer te leggen."}, {"v": "Op welke manier moeten de papieren formulieren voor de Kamer van Koophandel (KvK) worden aangeleverd?", "a": "Voor de Kamer van Koophandel (KvK) hebben wij de papieren versie nodig. Deze kunt u naar onze postbus sturen."}, {"v": "Waarom zie ik een ander huisnummer dan mijn eigen huisnummer in het portaal?", "a": "In het portaal wordt de naam van de VvE getoond zoals deze officieel in de administratie (Totaal Portaal) staat vermeld, vaak gekoppeld aan het eerste huisnummer van het complex. Dit betekent niet dat uw persoonlijke adresgegevens onjuist zijn."}, {"v": "Is de VvE nog wel verzekerd als een oude polis wordt beëindigd en de nieuwe polis nog niet is ontvangen?", "a": "De VvE is gewoon verzekerd. Nieuwe verzekeringen gaan doorgaans direct in op de datum dat de oude verzekeringen eindigen. Zodra de kopie van de nieuwe polis is ontvangen, wordt deze naar u toegestuurd."}, {"v": "Wat moet ik doen als de portiekdeur niet goed in het slot valt?", "a": "Controleer eerst of het slot door iemand zelf gerepareerd kan worden. Mogelijk is het iets simpels en kleins, waarmee voorrij- en reparatiekosten voorkomen kunnen worden. Indien dit niet lukt, kunnen wij iemand langs sturen om dit te verhelpen."}, {"v": "Wanneer is het bestuur bevoegd om zonder opdracht van de vergadering spoedeisende maatregelen te nemen?", "a": "Voor zover in verband met de omstandigheden het nemen van spoedeisende maatregelen welke uit een normaal beheer kunnen voortvloeien noodzakelijk is, is het bestuur zonder opdracht van de vergadering hiertoe bevoegd, met dien verstande dat het voor het aangaan van verbintenissen een belang van een nader door de vergadering vast te stellen bedrag te boven gaande de machtiging nodig heeft van de voorzitter van de vergadering."}, {"v": "Dient er na de verkoop van een appartement en de komst van nieuwe bewoners een nieuwe ledenvergadering te worden uitgeschreven?", "a": "Het uitschrijven van een nieuwe vergadering is na de verkoop van een appartement niet direct nodig; de reeds geplande vergadering blijft hiervoor staan."}, {"v": "Waarom is er bij de opstart van een VvE een eenmalige extra bijdrage nodig en welke extra kosten kunnen er zijn?", "a": "Bij de start van een VvE kan een eenmalige bijdrage worden gevraagd voor de betaling van de verzekeringspremie."}, {"v": "Kan een lekkagemelding in behandeling worden genomen als de VvE nog niet actief is?", "a": "Zolang de VvE niet actief is (geen inschrijving in de Kamer van Koophandel en geen eigen bankrekening), kunnen meldingen nog niet in behandeling worden genomen. In dat geval dienen eigenaren dergelijke zaken onderling op te lossen totdat de activatie van de Vereniging is voltooid."}, {"v": "Wie is bevoegd om de verzekeringsofferte voor de VvE te ondertekenen?", "a": "Het is om het even wie de verzekeringsofferte tekent. Het is het handigst dat de beheerder dit namens de VvE doet en de verzekeraar direct informeert over het bestuurderschap, inclusief opgave van het vestigings- en postadres."}, {"v": "Wat is de termijn voor het indienen van bezwaar tegen notulen?", "a": "De bezwaartermijn voor notulen bedraagt 30 dagen."}, {"v": "Op welke manier kan ik het beste vragen stellen over het functioneren van de VvE?", "a": "U kunt vragen over het functioneren van de VvE bij voorkeur per e-mail stellen."}, {"v": "Zijn eigenaren welkom op kantoor voor een VvE-vergadering?", "a": "U bent van harte welkom om naar ons kantoor te komen voor een toekomstige vergadering."}, {"v": "Wat moet ik doen als een ruimte, zoals een fietsenberging, niet op de splitsingstekening of in de splitsingsakte staat?", "a": "Als een ruimte niet is ingetekend op de splitsingstekening, is de kans groot dat deze geen onderdeel uitmaakt van de VvE. In dergelijke gevallen is het aan te bevelen om contact op te nemen met de notaris die de splitsing (recent) heeft uitgevoerd voor verdere verduidelijking."}, {"v": "Hoe lang duurt het voordat de formulieren voor de inschrijving van een bestuurswijziging bij de KvK zijn verwerkt?", "a": "De formulieren worden per post verstuurd naar de Kamer van Koophandel. Er gaat doorgaans wel enige tijd overheen voordat de verwerking en inschrijving volledig zijn afgerond."}, {"v": "Hoe kunnen de verdeelsleutels voor gemeenschappelijke schulden en kosten binnen een VvE worden gewijzigd?", "a": "De verdeling van gemeenschappelijke schulden en kosten is vastgelegd in de akte van splitsing. Dit kan alleen worden gewijzigd als alle eigenaren instemmen met een notariële wijziging van deze akte. Er zijn hoge notariskosten verbonden aan een dergelijke wijziging."}, {"v": "Is er een collectieve aansprakelijkheidsverzekering aanwezig?", "a": "Ja, er is een collectieve aansprakelijkheidsverzekering afgesloten."}, {"v": "Waarom kan de maandelijkse VvE-bijdrage verschillen tussen vergelijkbare appartementen in hetzelfde blok?", "a": "Het verschil in de maandelijkse bijdrage kan liggen in de herbouwwaarde. Wanneer een appartement bijvoorbeeld op een hoek gelegen is, is de herbouwwaarde vaak hoger omdat er meer te herbouwen is. Een hogere herbouwwaarde resulteert in een hogere jaarlijkse verzekeringspremie, wat invloed heeft op de hoogte van de periodieke bijdrage."}, {"v": "Waarom is het noodzakelijk dat de volledige kruipruimte toegankelijk is voor inspectie bij herstelwerkzaamheden?", "a": "De volledige kruipruimte moet toegankelijk zijn zodat alle balken geïnspecteerd kunnen worden. Dit is een vereiste om garantie te kunnen geven op de uitgevoerde werkzaamheden."}, {"v": "Welke diensten levert Totaal VvE Beheer?", "a": "Wij verzorgen administratief, financieel én technisch beheer. Denk aan het bijhouden van ledenadministratie, incasso van bijdragen, onderhoudsaansturing, verzekeringsbeheer en het organiseren van de jaarlijkse ledenvergadering. Alles wordt geleverd in één vast all-in pakket. Geen verborgen kosten."}, {"v": "Wat gebeurt er met openstaande bedragen voor onderhoudswerkzaamheden als een woning binnen de VvE wordt verkocht?", "a": "Mocht de woning inderdaad verkocht worden dan zal het bedrag op de notarisafrekening worden meegenomen."}, {"v": "Hoe werkt het proces wanneer er een nieuwe eigenaar in de VvE komt?", "a": "Wanneer de contactgegevens van de nieuwe eigenaar aan ons worden doorgegeven, zal de nieuwe eigenaar vanuit ons kantoor een welkomstbrief met informatie ontvangen."}, {"v": "Wat gebeurt er als er na de oplevering gebreken aan het uitgevoerde werk worden geconstateerd?", "a": "De uitvoerder dient haar verantwoordelijkheid te nemen over het uitgevoerde werk indien dat niet goed zou zijn; hiervoor is de garantieregeling van toepassing."}, {"v": "Wanneer wordt de eindbetaling aan een aannemer verricht na uitgevoerde werkzaamheden?", "a": "De (eind)betaling aan de aannemer wordt verricht zodra de werkzaamheden zijn uitgevoerd en de opleverkeuring heeft plaatsgevonden. Het is niet mogelijk om te wachten op een akkoord van alle individuele eigenaren voor het verrichten van de betaling indien het werk conform de afspraken is opgeleverd."}, {"v": "Zijn dwangsommen gedekt onder de bestuurdersaansprakelijkheidsverzekering van de VvE?", "a": "Vermogensschade die verband houdt met dwangsommen is doorgaans niet gedekt onder de bestuurdersaansprakelijkheidsverzekering."}, {"v": "Kan de beheerder een opdrachtbevestiging sturen voor een bouwkundige inspectie als de VvE nog niet officieel actief is?", "a": "Indien er nog geen VvE actief is en er nog geen bankrekening is geopend, kan de beheerder de opdracht nog niet officieel bevestigen. In dat geval dient de opdrachtgever de opdracht rechtstreeks aan de uitvoerende partij te bevestigen."}, {"v": "Bieden jullie ondersteuning bij het oprichten van een ondersplitsing?", "a": "Wij kunnen een ondersplitsing voor de VvE oprichten en hiervoor een begroting opstellen. Voor het begroten van een ondersplitsing is de akte van de hoofdsplitsing benodigd; op basis hiervan worden de verzekeringen ondergebracht en de begroting opgesteld."}, {"v": "Hoe kan ik een offerte aanvragen en wat zijn de stappen om het VvE beheer uit te besteden?", "a": "Indien u interesse heeft in onze dienstverlening, kunt u via de website een vrijblijvende offerte aanvragen met een overzicht van onze werkzaamheden. Na het accepteren van de offerte zullen wij de VvE uitnodigen voor een opstartvergadering om officieel het beheer van de VvE over te nemen."}, {"v": "Wie is verantwoordelijk voor de toegankelijkheid van gemeenschappelijke voorzieningen, zoals een vergaarbak, bij onderhoud of vervanging?", "a": "Hoewel het onderhoud aan een vergaarbak een verantwoordelijkheid van de VvE is, dient een eigenaar er zelf voor te zorgen dat deze toegankelijk blijft (bijvoorbeeld na een verbouwing). Indien een vergaarbak hersteld of vervangen moet worden, zijn de kosten voor eventuele aanpassingen om de toegang te faciliteren (zoals aanpassingen aan vloeren of vloerverwarming) altijd voor rekening van de eigenaar."}, {"v": "Op welke type vastgoed richt Totaal VvE Beheer zich, en richt het zich ook op VvE's met een zakelijke bestemming?", "a": "Totaal VvE Beheer richt de focus uitsluitend op VvE's met de bestemming wonen. We focussen ons als beheerder niet op VvE's met een zakelijke bestemming."}, {"v": "Heeft een prijsaanpassing of verhoging van de beheerkosten/administratiekosten directe invloed op de hoogte van mijn maandelijkse VvE-bijdrage?", "a": "Een prijswijziging of verhoging van de beheerskosten heeft geen directe invloed op de hoogte van de maandelijkse bijdrage van de eigenaren."}, {"v": "Is voor een wijziging van de splitsingsakte in een kleine VvE toestemming van alle eigenaren nodig en moet dit in notulen worden vastgelegd?", "a": "Wijziging van de akte geschiedt met toestemming van alle eigenaren binnen een kleine VvE; dit zal tevens in de notulen worden vastgelegd."}, {"v": "Is het mogelijk om vervroegd een vergadering aan te vragen bij de administrateur?", "a": "Ja, je kunt de administrateur vragen een vergadering uit te schrijven met duidelijke agendapunten voor de gewenste besluitvorming."}, {"v": "Is een schriftelijk besluit via e-mail met een meerderheid van 75% voldoende voor toestemming voor een uitbouw?", "a": "Nee, voor een schriftelijk besluit buiten de vergadering is een instemming van 100% vereist."}, {"v": "Welke meerderheid is er nodig in de vergadering voor het goedkeuren van een uitbouw?", "a": "Voor de realisatie van een uitbouw moeten in een vergadering alle stemmen aanwezig of vertegenwoordigd zijn, waarbij drie van de vier stemmen moeten instemmen. Indien er slechts drie stemmen aanwezig of vertegenwoordigd zijn, kan er ook een besluit worden genomen, maar dan moeten al die drie stemmen akkoord gaan met de uitbouw."}, {"v": "Wie is er verantwoordelijk voor het onderhoud van de kozijnen binnen de VvE?", "a": "Wanneer in het reglement staat dat het buitenschilderwerk voor rekening van de Vereniging is, mag u ervan uitgaan dat de kozijnen de verantwoordelijkheid van de VvE zijn. Echter, als er in de splitsingsakte een specifieke wijziging staat die bepaalt dat de kosten voor de individuele eigenaar zijn, dan is de eigenaar verantwoordelijk. In dat geval kan de VvE overigens nog wel inspraak hebben over het type kozijn en de kleur."}, {"v": "Is het toegestaan om kerstbomen of kerstversiering in de gemeenschappelijke ruimten of algemene toegangshal te plaatsen?", "a": "Wij adviseren om het plaatsen van kerstbomen of kerstversiering in de gemeenschappelijke ruimten of algemene toegangshal achterwege te laten, mede met het oog op geldende wet- en regelgeving (waaronder brandveiligheid)."}, {"v": "Wat zijn de mogelijkheden als de VvE niet akkoord gaat met de betaling van een factuur voor werkzaamheden waarvoor zij geen opdracht hebben gegeven?", "a": "Wanneer eigenaren niet akkoord gaan met een factuur voor onderhoudswerkzaamheden waartoe geen opdracht is verleend, kan het beheer de situatie ter sprake brengen in de eerstkomende Algemene Ledenvergadering (ALV). Daarnaast is het advies om in gesprek te gaan met de leden van de VvE om de situatie toe te lichten."}, {"v": "Kan de VvE beheerder e-mailadressen van andere eigenaren verstrekken?", "a": "In het kader van de AVG (privacywetgeving) is het niet toegestaan om e-mailadressen van mede-eigenaren zomaar te verstrekken aan derden."}, {"v": "Naar welk e-mailadres of postadres kunnen facturen en overige post worden verzonden?", "a": "Facturen kunnen per e-mail worden verzonden naar facturen@totaalvve.nl of info@totaalvve.nl. Voor overige post kunt u gebruikmaken van Postbus 89, 2280 AB te Rijswijk."}, {"v": "Wat is het minimumtarief per VvE per jaar?", "a": "Het minimumtarief is € 585,- ex btw per VvE per jaar, zonder rekening te houden met het aantal appartementsrechten. Bij verkoop van een appartement aan een andere eigenaar komt daar 195 ex btw (per nieuwe eigenaar) bovenop. Bovenstaand tarief is alleen van toepassing als er géén sprake is van gezamenlijke aansluitingen GWL en/of tv en internet, in die gevallen rekenen wij gewoon ons gangbare tarief per appartementsrecht."}, {"v": "Wat zijn de voordelen van het uitbesteden van VvE beheer, ondanks de kosten?", "a": "In de praktijk blijkt in veel gevallen dat wij betere afspraken hebben met o.a. banken, verzekeraars en een trouw netwerk hebben aan aannemers wat naast een efficiëntere afhandeling van onderhoud en storingen ook financiële voordelen voor de VvE's met zich meebrengt."}, {"v": "Waarom besteden kleine VvE's het beheer uit?", "a": "Het uitbesteden van het VvE beheer wordt in de praktijk ook (en juist) veel door kleine VvE's gedaan met name om continuïteit te waarborgen. Wij merken dat veel VvE's die nieuw bij ons kantoor in beheer komen dit doen omdat vrijwillige bestuurders hiermee stoppen of verhuizen waardoor kennis verloren gaat."}, {"v": "Wat moet ik doen als ik een e-mail abusievelijk heb ontvangen?", "a": "Indien u een e-mail per ongeluk heeft ontvangen, dient u dit direct aan ons te melden via info@totaalvve.nl en de e-mail onmiddellijk van uw computer te verwijderen. Het gebruik, delen, kopiëren of verspreiden van de inhoud door onbevoegden is verboden. Wij zijn niet aansprakelijk voor eventuele fouten of vertragingen in de e-mailoverdracht."}, {"v": "Welke documenten zijn bijgesloten in het concept voorstel voor de oprichting van een VvE?", "a": "In het concept voorstel voor de oprichting van een VvE vindt u de volgende bijlagen: een conceptvoorstel oprichting/notulen, een machtigingsformulier, een offerte van Totaal VvE Beheer en een offerte voor verzekeringen."}, {"v": "Waar kan ik meer informatie vinden over de werkzaamheden van Totaal VvE Beheer?", "a": "Onze werkzaamheden zijn te vinden op onze website en tevens uitgelegd in onze vrijblijvende offerte."}, {"v": "Welke kosten zijn inbegrepen in de jaarlijkse reservering onderhoud?", "a": "De jaarlijkse kosten/reservering onderhoud omvat: reservering onderhoud, bankkosten, premie verzekeringen (opstal, glas en aansprakelijkheid) en administratiekosten."}, {"v": "Waar kan ik de begroting en de maandelijkse bijdragen van de VvE vinden?", "a": "De begroting en de hoogte van de maandelijkse bijdragen kunt u terugvinden in de jaarstukken van de VvE."}, {"v": "Waarom is de verzekering van EVR voordeliger en wat dekt deze?", "a": "De verzekering via EVR is voordeliger door een scherpere premie en biedt bovendien een 6-jarige garantie tegen onderverzekering. De dekking omvat opstal, glas en aansprakelijkheid, inclusief de fundering."}, {"v": "Hoe worden de bijdragen aan de VvE vastgesteld?", "a": "In het kader van de wet verbetering functioneren VvE worden de bijdragen vastgesteld op basis van 0,5% van de herbouwwaarde of op basis van een MJOP."}, {"v": "Hoe kan ik contact opnemen met Totaal VvE Beheer voor dringende zaken?", "a": "Voor dringende zaken kunt u contact opnemen met mijn collega's. Zij zijn bereikbaar via info@totaalvve.nl of telefonisch van maandag tot en met vrijdag van 09:00 tot 13:00 uur via 070 360 34 43. Mocht u calamiteiten willen melden na 13:00 uur dan kunt u hetzelfde nummer bellen, u wordt dan doorgeschakeld naar de nooddienst."}, {"v": "Wat is het Totaal Portaal en hoe krijg ik toegang tot mijn inloggegevens en documenten?", "a": "Het Totaal Portaal is een slimme digitale omgeving waar u als eigenaar 24/7 inzicht heeft in al uw VvE-zaken en documenten (zoals notulen, jaarrekeningen, de MJOP en betaalgegevens) op één centrale plek. U kunt veilig inloggen op https://totaalportaal.nl/login met het bij ons bekende primaire e-mailadres. Voor uw eerste login of bij een vergeten wachtwoord klikt u op 'wachtwoord vergeten' om een instel-instructie te ontvangen. Let op: inloggegevens worden verstrekt zodra deze beschikbaar zijn. Indien jaarstukken of de begroting van het betreffende boekjaar nog niet zijn afgerond, kunnen deze op een later moment in het portaal verschijnen."}];
